import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const processCVInput = async (input: string, targetJob: string, role: string): Promise<ApiResponse> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      You are the Core Engine of "Sirati Al-Mohtarefah" (Professional CV) managed by Faisal Saeed Abdullah Al-Sunni.
      Transform the following input into a world-class, ATS-optimized CV, career roadmap, and smart application helpers.

      Input Data: ${input}
      Target Job: ${targetJob}
      Role: ${role}

      STRICT PROTOCOL:
      1. Use Power Verbs and Metric-driven achievements.
      2. Ensure ATS Golden Standard compatibility.
      3. Compare with Saudi Market 2026 requirements.
      4. Language: Arabic (primarily) with English technical terms.
      5. Generate 3 email templates: Formal application, Follow-up (after 1 week), and Direct Manager outreach.
      6. Generate a reference request sample for the user to send to their previous manager.

      Return JSON exactly matching this schema:
      {
        "cv": {
          "personal_info": { "full_name": "string", "email": "string", "phone": "string", "location": "string", "target_job": "string" },
          "summary": "Professional summary optimized with keywords",
          "experience": [{ "company": "string", "position": "string", "duration": "string", "achievements": ["achievement with metrics"] }],
          "education": [{ "institution": "string", "degree": "string", "year": "string" }],
          "skills": ["skill1", "skill2"],
          "ats_score": number
        },
        "career_path": {
          "suggested_jobs": ["Job 1", "Job 2", "Job 3"],
          "skill_gap": { "skills": ["Certification/Skill 1", "Certification/Skill 2"], "potential_salary_increase": "percentage string" },
          "elevator_pitch": "short persuasive pitch"
        },
        "smart_helper": {
          "emails": { "formal": "string", "follow_up": "string", "direct": "string" },
          "reference_request_sample": "string"
        }
      }
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          cv: { type: Type.OBJECT },
          career_path: { type: Type.OBJECT },
          smart_helper: { type: Type.OBJECT }
        },
        required: ["cv", "career_path", "smart_helper"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const analyzeJobMatch = async (cv: CVData, jobDescription: string): Promise<JobMatchResult> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      Analyze the match between this CV and the Job Description provided.
      CV Target Job: ${cv.personal_info.target_job}
      CV Skills: ${cv.skills.join(", ")}
      Job Description: ${jobDescription}

      Return JSON:
      {
        "match_score": number (0-100),
        "missing_keywords": ["keyword1", "keyword2"],
        "recommendations": "Advice on how to improve match"
      }
    `,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text);
};

import React, { useState } from 'react';
import { SmartHelperData } from '../types';

export const SmartHelper: React.FC<{ data: SmartHelperData }> = ({ data }) => {
  const [activeTab, setActiveTab] = useState<'formal' | 'follow' | 'direct' | 'ref'>('formal');

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('تم نسخ النص إلى الحافظة');
  };

  const tabs = [
    { id: 'formal', label: 'تقديم رسمي', content: data.emails.formal, icon: 'fa-paper-plane' },
    { id: 'follow', label: 'متابعة الطلب', content: data.emails.follow_up, icon: 'fa-clock-rotate-left' },
    { id: 'direct', label: 'تواصل مباشر', content: data.emails.direct, icon: 'fa-user-tie' },
    { id: 'ref', label: 'طلب توصية', content: data.reference_request_sample, icon: 'fa-handshake' },
  ];

  const currentTab = tabs.find(t => t.id === activeTab);

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
      <div className="bg-slate-900 p-6 text-white">
        <h3 className="text-xl font-bold flex items-center gap-2">
          <i className="fa-solid fa-wand-magic-sparkles text-emerald-400"></i>
          مساعد التقديم الذكي (Smart Application Helper)
        </h3>
        <p className="text-slate-400 text-sm mt-1">نماذج احترافية مخصصة لسيرتك الذاتية</p>
      </div>

      <div className="flex border-b overflow-x-auto bg-slate-50">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex-1 py-4 px-6 text-sm font-bold whitespace-nowrap transition-all border-b-2 flex items-center justify-center gap-2 ${
              activeTab === tab.id 
                ? 'border-emerald-500 text-emerald-600 bg-white' 
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-100'
            }`}
          >
            <i className={`fa-solid ${tab.icon}`}></i>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-8">
        <div className="bg-slate-50 rounded-2xl p-6 relative group border border-slate-200">
          <button 
            onClick={() => currentTab && copyToClipboard(currentTab.content)}
            className="absolute top-4 left-4 bg-white shadow-md p-2 rounded-lg text-slate-400 hover:text-emerald-600 transition-colors"
            title="نسخ النص"
          >
            <i className="fa-solid fa-copy"></i>
          </button>
          <div className="prose prose-slate max-w-none whitespace-pre-wrap text-slate-700 leading-relaxed font-medium">
            {currentTab?.content}
          </div>
        </div>
        <p className="mt-6 text-xs text-slate-400 text-center flex items-center justify-center gap-2">
          <i className="fa-solid fa-info-circle"></i>
          هذه النماذج مصاغة بعناية لتناسب المسمى الوظيفي المستهدف ومهاراتك الحالية.
        </p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CVData, JobMatchResult } from '../types';
import { analyzeJobMatch } from '../services/geminiService';

export const JobMatcher: React.FC<{ cv: CVData }> = ({ cv }) => {
  const [jobDesc, setJobDesc] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<JobMatchResult | null>(null);

  const handleMatch = async () => {
    if (!jobDesc.trim()) return;
    setLoading(true);
    try {
      const matchData = await analyzeJobMatch(cv, jobDesc);
      setResult(matchData);
    } catch (e) {
      alert('خطأ في تحليل الإعلان');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
      <div className="bg-emerald-600 p-6 text-white">
        <h3 className="text-xl font-bold flex items-center gap-2">
          <i className="fa-solid fa-magnifying-glass-chart"></i>
          محلل إعلانات الوظائف (Job-Ad Matcher)
        </h3>
        <p className="text-emerald-50 text-sm mt-1">قارن سيرتك مع أي إعلان وظيفي لرفع فرص قبولك</p>
      </div>

      <div className="p-8 space-y-6">
        <div className="space-y-3">
          <label className="text-sm font-bold text-slate-700 block">انسخ نص إعلان الوظيفة هنا:</label>
          <textarea
            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none h-32 text-sm"
            placeholder="أو الصق رابط الإعلان إذا كان متاحاً كنص..."
            value={jobDesc}
            onChange={(e) => setJobDesc(e.target.value)}
          ></textarea>
          <button
            onClick={handleMatch}
            disabled={loading || !jobDesc.trim()}
            className="w-full bg-slate-900 text-white font-bold py-3 rounded-xl hover:bg-black transition-all disabled:opacity-50"
          >
            {loading ? <i className="fa-solid fa-spinner fa-spin ml-2"></i> : 'بدء التحليل والمطابقة'}
          </button>
        </div>

        {result && (
          <div className="mt-8 space-y-6 animate-in slide-in-from-bottom duration-500">
            <div className="flex items-center gap-6 bg-slate-50 p-6 rounded-2xl border border-slate-200">
              <div className={`w-24 h-24 rounded-full border-4 flex items-center justify-center text-2xl font-black ${
                result.match_score > 70 ? 'border-emerald-500 text-emerald-600' : 'border-amber-500 text-amber-600'
              }`}>
                {result.match_score}%
              </div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-900 mb-1">نسبة التطابق</h4>
                <p className="text-sm text-slate-500 leading-tight">{result.recommendations}</p>
              </div>
            </div>

            <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
              <h4 className="text-amber-800 font-bold mb-4 flex items-center gap-2 text-sm">
                <i className="fa-solid fa-triangle-exclamation"></i>
                أضف هذه الكلمات لسيرتك لرفع النسبة إلى 100%:
              </h4>
              <div className="flex flex-wrap gap-2">
                {result.missing_keywords.map((kw, idx) => (
                  <span key={idx} className="bg-white px-3 py-1 rounded-lg border border-amber-300 text-amber-700 text-xs font-bold shadow-sm">
                    {kw}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { processCVInput } from './services/geminiService';
import { UserRole, ApiResponse } from './types';
import { APP_CONFIG } from './constants';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [input, setInput] = useState('');
  const [targetJob, setTargetJob] = useState('');
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [editsCount, setEditsCount] = useState(0);
  const [showNomination, setShowNomination] = useState(false);

  useEffect(() => {
    if (role === UserRole.EMPLOYER && activated && result) {
      const timer = setTimeout(() => setShowNomination(true), 3000);
      return () => clearTimeout(timer);
    }
  }, [role, activated, result]);

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleProcess = async () => {
    if (!input || !targetJob || !role) return;

    setLoading(true);
    try {
      const generatedOtp = generateOtp(role);
      setOtp(generatedOtp);
      const apiResult = await processCVInput(input, targetJob, role);
      setResult(apiResult);
      setEditsCount(prev => prev + 1);
    } catch (error) {
      console.error("Processing failed", error);
      alert("حدث خطأ أثناء معالجة البيانات، يرجى المحاولة مرة أخرى.");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) {
      setActivated(true);
    } else {
      alert("كود التفعيل غير صحيح");
    }
  };

  if (!role) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-20 flex flex-col items-center">
          <div className="text-center mb-16 space-y-4">
            <h2 className="text-4xl md:text-5xl font-black text-slate-900 leading-tight">المحرك الخلفي لـ <span className="text-emerald-600">سيرتي الاحترافية</span></h2>
            <p className="text-slate-600 text-lg max-w-2xl">نحول بياناتك العادية إلى إنجازات رقمية تنافس المعايير العالمية. اختر نوع الخدمة للبدء:</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-4xl">
            <button 
              onClick={() => setRole(UserRole.SEEKER)}
              className="group p-10 bg-white border-2 border-slate-100 rounded-3xl shadow-xl hover:border-emerald-500 hover:shadow-2xl transition-all text-right flex flex-col items-center sm:items-start gap-4"
            >
              <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform">
                <i className="fa-solid fa-user-tie"></i>
              </div>
              <div>
                <h3 className="text-2xl font-bold text-slate-900 mb-2">باحث عن عمل</h3>
                <p className="text-slate-500">تحسين السيرة، فحص الـ ATS، وخارطة طريق مهنية لعام 2026.</p>
              </div>
            </button>

            <button 
              onClick={() => setRole(UserRole.EMPLOYER)}
              className="group p-10 bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-xl hover:border-emerald-500 hover:shadow-2xl transition-all text-right flex flex-col items-center sm:items-start gap-4"
            >
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-2xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform">
                <i className="fa-solid fa-building-user"></i>
              </div>
              <div className="text-white">
                <h3 className="text-2xl font-bold mb-2">صاحب عمل / شركة</h3>
                <p className="text-slate-400">فرز ذكي، تحليل تخصصات، وبطاقة مطابقة للمرشحين.</p>
              </div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="container mx-auto px-4 py-12">
        {!result || (editsCount < APP_CONFIG.maxEdits && !activated) ? (
          <div className="max-w-4xl mx-auto space-y-8">
            <div className="flex items-center justify-between">
              <button onClick={() => setRole(null)} className="text-slate-500 hover:text-slate-900 font-bold flex items-center gap-2">
                <i className="fa-solid fa-arrow-right"></i> عودة للرئيسية
              </button>
              <div className="text-sm font-bold text-emerald-600 bg-emerald-50 px-4 py-2 rounded-full">
                {role === UserRole.SEEKER ? 'بوابة الباحث عن عمل' : 'بوابة صاحب العمل'}
              </div>
            </div>

            <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
              <div className="space-y-4">
                <label className="block text-xl font-bold text-slate-800">1. المسمى الوظيفي المستهدف:</label>
                <input 
                  type="text" 
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none text-lg"
                  placeholder="مثال: مدير مشاريع، مهندس برمجيات، محاسب..."
                  value={targetJob}
                  onChange={(e) => setTargetJob(e.target.value)}
                />
              </div>

              <div className="space-y-4">
                <label className="block text-xl font-bold text-slate-800">2. أدخل بيانات السيرة (نص أو ملف قديم):</label>
                <textarea 
                  className="w-full p-6 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none h-64 text-slate-700 leading-relaxed"
                  placeholder="انسخ محتوى سيرتك الحالية أو اكتب خبراتك ومهاراتك هنا بالتفصيل..."
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                ></textarea>
              </div>

              <button 
                onClick={handleProcess}
                disabled={loading || !input || !targetJob}
                className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-2xl text-xl shadow-lg shadow-emerald-200 transition-all disabled:opacity-50 flex items-center justify-center gap-3"
              >
                {loading ? <><i className="fa-solid fa-spinner fa-spin"></i> جاري المعالجة والتحسين الذكي...</> : <><i className="fa-solid fa-wand-magic-sparkles"></i> توليد السيرة الاحترافية الآن</>}
              </button>
            </div>
          </div>
        ) : null}

        {result && otp && !activated && (
          <div className="py-12">
            <Paywall role={role} otp={otp} onActivate={handleActivate} />
          </div>
        )}

        {result && activated && (
          <div className="space-y-12 animate-in fade-in duration-1000 max-w-4xl mx-auto">
            {/* Success Bar */}
            <div className="flex flex-col md:flex-row gap-6 items-center justify-between">
              <div className="bg-emerald-600 text-white px-6 py-3 rounded-2xl flex items-center gap-4 shadow-lg w-full md:w-auto">
                <i className="fa-solid fa-circle-check text-2xl"></i>
                <span className="font-bold">تم التفعيل بنجاح - تم فتح المحتوى المهني بالكامل</span>
              </div>
              <button onClick={() => window.print()} className="bg-slate-900 hover:bg-black text-white px-10 py-4 rounded-2xl font-black shadow-xl flex items-center gap-3 transition-all whitespace-nowrap">
                <i className="fa-solid fa-file-pdf"></i> تحميل السيرة (PDF)
              </button>
            </div>

            {/* Notification for Employers */}
            {role === UserRole.EMPLOYER && showNomination && (
              <div className="bg-blue-600 text-white p-6 rounded-2xl shadow-xl flex items-center gap-4 animate-bounce">
                <i className="fa-solid fa-bell text-3xl"></i>
                <div className="flex-1">
                  <h4 className="font-bold">نظام الترشيح التلقائي (Auto-Nomination)</h4>
                  <p className="text-sm opacity-90">وجدنا لك مرشحاً طابق متطلباتك بنسبة {result.cv.ats_score}% قبل 5 دقائق، هل تود الاطلاع على ملفه؟</p>
                </div>
                <button className="bg-white text-blue-600 font-bold px-4 py-2 rounded-lg text-sm">عرض الملف</button>
              </div>
            )}

            {/* Main Result Sections */}
            <CVPreview data={result.cv} />

            {role === UserRole.SEEKER && (
              <>
                <div className="grid grid-cols-1 gap-12">
                  <CareerPath data={result.career_path} />
                  <SmartHelper data={result.smart_helper} />
                  <JobMatcher cv={result.cv} />
                </div>
              </>
            )}

            {role === UserRole.EMPLOYER && (
              <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100">
                <h3 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-3">
                  <i className="fa-solid fa-id-card-clip text-emerald-600"></i>
                  بطاقة مطابقة المرشح الذكية
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                  <div className="md:col-span-1 bg-slate-50 p-6 rounded-2xl text-center border border-slate-200">
                    <p className="text-slate-500 font-medium mb-2">نسبة الملائمة</p>
                    <div className="text-5xl font-black text-emerald-600">{result.cv.ats_score}%</div>
                  </div>
                  <div className="md:col-span-3 space-y-4">
                    <h4 className="font-bold text-slate-800">أسباب ترشيح هذا المتقدم:</h4>
                    <ul className="space-y-3">
                      {result.cv.skills.slice(0, 4).map((skill, i) => (
                        <li key={i} className="flex items-center gap-2 text-slate-600">
                          <i className="fa-solid fa-check-double text-emerald-500"></i>
                          يمتلك خبرة معمقة في مهارة <strong>{skill}</strong>.
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            )}

            <div className="text-center pb-20">
              <p className="text-slate-400 mb-6">هل ترغب في إجراء تعديل إضافي؟ (المتبقي: {APP_CONFIG.maxEdits - editsCount})</p>
              {editsCount < APP_CONFIG.maxEdits && (
                <button 
                  onClick={() => setActivated(false)} 
                  className="bg-white border border-slate-200 px-8 py-3 rounded-xl font-bold hover:bg-slate-50 transition-all"
                >
                  إجراء تعديلات
                </button>
              )}
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

