import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult, VerificationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const processCVInput = async (input: string, targetJob: string, role: string, userLocation?: string): Promise<ApiResponse> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      You are the Core Engine of "Sirati Al-Mohtarefah" managed by Faisal Saeed Abdullah Al-Sunni.

      Input Data: ${input}
      Target Job: ${targetJob}
      User Location: ${userLocation || "Saudi Arabia"}
      Role: ${role}

      STRICT PROTOCOL:
      1. Use Power Verbs and Metric-driven achievements.
      2. Ensure ATS Golden Standard.
      3. Language: Arabic (primarily) with English technical terms.

      ADDITIONAL TASKS:
      - Career Radar: Analyze the most in-demand skills specifically in ${userLocation || "the user's region"} within KSA.
      - Social Brand: Create one LinkedIn post and one X post to announce job search readiness.
      - Salary Negotiator: Estimate the salary range (Min/Max) for this role in the Saudi market 2026 and provide a negotiation script.
      - Smart Helper: Generate 3 emails and a reference request sample.

      Return JSON matching this schema:
      {
        "cv": { ... },
        "career_path": { ... },
        "smart_helper": { ... },
        "market_insights": {
          "city": "string",
          "trending_skills": ["skill1", "skill2"],
          "region_analysis": "short analysis of job market in this city"
        },
        "social_brand": {
          "linkedin_post": "string with hashtags",
          "x_post": "string with hashtags"
        },
        "salary_negotiation": {
          "range": { "min": "SR X,XXX", "max": "SR X,XXX" },
          "script": "Professional negotiation script"
        }
      }
    `,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text);
};

export const verifyCertificate = async (base64Image: string, cvData: CVData): Promise<VerificationResult> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        inlineData: {
          mimeType: "image/jpeg",
          data: base64Image.split(',')[1]
        }
      },
      {
        text: `
          Extract information from this professional certificate. 
          Identify the Certificate Name, Issuer, and check if it matches the skills or education in this CV:
          Skills: ${cvData.skills.join(", ")}
          Education: ${JSON.stringify(cvData.education)}

          Return JSON:
          {
            "certificate_name": "string",
            "issuer": "string",
            "is_valid": boolean,
            "match_explanation": "how this matches the CV"
          }
        `
      }
    ],
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text);
};

export const analyzeJobMatch = async (cv: CVData, jobDescription: string): Promise<JobMatchResult> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      Analyze the match between this CV and the Job Description provided.
      Return JSON: { "match_score": number, "missing_keywords": ["kw"], "recommendations": "string" }
    `,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text);
};

