import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { SocialBrand } from './components/SocialBrand';
import { SalaryNegotiator } from './components/SalaryNegotiator';
import { CredentialVerifier } from './components/CredentialVerifier';
import { CareerSimulator } from './components/CareerSimulator';
import { PortfolioBuilder } from './components/PortfolioBuilder';
import { VirtualCoach } from './components/VirtualCoach';
import { processCVInput } from './services/geminiService';
import { UserRole, ApiResponse, VerificationResult } from './types';
import { APP_CONFIG, PAYMENT_INFO } from './constants';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [input, setInput] = useState('');
  const [targetJob, setTargetJob] = useState('');
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [editsCount, setEditsCount] = useState(0);
  const [showNomination, setShowNomination] = useState(false);
  const [userLocation, setUserLocation] = useState('السعودية');
  const [verifications, setVerifications] = useState<VerificationResult[]>([]);
  const [isCorporateGold, setIsCorporateGold] = useState(false);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        try { setUserLocation("المنطقة الحالية"); } catch (e) {}
      });
    }
  }, []);

  useEffect(() => {
    if (role === UserRole.EMPLOYER && activated && result) {
      const timer = setTimeout(() => setShowNomination(true), 3000);
      return () => clearTimeout(timer);
    }
  }, [role, activated, result]);

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleProcess = async () => {
    if (!input || !targetJob || !role) return;
    setLoading(true);
    try {
      const generatedOtp = generateOtp(role);
      setOtp(generatedOtp);
      const apiResult = await processCVInput(input, targetJob, role, userLocation);
      setResult(apiResult);
      setEditsCount(prev => prev + 1);
    } catch (error) {
      alert("حدث خطأ أثناء المعالجة.");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string) => {
    if (code === 'GOLD100') {
      setIsCorporateGold(true);
      setActivated(true);
    } else if (code.length >= 4) {
      setActivated(true);
    } else {
      alert("كود التفعيل غير صحيح");
    }
  };

  const handleVerification = (res: VerificationResult) => {
    if (res.is_valid) {
      setVerifications(prev => [...prev, res]);
      if (result) setResult({ ...result, cv: { ...result.cv, is_verified: true } });
    } else {
      alert(`الشهادة لم تطابق البيانات.`);
    }
  };

  if (!role) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-20 flex flex-col items-center">
          <div className="text-center mb-16 space-y-4">
            <h2 className="text-4xl md:text-5xl font-black text-slate-900 leading-tight">المحرك الذكي لـ <span className="text-emerald-600">سيرتي الاحترافية</span></h2>
            <p className="text-slate-600 text-lg max-w-2xl">نحول بياناتك العادية إلى إنجازات رقمية تنافس المعايير العالمية.</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-4xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-10 bg-white border-2 border-slate-100 rounded-3xl shadow-xl hover:border-emerald-500 transition-all text-right flex flex-col items-start gap-4">
              <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center text-2xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className="text-2xl font-bold text-slate-900">باحث عن عمل</h3><p className="text-slate-500">تحسين السيرة وفحص الـ ATS.</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-10 bg-slate-900 border-2 border-slate-800 rounded-3xl shadow-xl hover:border-emerald-500 transition-all text-right flex flex-col items-start gap-4">
              <div className="w-16 h-16 bg-emerald-500 text-slate-900 rounded-2xl flex items-center justify-center text-2xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-building-user"></i></div>
              <div className="text-white"><h3 className="text-2xl font-bold">صاحب عمل</h3><p className="text-slate-400">فرز ذكي وتحليل مرشحين.</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="container mx-auto px-4 py-12">
        {/* Market Pulse Notification */}
        {result && activated && role === UserRole.SEEKER && (
          <div className="max-w-4xl mx-auto mb-8 animate-bounce">
            <div className="bg-yellow-400 text-slate-900 p-4 rounded-2xl shadow-xl flex items-center justify-between border-2 border-white">
              <div className="flex items-center gap-3 font-black">
                <i className="fa-solid fa-bolt"></i>
                <span>تنبيه السوق: زاد الطلب على تخصصك بنسبة {result.market_pulse.demand_increase} هذا الأسبوع!</span>
              </div>
              <button className="bg-slate-900 text-white text-xs px-4 py-2 rounded-lg font-bold">حدث الآن</button>
            </div>
          </div>
        )}

        {!result || (editsCount < APP_CONFIG.maxEdits && !activated) ? (
          <div className="max-w-4xl mx-auto space-y-8">
            <button onClick={() => setRole(null)} className="text-slate-500 font-bold flex items-center gap-2"><i className="fa-solid fa-arrow-right"></i> عودة</button>
            <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
              <input type="text" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none text-lg" placeholder="المسمى الوظيفي المستهدف" value={targetJob} onChange={(e) => setTargetJob(e.target.value)} />
              <textarea className="w-full p-6 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none h-64 text-slate-700" placeholder="بيانات السيرة..." value={input} onChange={(e) => setInput(e.target.value)} />
              <button onClick={handleProcess} disabled={loading || !input || !targetJob} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-2xl text-xl shadow-lg flex items-center justify-center gap-3">
                {loading ? <><i className="fa-solid fa-spinner fa-spin"></i> جاري المعالجة...</> : <><i className="fa-solid fa-wand-magic-sparkles"></i> توليد الآن</>}
              </button>
            </div>
          </div>
        ) : null}

        {result && otp && !activated && <div className="py-12"><Paywall role={role} otp={otp} onActivate={handleActivate} /></div>}

        {result && activated && (
          <div className="space-y-12 max-w-4xl mx-auto">
            <div className="flex flex-col md:flex-row gap-6 items-center justify-between">
              <div className="bg-emerald-600 text-white px-6 py-3 rounded-2xl flex items-center gap-4 shadow-lg w-full md:w-auto">
                <i className="fa-solid fa-circle-check text-2xl"></i>
                <span className="font-bold">تم التفعيل بنجاح - {isCorporateGold ? 'عضوية جولد' : 'عضوية احترافية'}</span>
              </div>
              <button onClick={() => window.print()} className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black shadow-xl flex items-center gap-3"><i className="fa-solid fa-file-pdf"></i> PDF</button>
            </div>

            <CVPreview data={result.cv} />

            {role === UserRole.SEEKER && (
              <div className="grid grid-cols-1 gap-12">
                <CareerSimulator data={result.timeline} />
                <PortfolioBuilder data={result.portfolio} />
                <VirtualCoach targetJob={targetJob} />
                <CareerRadar data={result.market_insights} />
                <CredentialVerifier cvData={result.cv} onVerified={handleVerification} />
                <CareerPath data={result.career_path} />
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                  <SalaryNegotiator data={result.salary_negotiation} />
                  <SocialBrand data={result.social_brand} />
                </div>
                <SmartHelper data={result.smart_helper} />
                <JobMatcher cv={result.cv} />
              </div>
            )}

            {role === UserRole.EMPLOYER && (
              <div className="space-y-12">
                <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100">
                  <div className="flex justify-between items-center mb-6">
                    <h3 className="text-2xl font-bold flex items-center gap-3"><i className="fa-solid fa-id-card-clip text-emerald-600"></i> مطابقة المرشح</h3>
                    {isCorporateGold && <span className="bg-yellow-100 text-yellow-700 px-4 py-1 rounded-full text-xs font-black border border-yellow-200 uppercase">Corporate Gold</span>}
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                    <div className="md:col-span-1 bg-slate-50 p-6 rounded-2xl text-center border border-slate-200">
                      <div className="text-5xl font-black text-emerald-600">{result.cv.ats_score}%</div>
                    </div>
                    <div className="md:col-span-3">
                      <h4 className="font-bold text-slate-800 mb-2">اصطياد المواهب المنافسة (Reverse Headhunting):</h4>
                      <p className="text-sm text-slate-600">{result.headhunting?.target_competitors_gaps}</p>
                    </div>
                  </div>
                </div>
                {isCorporateGold && (
                  <div className="bg-slate-900 text-white p-8 rounded-3xl shadow-xl border border-slate-800">
                    <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><i className="fa-solid fa-robot text-emerald-400"></i> المقابلات النصية الأولية (AI Screening)</h3>
                    <p className="text-slate-400 text-sm mb-6">يقوم الذكاء الاصطناعي حالياً بالتواصل مع المرشح لإجراء مقابلة أولية نيابة عنك.</p>
                    <button className="bg-emerald-600 text-white font-bold px-6 py-2 rounded-lg text-sm">عرض النتائج الحية</button>
                  </div>
                )}
              </div>
            )}
          </div>
        )}
      </div>
    </Layout>
  );
};

