import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult, VerificationResult, InterviewAnalysis } from "../types";

// Note: GoogleGenAI instance is created inside each function to ensure it uses the most up-to-date API key as per guidelines.

export const processCVInput = async (input: string, targetJob: string, role: string, userLocation?: string): Promise<ApiResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      You are the Core Engine of "Sirati Al-Mohtarefah" managed by Faisal Saeed Abdullah Al-Sunni.

      Input Data: ${input}
      Target Job: ${targetJob}
      User Location: ${userLocation || "Saudi Arabia"}
      Role: ${role}

      STRICT PROTOCOL:
      1. Use Power Verbs and Metric-driven achievements.
      2. Ensure ATS Golden Standard.
      3. Language: Arabic (primarily) with English technical terms.

      ADDITIONAL TASKS:
      - Career Simulator: 5-year growth path including role/salary/skills.
      - Portfolio Builder: Layout structure for a project portfolio.
      - Market Pulse: Weekly demand update for the user's role.
      - Reverse Headhunting: (If role is Employer) Competitor gap analysis.

      Return JSON matching this schema:
      {
        "cv": { ... },
        "career_path": { ... },
        "smart_helper": { ... },
        "market_insights": { ... },
        "social_brand": { ... },
        "salary_negotiation": { ... },
        "timeline": {
           "steps": [{ "year": "2026", "title": "string", "salary": "SR X,XXX", "focus_skill": "string" }]
        },
        "portfolio": {
           "structure": [{ "section_name": "string", "description": "string", "key_projects_count": number, "recommended_tech": ["tech"] }]
        },
        "market_pulse": {
           "demand_increase": "percentage string",
           "trend_description": "string"
        },
        "headhunting": {
           "target_competitors_gaps": "string",
           "suggested_profiles_traits": ["trait"]
        }
      }
    `,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || '{}');
};

export const analyzeSelfIntro = async (text: string, targetJob: string): Promise<InterviewAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      Act as a Virtual Coach. Analyze this self-introduction text for a ${targetJob} role.
      Text: "${text}"

      Evaluate: Confidence, Keyword usage, Emotional Intelligence.
      Provide suggestions for improvement, specifically for salary talk.

      Return JSON:
      {
        "confidence_score": number (0-100),
        "keywords_score": number (0-100),
        "eq_score": number (0-100),
        "feedback": "string",
        "suggested_phrases": ["phrase 1", "phrase 2"]
      }
    `,
    config: {
      responseMimeType: "application/json"
    }
  });
  return JSON.parse(response.text || '{}');
};

export const verifyCertificate = async (base64Image: string, cvData: CVData): Promise<VerificationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: base64Image.split(',')[1]
          }
        },
        {
          text: `Extract info from this certificate and match with these CV skills: ${cvData.skills.join(", ")}`
        }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || '{}');
};

export const analyzeJobMatch = async (cv: CVData, jobDescription: string): Promise<JobMatchResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      Compare the following CV skills with the Job Description and provide a match analysis.
      CV Skills: ${cv.skills.join(', ')}
      Job Description: ${jobDescription}

      Return JSON: { "match_score": number, "missing_keywords": ["kw"], "recommendations": "string" }
    `,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

