  career_path: any;
  smart_helper: any;
  market_insights: any;
  social_brand: any;
  salary_negotiation: any;
  timeline: any;
  portfolio: any;
  market_pulse: any;
}

export interface VerificationResult {
  certificate_name: string;
  issuer: string;
  is_valid: boolean;
  match_explanation: string;
}

export interface InterviewAnalysis {
  confidence_score: number;
  keywords_score: number;
  eq_score: number;
  feedback: string;
  suggested_phrases: string[];
}

export interface JobMatchResult {
  match_score: number;
  missing_keywords: string[];
  recommendations: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult, VerificationResult, InterviewAnalysis, CandidateProfile } from "../types";

export const processCVInput = async (input: string, targetJob: string, role: string, userLocation?: string): Promise<ApiResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      You are the Core Engine of "Sirati Al-Mohtarefah" managed by Faisal Saeed Abdullah Al-Sunni.
      Role: ${role}
      Input: ${input}
      Target: ${targetJob}
      Location: ${userLocation}

      Generate a complete CV and career data in JSON format. Use strong metrics and power verbs.
    `,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || '{}');
};

export const getKeywordSuggestions = async (skill: string, targetJob: string): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Suggest 5 high-value ATS keywords/phrases for a ${targetJob} professional who has the skill: ${skill}. Return a JSON array of strings.`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '[]');
};

export const generateMockCandidates = async (filters: any): Promise<CandidateProfile[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate 3 professional candidate profiles for an employer based on filters: ${JSON.stringify(filters)}. 
    Include: id, full_name, target_job, location, summary, experience, skills, top_achievements (3 strings), ai_fit_score (0-100), expected_salary (string), languages, phone, email.
    Ensure they look realistic for the Saudi market 2026. Return as JSON array of objects.`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '[]');
};

export const verifyCertificate = async (base64Image: string, cvData: CVData): Promise<VerificationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image.split(',')[1] } },
        { text: `Extract info and match with CV skills: ${cvData.skills.join(", ")}` }
      ]
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export const analyzeSelfIntro = async (text: string, targetJob: string): Promise<InterviewAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze self-intro for ${targetJob}. Text: ${text}. Return JSON with scores and feedback.`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export const analyzeJobMatch = async (cv: CVData, jobDescription: string): Promise<JobMatchResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Match CV to JD. Return JSON: { "match_score": number, "missing_keywords": ["kw"], "recommendations": "string" }`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

import React, { useState } from 'react';
import { getKeywordSuggestions } from '../services/geminiService';

interface CandidateHubProps {
  onProcess: (data: string, target: string) => void;
  loading: boolean;
}

export const CandidateHub: React.FC<CandidateHubProps> = ({ onProcess, loading }) => {
  const [targetJob, setTargetJob] = useState('');
  const [name, setName] = useState('');
  const [exp, setExp] = useState('');
  const [skillsInput, setSkillsInput] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [suggesting, setSuggesting] = useState(false);

  const handleSkillBlur = async () => {
    if (!skillsInput || !targetJob) return;
    setSuggesting(true);
    try {
      const data = await getKeywordSuggestions(skillsInput, targetJob);
      setSuggestions(data);
    } catch (e) {} finally { setSuggesting(false); }
  };

  const addSuggestion = (s: string) => {
    setSkillsInput(prev => prev ? `${prev}, ${s}` : s);
    setSuggestions(prev => prev.filter(x => x !== s));
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700">الاسم الكامل</label>
          <input 
            type="text" 
            className="w-full p-3 bg-slate-50 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" 
            value={name} 
            onChange={e => setName(e.target.value)}
          />
        </div>
        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700">المسمى الوظيفي المستهدف</label>
          <input 
            type="text" 
            className="w-full p-3 bg-slate-50 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" 
            value={targetJob} 
            onChange={e => setTargetJob(e.target.value)}
          />
        </div>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-bold text-slate-700">الخبرات العملية (اذكر جهة العمل والمهام)</label>
        <textarea 
          className="w-full p-4 bg-slate-50 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 h-32" 
          value={exp} 
          onChange={e => setExp(e.target.value)}
        />
      </div>

      <div className="space-y-2">
        <div className="flex justify-between items-center">
          <label className="text-sm font-bold text-slate-700">المهارات التقنية (افصل بينها بفاصلة)</label>
          {suggesting && <i className="fa-solid fa-spinner fa-spin text-emerald-500 text-xs"></i>}
        </div>
        <input 
          type="text" 
          className="w-full p-3 bg-slate-50 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" 
          value={skillsInput} 
          onBlur={handleSkillBlur}
          onChange={e => setSkillsInput(e.target.value)}
          placeholder="مثال: SQL, Project Management, Python"
        />
        {suggestions.length > 0 && (
          <div className="flex flex-wrap gap-2 pt-2">
            <span className="text-xs font-bold text-emerald-600 w-full mb-1">كلمات مفتاحية مقترحة لرفع الـ ATS:</span>
            {suggestions.map((s, i) => (
              <button 
                key={i} 
                onClick={() => addSuggestion(s)}
                className="text-[10px] bg-emerald-50 text-emerald-700 border border-emerald-200 px-2 py-1 rounded-full hover:bg-emerald-100 transition-colors"
              >
                + {s}
              </button>
            ))}
          </div>
        )}
      </div>

      <button 
        onClick={() => onProcess(`${name}\n${exp}\nSkills: ${skillsInput}`, targetJob)}
        disabled={loading || !name || !targetJob}
        className="w-full bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-lg flex items-center justify-center gap-3 hover:bg-emerald-700 transition-all disabled:opacity-50"
      >
        {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
        تحسين السيرة بالذكاء الاصطناعي
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { SearchFilters, CandidateProfile } from '../types';
import { generateMockCandidates } from '../services/geminiService';

interface TalentScoutProps {
  onViewCandidate: (c: CandidateProfile) => void;
  onShortlist: (c: CandidateProfile) => void;
  shortlist: CandidateProfile[];
}

export const TalentScout: React.FC<TalentScoutProps> = ({ onViewCandidate, onShortlist, shortlist }) => {
  const [filters, setFilters] = useState<SearchFilters>({ city: '', experience_years: '', skills: '', language: '' });
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<CandidateProfile[]>([]);

  const handleSearch = async () => {
    setLoading(true);
    try {
      const data = await generateMockCandidates(filters);
      setResults(data);
    } catch (e) {
      alert("خطأ في البحث");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-10">
      <div className="bg-slate-900 p-8 rounded-3xl shadow-xl border border-slate-800">
        <h3 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
          <i className="fa-solid fa-magnifying-glass text-emerald-400"></i>
          محرك البحث المتقدم عن الكفاءات
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <input 
            className="bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none focus:ring-1 focus:ring-emerald-500 text-sm" 
            placeholder="المدينة (الرياض، جدة...)" 
            value={filters.city}
            onChange={e => setFilters({...filters, city: e.target.value})}
          />
          <input 
            className="bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none focus:ring-1 focus:ring-emerald-500 text-sm" 
            placeholder="سنوات الخبرة" 
            value={filters.experience_years}
            onChange={e => setFilters({...filters, experience_years: e.target.value})}
          />
          <input 
            className="bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none focus:ring-1 focus:ring-emerald-500 text-sm" 
            placeholder="المهارات التقنية" 
            value={filters.skills}
            onChange={e => setFilters({...filters, skills: e.target.value})}
          />
          <button 
            onClick={handleSearch}
            disabled={loading}
            className="bg-emerald-600 text-white font-bold rounded-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"
          >
            {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-search"></i>}
            ابحث الآن
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {results.map(candidate => (
          <div key={candidate.id} className="bg-white rounded-3xl shadow-lg border border-slate-100 overflow-hidden group hover:border-emerald-500 transition-all">
            <div className="bg-slate-50 p-6 border-b border-slate-100 relative">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="font-black text-slate-900 text-lg">{candidate.full_name}</h4>
                  <p className="text-emerald-600 font-bold text-sm">{candidate.target_job}</p>
                </div>
                <div className="bg-emerald-50 text-emerald-700 px-3 py-1 rounded-full text-xs font-black">
                  {candidate.ai_fit_score}% مطابقة
                </div>
              </div>
              <div className="text-[10px] text-slate-500 flex items-center gap-2">
                <i className="fa-solid fa-location-dot"></i> {candidate.location}
              </div>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <p className="text-[10px] font-bold text-slate-400 mb-2 uppercase">أقوى 3 إنجازات:</p>
                <ul className="space-y-1">
                  {candidate.top_achievements.map((ach, i) => (
                    <li key={i} className="text-xs text-slate-700 flex items-start gap-2">
                      <i className="fa-solid fa-circle-check text-emerald-500 mt-1"></i>
                      {ach}
                    </li>
                  ))}
                </ul>
              </div>
              <div className="flex justify-between items-center pt-4 border-t">
                <span className="text-xs font-bold text-slate-500">الراتب المتوقع: <span className="text-slate-900">{candidate.expected_salary}</span></span>
              </div>
              <div className="grid grid-cols-2 gap-2 pt-2">
                <button 
                  onClick={() => onViewCandidate(candidate)}
                  className="bg-slate-900 text-white py-2 rounded-lg text-xs font-bold hover:bg-black transition-all"
                >
                  عرض الذكاء
                </button>
                <button 
                  onClick={() => onShortlist(candidate)}
                  className={`py-2 rounded-lg text-xs font-bold transition-all border ${
                    shortlist.some(s => s.id === candidate.id) 
                      ? 'bg-amber-50 border-amber-500 text-amber-600' 
                      : 'bg-white border-slate-200 text-slate-600 hover:border-emerald-500'
                  }`}
                >
                  {shortlist.some(s => s.id === candidate.id) ? 'في المفضلة' : 'حفظ'}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { SocialBrand } from './components/SocialBrand';
import { SalaryNegotiator } from './components/SalaryNegotiator';
import { CredentialVerifier } from './components/CredentialVerifier';
import { CareerSimulator } from './components/CareerSimulator';
import { PortfolioBuilder } from './components/PortfolioBuilder';
import { VirtualCoach } from './components/VirtualCoach';
import { CandidateHub } from './components/CandidateHub';
import { TalentScout } from './components/TalentScout';
import { processCVInput } from './services/geminiService';
import { UserRole, ApiResponse, VerificationResult, CandidateProfile } from './types';
import { APP_CONFIG } from './constants';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [editsCount, setEditsCount] = useState(0);
  const [userLocation, setUserLocation] = useState('السعودية');
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(() => setUserLocation("الرياض (منطقتك الحالية)"));
    }
  }, []);

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleProcessSeeker = async (data: string, target: string) => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(data, target, UserRole.SEEKER, userLocation);
      setResult(apiResult);
      setEditsCount(prev => prev + 1);
    } catch (error) {
      alert("حدث خطأ.");
    } finally {
      setLoading(false);
    }
  };

  const handleViewCandidate = (c: CandidateProfile) => {
    setActiveCandidate(c);
    setOtp(generateOtp(UserRole.EMPLOYER));
    // Simulate API Result for CV View
    setResult({
      cv: c as any,
      career_path: null,
      smart_helper: null,
      market_insights: null,
      social_brand: null,
      salary_negotiation: null,
      timeline: null,
      portfolio: null,
      market_pulse: null
    } as any);
  };

  const toggleShortlist = (c: CandidateProfile) => {
    setShortlist(prev => 
      prev.some(s => s.id === c.id) ? prev.filter(s => s.id !== c.id) : [...prev, c]
    );
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert("كود التفعيل غير صحيح");
  };

  if (!role) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <div className="inline-block bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest mb-4">AI-Powered Professional Services</div>
            <h2 className="text-5xl md:text-7xl font-black text-slate-900 leading-tight">سيرتي <span className="text-emerald-600">الاحترافية</span></h2>
            <p className="text-slate-500 text-xl max-w-2xl mx-auto">المحرك الأذكى لتمكين الكفاءات في سوق العمل السعودي 2026</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white border-2 border-slate-100 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-right flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className="text-3xl font-black text-slate-900 mb-2 underline decoration-emerald-200 decoration-8 underline-offset-4">Candidate Hub</h3><p className="text-slate-500 text-lg">بناء سيرة ذاتية عالمية، خطاب تغطية، وتحسين ATS فوري.</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 border-2 border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-right flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className="text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4">Talent Scout</h3><p className="text-slate-400 text-lg">فرز ذكي، تحليل تخصصات، وبطاقة مطابقة فورية للمرشحين.</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="container mx-auto px-4 py-12">
        <div className="flex items-center justify-between mb-12 max-w-6xl mx-auto">
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setActiveCandidate(null);}} className="text-slate-500 font-bold flex items-center gap-2 hover:text-slate-900 transition-colors"><i className="fa-solid fa-arrow-right"></i> القائمة الرئيسية</button>
          <div className="bg-slate-900 text-white px-6 py-2 rounded-full text-xs font-bold flex items-center gap-3">
             <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
             {role === UserRole.SEEKER ? 'Candidate Hub Active' : 'Talent Scout Portal'}
          </div>
        </div>

        {role === UserRole.SEEKER && !result && (
          <div className="max-w-4xl mx-auto"><CandidateHub onProcess={handleProcessSeeker} loading={loading} /></div>
        )}

        {role === UserRole.EMPLOYER && !activeCandidate && (
          <div className="max-w-6xl mx-auto">
             <TalentScout onViewCandidate={handleViewCandidate} onShortlist={toggleShortlist} shortlist={shortlist} />
          </div>
        )}

        {result && otp && !activated && <div className="py-12"><Paywall role={role} otp={otp} onActivate={handleActivate} /></div>}

        {result && activated && (
          <div className="space-y-12 max-w-4xl mx-auto">
            <div className="flex justify-between items-center bg-emerald-600 text-white p-6 rounded-3xl shadow-xl">
               <div className="flex items-center gap-4">
                 <i className="fa-solid fa-check-circle text-3xl"></i>
                 <div>
                   <h4 className="font-black">تم تفعيل المحتوى بالكامل</h4>
                   <p className="text-xs opacity-80">يمكنك الآن استعراض كافة البيانات والتحميل</p>
                 </div>
               </div>
               <button onClick={() => window.print()} className="bg-white text-emerald-600 px-8 py-3 rounded-2xl font-black shadow-lg hover:bg-slate-50 transition-all flex items-center gap-2">
                 <i className="fa-solid fa-download"></i> PDF
               </button>
            </div>

            <CVPreview data={result.cv} />

            {role === UserRole.SEEKER && (
              <div className="grid grid-cols-1 gap-12">
                <CareerSimulator data={result.timeline} />
                <PortfolioBuilder data={result.portfolio} />
                <VirtualCoach targetJob={result.cv.personal_info.target_job} />
                <CareerRadar data={result.market_insights} />
                <CareerPath data={result.career_path} />
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                  <SalaryNegotiator data={result.salary_negotiation} />
                  <SocialBrand data={result.social_brand} />
                </div>
                <SmartHelper data={result.smart_helper} />
                <JobMatcher cv={result.cv} />
              </div>
            )}

            {activeCandidate && (
              <div className="bg-indigo-50 border border-indigo-200 p-8 rounded-3xl">
                <h3 className="text-xl font-bold text-indigo-900 mb-4 flex items-center gap-2">
                  <i className="fa-solid fa-user-shield"></i>
                  بيانات التواصل والملخص الذكي
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                   <div className="space-y-2">
                     <p className="text-sm font-bold text-indigo-700">البريد الإلكتروني:</p>
                     <p className="bg-white p-3 rounded-xl border border-indigo-100">{activeCandidate.email}</p>
                   </div>
                   <div className="space-y-2">
                     <p className="text-sm font-bold text-indigo-700">رقم الجوال:</p>
                     <p className="bg-white p-3 rounded-xl border border-indigo-100">{activeCandidate.phone}</p>
                   </div>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

export enum UserRole {
  SEEKER = 'SEEKER',
  EMPLOYER = 'EMPLOYER'
}

export interface Experience {
  company: string;
  position: string;
  duration: string;
  achievements: string[];
}

export interface Education {
  institution: string;
  degree: string;
  year: string;
}

export interface CVData {
  personal_info: {
    full_name: string;
    email: string;
    phone: string;
    location: string;
    target_job: string;
  };
  summary: string;
  experience: Experience[];
  education: Education[];
  skills: string[];
  ats_score: number;
  is_verified?: boolean;
}

export interface CandidateProfile extends CVData {
  id: string;
  top_achievements: string[];
  ai_fit_score: number;
  expected_salary: string;
  languages: string[];
}

