  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a candidate scorecard. 
    ATS Score: ${cv.ats_score}
    Interview Performance: ${report ? (report.technical_depth + report.tact) / 2 : 'N/A'}
    Reliability: ${cv.is_verified ? 'High' : 'Medium'}
