import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult, VerificationResult, InterviewAnalysis, CandidateProfile, InterviewQuestion, InterviewReport, ScorecardData } from "../types";

export const verifyCertificate = async (base64Data: string, cvData: CVData): Promise<VerificationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const data = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;
  const mimeType = base64Data.includes(';') ? base64Data.split(';')[0].split(':')[1] : 'image/png';

  const imagePart = {
    inlineData: {
      data,
      mimeType,
    },
  };
  const textPart = {
    text: `Verify if this professional certificate belongs to ${cvData.personal_info.full_name} and aligns with their career goals. Return the analysis in JSON format: { "certificate_name": "string", "issuer": "string", "is_valid": boolean, "match_explanation": "string" }`
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, textPart] },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{}');
};

export const analyzeSelfIntro = async (text: string, targetJob: string): Promise<InterviewAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze the following self-introduction for a ${targetJob} position: "${text}". Provide feedback on confidence, relevant keywords, and EQ. 
    Return the response in JSON format: { "confidence_score": number, "keywords_score": number, "eq_score": number, "feedback": "string", "suggested_phrases": ["string"] }`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export const processCVInput = async (input: string, targetJob: string, role: string, userLocation?: string): Promise<ApiResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      You are the Core Engine of "Sirati Al-Mohtarefah" managed by Faisal Saeed Abdullah Al-Sunni.
      Role: ${role}
      Input: ${input}
      Target: ${targetJob}
      Location: ${userLocation}

      CORE INSTRUCTIONS:
      1. DEEP MINING: Analyze job title evolution and modernize titles (e.g., "Writer" -> "Content Manager"). Identify timeline gaps.
      2. AUTO-ENRICHMENT: For each experience, generate 5 "Smart Achievements" based on industry standards if not provided.
      3. SEMANTIC TRANSFORMATION: Convert paragraphs to bullet points starting with ATS-friendly action verbs.
      4. SOVEREIGN PROOFREADING: Fix all spelling/grammar and unify technical terms.
      5. COMPARISON REPORT: Provide an old ATS score vs a new ATS score.

      Generate a complete enhanced CV and career data in JSON format.
      Schema includes: cv, career_path, smart_helper, market_insights, social_brand, salary_negotiation, timeline, portfolio, market_pulse, 
      AND "enhancement" { old_score, new_score, modernized_titles: [{old, new}], detected_gaps: [], enrichment_summary },
      AND "suggested_achievements": [{ position_idx: number, achievements: [string] }]
    `,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateInterviewQuestions = async (targetJob: string, skills: string[]): Promise<InterviewQuestion[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate 3 high-quality technical interview questions for a ${targetJob} role, focusing on these skills: ${skills.join(', ')}. Return as JSON array of objects with 'id' and 'question'.`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '[]');
};

export const analyzeInterviewAnswers = async (questions: InterviewQuestion[], answers: string[]): Promise<InterviewReport> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const qa = questions.map((q, i) => `Q: ${q.question}\nA: ${answers[i]}`).join('\n\n');
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze these interview answers for honesty, technical depth, and tact. 
    ${qa}
    Return JSON: { "honesty": number (0-100), "technical_depth": number (0-100), "tact": number (0-100), "summary": "string" }`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export const generateScorecard = async (cv: CVData, report?: InterviewReport): Promise<ScorecardData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a candidate scorecard. 
    ATS Score: ${cv.ats_score}
    Interview Performance: ${report ? (report.technical_depth + report.tact) / 2 : 'N/A'}
    Reliability: ${cv.is_verified ? 'High' : 'Medium'}
    Return JSON: { "ats_score": number, "interview_score": number, "reliability_score": number, "recommendation": "HIRE"|"FUTURE"|"REJECT", "summary_text": "string" }`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

