          className="w-full p-4 bg-slate-50 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 h-32" 
          value={exp} 
          onChange={e => setExp(e.target.value)}
          placeholder="يمكنك الكتابة هنا أو الصق النص مباشرة..."
        />
      </div>

      <div className="space-y-2">
        <div className="flex justify-between items-center">
          <label className="text-sm font-bold text-slate-700">المهارات التقنية (افصل بينها بفاصلة)</label>
          {suggesting && <i className="fa-solid fa-spinner fa-spin text-emerald-500 text-xs"></i>}
        </div>
        <input 
          type="text" 
          className="w-full p-3 bg-slate-50 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" 
          value={skillsInput} 
          onBlur={handleSkillBlur}
          onChange={e => setSkillsInput(e.target.value)}
          placeholder="مثال: SQL, Project Management, Python"
        />
        {suggestions.length > 0 && (
          <div className="flex flex-wrap gap-2 pt-2">
            <span className="text-xs font-bold text-emerald-600 w-full mb-1">كلمات مفتاحية مقترحة لرفع الـ ATS:</span>
