import React from 'react';
import { CVData, TemplateType, ThemeConfig, Language } from '../types';

interface CVPreviewProps {
  data: CVData;
  template: TemplateType;
  theme: ThemeConfig;
  lang: Language;
  activated: boolean;
}

export const CVPreview: React.FC<CVPreviewProps> = ({ data, template, theme, lang, activated }) => {
  const isRtl = lang === Language.AR;
  const directionClass = isRtl ? 'rtl' : 'ltr';
  const textAlignClass = isRtl ? 'text-right' : 'text-left';

  const renderSection = (type: string) => {
    switch (type) {
      case 'summary':
        return (
          <section key="summary" className="mb-6">
            <h3 style={{ color: theme.primaryColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-3 uppercase tracking-wider">
              {isRtl ? 'الملخص المهني' : 'Professional Summary'}
            </h3>
            <p className="text-sm leading-relaxed text-slate-700 text-justify">{data.summary}</p>
          </section>
        );
      case 'experience':
        return (
          <section key="experience" className="mb-6">
            <h3 style={{ color: theme.primaryColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-4 uppercase tracking-wider">
              {isRtl ? 'الخبرات العملية' : 'Work Experience'}
            </h3>
            <div className="space-y-4">
              {data.experience.map((exp, idx) => (
                <div key={idx} className="relative">
                  <div className="flex justify-between items-baseline mb-1">
                    <h4 className="font-bold text-slate-900">{exp.position}</h4>
                    <span className="text-[10px] text-slate-500 font-bold">{exp.duration}</span>
                  </div>
                  <p className="text-sm italic mb-2" style={{ color: theme.primaryColor }}>{exp.company}</p>
                  <ul className="list-disc list-inside space-y-1 text-slate-700 text-xs">
                    {exp.achievements.map((item, i) => <li key={i}>{item}</li>)}
                  </ul>
                </div>
              ))}
            </div>
          </section>
        );
      case 'education':
        return (
          <section key="education" className="mb-6">
            <h3 style={{ color: theme.primaryColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-3 uppercase tracking-wider">
              {isRtl ? 'التعليم' : 'Education'}
            </h3>
            <div className="space-y-3">
              {data.education.map((edu, idx) => (
                <div key={idx}>
                  <h4 className="font-bold text-slate-900 text-sm">{edu.degree}</h4>
                  <p className="text-xs text-slate-600">{edu.institution} | {edu.year}</p>
                </div>
              ))}
            </div>
          </section>
        );
      case 'skills':
        return (
          <section key="skills" className="mb-6">
            <h3 style={{ color: theme.primaryColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-3 uppercase tracking-wider">
              {isRtl ? 'المهارات' : 'Skills'}
            </h3>
            <div className="flex flex-wrap gap-2">
              {data.skills.map((skill, idx) => (
                <span key={idx} className="px-2 py-1 bg-slate-100 text-slate-700 rounded text-[10px] font-bold border border-slate-200">
                  {skill}
                </span>
              ))}
            </div>
          </section>
        );
      default:
        return null;
    }
  };

  const renderClassic = () => (
    <div className={`p-12 ${textAlignClass}`}>
      <div className="border-b-4 border-slate-900 pb-6 mb-8 text-center">
        <h2 className="text-4xl font-black text-slate-900 mb-2 uppercase">{data.personal_info.full_name}</h2>
        <div className="flex justify-center gap-6 text-xs text-slate-600 font-bold">
          <span>{data.personal_info.email}</span>
          <span>•</span>
          <span>{data.personal_info.phone}</span>
          <span>•</span>
          <span>{data.personal_info.location}</span>
        </div>
      </div>
      {theme.sectionOrder.map(renderSection)}
    </div>
  );

  const renderProfessional = () => (
    <div className={`p-12 ${textAlignClass}`}>
      <div className="flex justify-between items-start mb-10">
        <div>
          <h2 className="text-5xl font-black text-slate-900 mb-1" style={{ color: theme.primaryColor }}>{data.personal_info.full_name}</h2>
          <p className="text-xl font-bold text-slate-500 uppercase tracking-widest">{data.personal_info.target_job}</p>
        </div>
        <div className="text-right text-xs space-y-1 font-medium text-slate-600">
          <p>{data.personal_info.email}</p>
          <p>{data.personal_info.phone}</p>
          <p>{data.personal_info.location}</p>
        </div>
      </div>
      <div className="grid grid-cols-1 gap-4">
        {theme.sectionOrder.map(renderSection)}
      </div>
    </div>
  );

  const renderModern = () => (
    <div className={`flex min-h-[1123px] ${directionClass}`}>
      <div className="w-1/3 bg-slate-900 text-white p-8 space-y-8">
        <div className="space-y-4">
          <div className="w-32 h-32 bg-slate-800 rounded-2xl mx-auto flex items-center justify-center border-2 border-slate-700 shadow-xl">
             <i className="fa-solid fa-user text-5xl text-slate-600"></i>
          </div>
          <div className="text-center">
             <h2 className="text-xl font-black mb-1">{data.personal_info.full_name}</h2>
             <p className="text-xs text-slate-400 font-bold uppercase tracking-widest" style={{ color: theme.primaryColor }}>{data.personal_info.target_job}</p>
          </div>
        </div>
        <div className="space-y-6">
          <section>
            <h4 className="text-[10px] font-black uppercase text-slate-500 mb-3 border-b border-slate-700 pb-1">Contact</h4>
            <div className="text-xs space-y-2 opacity-80">
              <p className="flex items-center gap-2"><i className="fa-solid fa-envelope w-4"></i> {data.personal_info.email}</p>
              <p className="flex items-center gap-2"><i className="fa-solid fa-phone w-4"></i> {data.personal_info.phone}</p>
              <p className="flex items-center gap-2"><i className="fa-solid fa-location-dot w-4"></i> {data.personal_info.location}</p>
            </div>
          </section>
          {theme.sectionOrder.filter(s => s === 'skills' || s === 'education').map(s => {
             if (s === 'skills') return (
               <section key="skills_side">
                 <h4 className="text-[10px] font-black uppercase text-slate-500 mb-3 border-b border-slate-700 pb-1">Expertise</h4>
                 <div className="flex flex-wrap gap-1">
                   {data.skills.map((sk, i) => <span key={i} className="bg-slate-800 text-[9px] px-2 py-1 rounded">{sk}</span>)}
                 </div>
               </section>
             );
             if (s === 'education') return (
              <section key="edu_side">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-3 border-b border-slate-700 pb-1">Education</h4>
                <div className="space-y-3">
                  {data.education.map((edu, i) => (
                    <div key={i} className="text-[10px]">
                      <p className="font-black" style={{ color: theme.primaryColor }}>{edu.degree}</p>
                      <p className="opacity-60">{edu.institution}</p>
                    </div>
                  ))}
                </div>
              </section>
             );
          })}
        </div>
      </div>
      <div className={`flex-1 p-12 bg-white ${textAlignClass}`}>
        {theme.sectionOrder.filter(s => s === 'summary' || s === 'experience').map(renderSection)}
      </div>
    </div>
  );

  const renderNeom = () => (
    <div className={`p-12 bg-slate-50 ${textAlignClass}`}>
      <div className="bg-white rounded-[40px] shadow-2xl p-10 border border-slate-100 mb-8 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 blur-3xl rounded-full opacity-20" style={{ backgroundColor: theme.primaryColor }}></div>
        <div className="flex flex-col md:flex-row justify-between items-center gap-6 relative z-10">
           <div>
             <h2 className="text-4xl font-black text-slate-900 mb-2">{data.personal_info.full_name}</h2>
             <div className="flex gap-4">
                <span className="text-xs font-black px-3 py-1 bg-slate-900 text-white rounded-full">{data.personal_info.target_job}</span>
                <span className="text-xs font-bold text-slate-400">{data.personal_info.location}</span>
             </div>
           </div>
           <div className="flex flex-col items-end gap-1">
             <div className="bg-emerald-50 text-emerald-600 px-4 py-1.5 rounded-2xl text-[10px] font-black border border-emerald-100">
               ATS RATING: {data.ats_score}%
             </div>
           </div>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {theme.sectionOrder.map(renderSection)}
      </div>
    </div>
  );

  const getTemplate = () => {
    switch (template) {
      case TemplateType.CLASSIC: return renderClassic();
      case TemplateType.PROFESSIONAL: return renderProfessional();
      case TemplateType.MODERN: return renderModern();
      case TemplateType.NEOM: return renderNeom();
    }
  };

  return (
    <div className={`bg-white shadow-2xl overflow-hidden min-h-[1123px] relative mx-auto max-w-[800px] border border-slate-200 ${directionClass}`}>
      {!activated && (
        <div className="absolute inset-0 pointer-events-none z-50 overflow-hidden flex flex-col justify-center gap-32">
          {Array(8).fill(0).map((_, i) => (
            <div key={i} className="text-slate-200/40 text-6xl font-black -rotate-45 whitespace-nowrap select-none w-full text-center">
              {isRtl ? 'نسخة معاينة - غير مفعلة' : 'PREVIEW ONLY - NOT ACTIVATED'}
            </div>
          ))}
        </div>
      )}
      {getTemplate()}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { SocialBrand } from './components/SocialBrand';
import { SalaryNegotiator } from './components/SalaryNegotiator';
import { CredentialVerifier } from './components/CredentialVerifier';
import { CareerSimulator } from './components/CareerSimulator';
import { PortfolioBuilder } from './components/PortfolioBuilder';
import { VirtualCoach } from './components/VirtualCoach';
import { CandidateHub } from './components/CandidateHub';
import { TalentScout } from './components/TalentScout';
import { AIScreening } from './components/AIScreening';
import { Scorecard } from './components/Scorecard';
import { SmartScheduler } from './components/SmartScheduler';
import { CVComparison } from './components/CVComparison';
import { processCVInput, generateInterviewQuestions, generateScorecard, translateCV } from './services/geminiService';
import { UserRole, ApiResponse, VerificationResult, CandidateProfile, InterviewQuestion, InterviewReport, ScorecardData, TemplateType, ThemeConfig, Language } from './types';
import { APP_CONFIG } from './constants';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [rawInput, setRawInput] = useState('');
  const [userLocation, setUserLocation] = useState('السعودية');
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  // Design & Language State
  const [template, setTemplate] = useState<TemplateType>(TemplateType.PROFESSIONAL);
  const [lang, setLang] = useState<Language>(Language.AR);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#059669', // Default Emerald-600
    sectionOrder: ['summary', 'experience', 'education', 'skills']
  });

  // AI Interview State
  const [screeningQuestions, setScreeningQuestions] = useState<InterviewQuestion[]>([]);
  const [interviewReport, setInterviewReport] = useState<InterviewReport | null>(null);
  const [scorecard, setScorecard] = useState<ScorecardData | null>(null);
  const [showInterview, setShowInterview] = useState(false);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(() => setUserLocation("الرياض (منطقتك الحالية)"));
    }
  }, []);

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleProcessSeeker = async (data: string, target: string, ghost: boolean) => {
    setLoading(true);
    setRawInput(data);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(data, target, UserRole.SEEKER, userLocation);
      apiResult.cv.is_ghost_mode = ghost;
      setResult(apiResult);
    } catch (error) {
      alert("حدث خطأ.");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslate = async () => {
    if (!result) return;
    setLoading(true);
    const newLang = lang === Language.AR ? Language.EN : Language.AR;
    try {
      const translatedData = await translateCV(result.cv, newLang);
      setResult({ ...result, cv: translatedData });
      setLang(newLang);
    } catch (e) {
      alert("فشل الترجمة الذكية");
    } finally {
      setLoading(false);
    }
  };

  const handleConfirmAchievement = (idx: number, ach: string) => {
    if (!result) return;
    const newCV = { ...result.cv };
    if (newCV.experience[idx]) {
      if (!newCV.experience[idx].achievements.includes(ach)) {
        newCV.experience[idx].achievements.push(ach);
        setResult({ ...result, cv: newCV });
      }
    }
  };

  const handleStartInterview = async (c: CandidateProfile) => {
    setLoading(true);
    try {
      const qs = await generateInterviewQuestions(c.personal_info.target_job, c.skills);
      setScreeningQuestions(qs);
      setShowInterview(true);
    } catch (e) {
      alert("فشل توليد أسئلة المقابلة");
    } finally {
      setLoading(false);
    }
  };

  const handleInterviewComplete = async (report: InterviewReport) => {
    setInterviewReport(report);
    if (activeCandidate) {
      const sc = await generateScorecard(activeCandidate, report);
      setScorecard(sc);
    }
    setShowInterview(false);
  };

  const handleViewCandidate = (c: CandidateProfile) => {
    setActiveCandidate(c);
    setOtp(generateOtp(UserRole.EMPLOYER));
    setResult({
      cv: c as any,
      career_path: {} as any,
      smart_helper: {} as any,
      market_insights: {} as any,
      social_brand: {} as any,
      salary_negotiation: {} as any,
      timeline: {} as any,
      portfolio: {} as any,
      market_pulse: {} as any
    } as ApiResponse);
  };

  const toggleShortlist = (c: CandidateProfile) => {
    setShortlist(prev => 
      prev.some(s => s.id === c.id) ? prev.filter(s => s.id !== c.id) : [...prev, c]
    );
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert("كود التفعيل غير صحيح");
  };

  const themeColors = ['#059669', '#1d4ed8', '#1e293b', '#7c3aed', '#be123c'];

  if (!role) {
    return (
      <Layout>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <h2 className="text-5xl md:text-7xl font-black text-slate-900 leading-tight">سيرتي <span className="text-emerald-600">الاحترافية</span></h2>
            <p className="text-slate-500 text-xl max-w-2xl mx-auto">المحرك الأذكى لتمكين الكفاءات في سوق العمل السعودي 2026</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white border-2 border-slate-100 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-right flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className="text-3xl font-black text-slate-900 mb-2 underline decoration-emerald-200 decoration-8 underline-offset-4">Candidate Hub</h3><p className="text-slate-500 text-lg">بناء سيرة ذاتية عالمية مع وضع التوظيف الصامت وتعدد القوالب.</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 border-2 border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-right flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className="text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4">Talent Scout</h3><p className="text-slate-400 text-lg">فرز ذكي، مقابلات AI، وتقارير ملاءمة فورية.</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="container mx-auto px-4 py-12">
        <div className="flex items-center justify-between mb-12 max-w-6xl mx-auto">
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setActiveCandidate(null);}} className="text-slate-500 font-bold flex items-center gap-2 hover:text-slate-900 transition-colors"><i className="fa-solid fa-arrow-right"></i> القائمة الرئيسية</button>
          <div className="bg-slate-900 text-white px-6 py-2 rounded-full text-xs font-bold flex items-center gap-3">
             <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
             {role === UserRole.SEEKER ? 'Candidate Hub Active' : 'Talent Scout Portal'}
          </div>
        </div>

        {role === UserRole.SEEKER && !result && (
          <div className="max-w-4xl mx-auto"><CandidateHub onProcess={handleProcessSeeker} loading={loading} /></div>
        )}

        {role === UserRole.EMPLOYER && !activeCandidate && (
          <div className="max-w-6xl mx-auto">
             <TalentScout onViewCandidate={handleViewCandidate} onShortlist={toggleShortlist} shortlist={shortlist} />
          </div>
        )}

        {role === UserRole.SEEKER && result && !activated && (
          <div className="max-w-6xl mx-auto mb-12">
            <CVComparison 
              originalText={rawInput} 
              report={result.enhancement!} 
              suggested={result.suggested_achievements || []}
              onConfirmAchievement={handleConfirmAchievement}
            />
          </div>
        )}

        {result && (
          <div className="max-w-6xl mx-auto flex flex-col lg:flex-row gap-8">
