import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult, VerificationResult, InterviewAnalysis, CandidateProfile, InterviewQuestion, InterviewReport, ScorecardData, Language } from "../types";

export const translateCV = async (cv: CVData, targetLang: Language): Promise<CVData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are a professional recruitment expert. Translate the following CV data to ${targetLang === Language.EN ? 'English' : 'Arabic'}. 
    RULES:
    1. CONTEXTUAL TRANSLATION: Do not use literal translation. Use industry-standard professional terms (e.g., 'Customer Service' might become 'Client Relations' or 'Customer Success' depending on the role).
    2. CULTURAL ADAPTATION: Adapt phrasing to sound native and professional in the target language.
    3. GLOSSARY: Use modern Saudi market and Global terminology.
    4. Maintain exact JSON structure.

    Data: ${JSON.stringify(cv)}`,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || '{}');
};

export const verifyCertificate = async (base64Data: string, cvData: CVData): Promise<VerificationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const data = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;
  const mimeType = base64Data.includes(';') ? base64Data.split(';')[0].split(':')[1] : 'image/png';

  const imagePart = {
    inlineData: {
      data,
      mimeType,
    },
  };
  const textPart = {
    text: `Verify if this professional certificate belongs to ${cvData.personal_info.full_name} and aligns with their career goals. Return the analysis in JSON format: { "certificate_name": "string", "issuer": "string", "is_valid": boolean, "match_explanation": "string" }`
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, textPart] },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{}');
};

