const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [rawInput, setRawInput] = useState('');
  const [userLocation, setUserLocation] = useState('السعودية');
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  // Language & Design State
  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [template, setTemplate] = useState<TemplateType>(TemplateType.PROFESSIONAL);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#059669', // Default Emerald-600
    sectionOrder: ['summary', 'experience', 'education', 'skills']
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(() => setUserLocation(isRtl ? "الرياض (منطقتك الحالية)" : "Riyadh (Your current location)"));
    }
  }, [uiLang]);

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleProcessSeeker = async (data: string, target: string, ghost: boolean) => {
    setLoading(true);
    setRawInput(data);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(data, target, UserRole.SEEKER, userLocation, uiLang);
      apiResult.cv.is_ghost_mode = ghost;
      setResult(apiResult);
    } catch (error) {
      alert(isRtl ? "حدث خطأ أثناء معالجة البيانات." : "Error processing data.");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    if (!result) {
      setUiLang(prev => prev === Language.AR ? Language.EN : Language.AR);
      return;
    }
    setLoading(true);
    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert(isRtl ? "فشل الترجمة الذكية للقوالب." : "Smart translation failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleConfirmAchievement = (idx: number, ach: string) => {
    if (!result) return;
    const newCV = { ...result.cv };
    if (newCV.experience[idx]) {
      if (!newCV.experience[idx].achievements.includes(ach)) {
        newCV.experience[idx].achievements.push(ach);
        setResult({ ...result, cv: newCV });
      }
    }
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert(isRtl ? "كود التفعيل غير صحيح" : "Invalid activation code");
  };

  const handleStartInterview = async (c: CandidateProfile) => {
    setLoading(true);
    try {
      const qs = await generateInterviewQuestions(c.personal_info.target_job, c.skills);
      // set questions etc... (omitted for brevity in this block, assumed existing)
    } catch (e) {
      alert("Failed to start AI Screening.");
    } finally {
      setLoading(false);
    }
  };

  const handleViewCandidate = (c: CandidateProfile) => {
    setActiveCandidate(c);
    setOtp(generateOtp(UserRole.EMPLOYER));
    setResult({
      cv: c as any,
      career_path: {} as any,
      smart_helper: {} as any,
      market_insights: {} as any,
      social_brand: {} as any,
      salary_negotiation: {} as any,
      timeline: {} as any,
      portfolio: {} as any,
      market_pulse: {} as any
    } as ApiResponse);
  };

  const toggleShortlist = (c: CandidateProfile) => {
    setShortlist(prev => 
      prev.some(s => s.id === c.id) ? prev.filter(s => s.id !== c.id) : [...prev, c]
    );
  };

  const themeColors = ['#059669', '#1d4ed8', '#1e293b', '#7c3aed', '#be123c'];

  if (!role) {
    return (
      <Layout lang={uiLang} onLangToggle={handleTranslateToggle}>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <h2 className={`text-5xl md:text-7xl font-black text-slate-900 leading-tight ${!isRtl ? 'font-en' : ''}`}>
              {t.hero_title} <span className="text-emerald-600">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 text-xl max-w-2xl mx-auto">{t.hero_desc}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white border-2 border-slate-100 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className={`text-3xl font-black text-slate-900 mb-2 underline decoration-emerald-200 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_seeker}</h3><p className="text-slate-500 text-lg">{t.role_seeker_desc}</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 border-2 border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className={`text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_employer}</h3><p className="text-slate-400 text-lg">{t.role_employer_desc}</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle}>
      <div className="container mx-auto px-4 py-12">
        <div className={`flex items-center justify-between mb-12 max-w-6xl mx-auto`}>
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setActiveCandidate(null);}} className="text-slate-500 font-bold flex items-center gap-2 hover:text-slate-900 transition-colors">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i> {t.back_to_main}
          </button>
          <div className="bg-slate-900 text-white px-6 py-2 rounded-full text-xs font-bold flex items-center gap-3">
             <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
             {role === UserRole.SEEKER ? 'Candidate Hub Active' : 'Talent Scout Portal'}
          </div>
        </div>

        {role === UserRole.SEEKER && !result && (
          <div className="max-w-4xl mx-auto">
            <CandidateHub onProcess={handleProcessSeeker} loading={loading} />
          </div>
        )}

        {role === UserRole.EMPLOYER && !activeCandidate && (
          <div className="max-w-6xl mx-auto">
             <TalentScout onViewCandidate={handleViewCandidate} onShortlist={toggleShortlist} shortlist={shortlist} />
          </div>
        )}

        {role === UserRole.SEEKER && result && !activated && result.enhancement && (
          <div className="max-w-6xl mx-auto mb-12">
            <CVComparison 
              originalText={rawInput} 
              report={result.enhancement} 
              suggested={result.suggested_achievements || []}
              onConfirmAchievement={handleConfirmAchievement}
            />
          </div>
        )}

        {result && (
          <div className={`max-w-6xl mx-auto flex flex-col lg:flex-row gap-8 ${!isRtl ? 'lg:flex-row' : ''}`}>
            {/* Design Sidebar - Only for Seekers */}
            {role === UserRole.SEEKER && (
              <aside className="lg:w-80 space-y-6">
                <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100">
                  <h3 className="text-lg font-black mb-4 flex items-center gap-2">
                    <i className="fa-solid fa-palette text-emerald-500"></i>
                    {t.design_customize}
                  </h3>

                  <div className="space-y-6">
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.choose_template}</p>
                      <div className="grid grid-cols-2 gap-2">
                        {Object.values(TemplateType).map(v => (
                          <button 
                            key={v}
                            onClick={() => setTemplate(v)}
                            className={`p-2 rounded-xl border-2 text-[10px] font-bold transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 hover:border-slate-200 text-slate-500'}`}
                          >
                            {v}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.theme_color}</p>
                      <div className="flex gap-2">
                        {themeColors.map(c => (
                          <button 
                            key={c}
                            onClick={() => setTheme({...theme, primaryColor: c})}
                            className={`w-8 h-8 rounded-full border-2 transition-transform ${theme.primaryColor === c ? 'scale-125 border-white shadow-lg' : 'border-transparent'}`}
                            style={{ backgroundColor: c }}
                          />
                        ))}
                      </div>
                    </div>

                    <div>
                       <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.section_order}</p>
                       <div className="space-y-1">
                          {theme.sectionOrder.map((s, i) => (
                            <div key={s} className="flex items-center justify-between p-2 bg-slate-50 rounded-lg text-[10px] font-bold text-slate-600">
                               <span>{s.toUpperCase()}</span>
                               <div className="flex gap-2">
                                  <button onClick={() => {
                                    const newOrder = [...theme.sectionOrder];
                                    if (i > 0) [newOrder[i-1], newOrder[i]] = [newOrder[i], newOrder[i-1]];
                                    setTheme({...theme, sectionOrder: newOrder});
                                  }} className="text-slate-400 hover:text-emerald-500"><i className="fa-solid fa-chevron-up"></i></button>
                               </div>
                            </div>
                          ))}
                       </div>
                    </div>

                    <button 
                      onClick={handleTranslateToggle}
                      disabled={loading}
                      className="w-full py-4 bg-slate-900 text-white rounded-2xl text-xs font-black hover:bg-black transition-all flex items-center justify-center gap-2"
                    >
                      {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-language"></i>}
                      {t.translate_btn}
                    </button>
                  </div>
                </div>
              </aside>
            )}

            <div className="flex-1 space-y-12">
               {/* Watermarked Preview Area */}
               <div className="relative">
                  <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />
               </div>

               {otp && !activated && <Paywall role={role} otp={otp} onActivate={handleActivate} lang={uiLang} />}

               {activated && (
                  <div className="space-y-12">
                    <div className="bg-emerald-600 text-white p-8 rounded-[40px] shadow-2xl flex items-center justify-between">
                       <div className="flex items-center gap-4">
                          <i className="fa-solid fa-crown text-4xl text-yellow-300"></i>
                          <div>
                             <h4 className="text-xl font-black">{t.verified_badge}</h4>
                             <p className="opacity-80 text-sm">{t.verified_desc}</p>
                          </div>
                       </div>
                       <button onClick={() => window.print()} className="bg-white text-emerald-600 px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-slate-50 transition-all flex items-center gap-2">
                         <i className="fa-solid fa-download"></i> {t.export_pdf}
                       </button>
                    </div>

                    {role === UserRole.SEEKER && (
                      <div className="grid grid-cols-1 gap-12">
                        <CareerPath data={result.career_path} />
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                           <CareerRadar data={result.market_insights} />
                           <CareerSimulator data={result.timeline} />
                        </div>
                        <VirtualCoach targetJob={result.cv.personal_info.target_job} />
                        <JobMatcher cv={result.cv} />
                        <SmartHelper data={result.smart_helper} />
                      </div>
                    )}
                  </div>
               )}
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

