      <footer className="bg-slate-900 dark:bg-black text-slate-400 py-8 text-center text-sm border-t border-slate-800 no-print">
        <p>© {new Date().getFullYear()} {isRtl ? 'جميع الحقوق محفوظة - منصة سيرتي الاحترافية' : 'All Rights Reserved - Sirati Pro Platform'}</p>
        <p className="mt-2 text-slate-500">{isRtl ? 'تم التطوير لتلبية أعلى معايير الجودة العالمية' : 'Developed to meet the highest global quality standards'}</p>
      </footer>
    </div>
  );
};

import React, { useState } from 'react';
import { PAYMENT_INFO, TRANSLATIONS } from '../constants';
