            {t.paywall_instructions}
          </h3>
          <div className="space-y-4 text-sm text-slate-700 dark:text-slate-300">
            <div className="flex justify-between">
              <span className="font-bold">{t.paywall_bank}</span>
              <span className="font-medium">{bankName}</span>
            </div>
            <div className="flex justify-between">
              <span className="font-bold">{t.paywall_beneficiary}</span>
              <span className="font-medium">{ownerName}</span>
            </div>
            <div className="flex flex-col gap-2">
              <span className="font-bold">{t.paywall_iban}</span>
              <span className="bg-white dark:bg-slate-900 p-3 rounded-xl border border-slate-200 dark:border-slate-700 font-mono text-center text-xs break-all shadow-sm dark:text-emerald-400">
                {PAYMENT_INFO.iban}
              </span>
            </div>
            <div className="flex justify-between items-center pt-4 border-t border-slate-200 dark:border-slate-700">
              <span className="font-black text-slate-900 dark:text-white text-lg">{t.paywall_amount}</span>
              <span className="text-2xl font-black text-emerald-600 dark:text-emerald-400">{price}</span>
            </div>
          </div>
        </div>

        <div className="space-y-4">
          <label className="block text-sm font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest">{t.paywall_activation_code}</label>
          <div className="flex flex-col md:flex-row gap-3">
            <input 
              type="text" 
              className="flex-grow p-4 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-2xl focus:ring-2 focus:ring-emerald-500 dark:focus:ring-emerald-400 outline-none text-center font-mono tracking-[0.5em] text-lg font-black dark:text-white"
              placeholder="XXXXXX"
              value={code}
              onChange={(e) => setCode(e.target.value.toUpperCase())}
            />
            <button 
              onClick={() => onActivate(code)}
              className="bg-slate-900 dark:bg-emerald-600 hover:bg-black dark:hover:bg-emerald-500 text-white font-black px-10 py-4 rounded-2xl transition-all shadow-xl hover:scale-105 active:scale-95"
            >
              {t.paywall_verify}
            </button>
          </div>
          <p className="text-xs text-slate-500 dark:text-slate-400 text-center leading-relaxed">
            {t.paywall_whatsapp_note}
            <a href={`https://wa.me/${PAYMENT_INFO.whatsapp}`} className="text-emerald-600 dark:text-emerald-400 font-black mx-1 hover:underline underline-offset-4">
               {PAYMENT_INFO.whatsapp}
            </a> 
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CVData, TemplateType, ThemeConfig, Language } from '../types';

interface CVPreviewProps {
  data: CVData;
  template: TemplateType;
  theme: ThemeConfig;
  lang: Language;
  activated: boolean;
}

export const CVPreview: React.FC<CVPreviewProps> = ({ data, template, theme, lang, activated }) => {
  const [eyeComfort, setEyeComfort] = useState(false);
  const isRtl = lang === Language.AR;
  const directionClass = isRtl ? 'rtl' : 'ltr';
  const textAlignClass = isRtl ? 'text-right' : 'text-left';

  const renderSection = (type: string) => {
    const textColor = eyeComfort ? 'text-slate-300' : 'text-slate-700';
    const headingColor = theme.primaryColor;

    switch (type) {
      case 'summary':
        return (
          <section key="summary" className="mb-6">
            <h3 style={{ color: headingColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-3 uppercase tracking-wider">
              {isRtl ? 'الملخص المهني' : 'Professional Summary'}
            </h3>
            <p className={`text-sm leading-relaxed ${textColor} text-justify`}>{data.summary}</p>
          </section>
        );
      case 'experience':
        return (
          <section key="experience" className="mb-6">
            <h3 style={{ color: headingColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-4 uppercase tracking-wider">
              {isRtl ? 'الخبرات العملية' : 'Work Experience'}
            </h3>
            <div className="space-y-4">
              {data.experience.map((exp, idx) => (
                <div key={idx} className="relative">
                  <div className="flex justify-between items-baseline mb-1">
                    <h4 className={`font-bold ${eyeComfort ? 'text-white' : 'text-slate-900'}`}>{exp.position}</h4>
                    <span className="text-[10px] text-slate-500 font-bold">{exp.duration}</span>
                  </div>
                  <p className="text-sm italic mb-2" style={{ color: headingColor }}>{exp.company}</p>
                  <ul className={`list-disc list-inside space-y-1 ${textColor} text-xs`}>
                    {exp.achievements.map((item, i) => <li key={i}>{item}</li>)}
                  </ul>
                </div>
              ))}
            </div>
          </section>
        );
      case 'education':
        return (
          <section key="education" className="mb-6">
            <h3 style={{ color: headingColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-3 uppercase tracking-wider">
              {isRtl ? 'التعليم' : 'Education'}
            </h3>
            <div className="space-y-3">
              {data.education.map((edu, idx) => (
                <div key={idx}>
                  <h4 className={`font-bold ${eyeComfort ? 'text-white' : 'text-slate-900'} text-sm`}>{edu.degree}</h4>
                  <p className={`text-xs ${eyeComfort ? 'text-slate-400' : 'text-slate-600'}`}>{edu.institution} | {edu.year}</p>
                </div>
              ))}
            </div>
          </section>
        );
      case 'skills':
        return (
          <section key="skills" className="mb-6">
            <h3 style={{ color: headingColor }} className="text-lg font-bold border-b-2 border-current pb-1 mb-3 uppercase tracking-wider">
              {isRtl ? 'المهارات' : 'Skills'}
            </h3>
            <div className="flex flex-wrap gap-2">
              {data.skills.map((skill, idx) => (
                <span key={idx} className={`px-2 py-1 ${eyeComfort ? 'bg-slate-800 text-slate-300' : 'bg-slate-100 text-slate-700'} rounded text-[10px] font-bold border border-slate-200 dark:border-slate-700`}>
                  {skill}
                </span>
              ))}
            </div>
          </section>
        );
      default:
        return null;
    }
  };

  const renderClassic = () => (
    <div className={`p-12 ${textAlignClass}`}>
      <div className={`border-b-4 ${eyeComfort ? 'border-slate-700' : 'border-slate-900'} pb-6 mb-8 text-center`}>
        <h2 className={`text-4xl font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} mb-2 uppercase`}>{data.personal_info.full_name}</h2>
        <div className={`flex justify-center gap-6 text-xs ${eyeComfort ? 'text-slate-400' : 'text-slate-600'} font-bold`}>
          <span>{data.personal_info.email}</span>
          <span>•</span>
          <span>{data.personal_info.phone}</span>
          <span>•</span>
          <span>{data.personal_info.location}</span>
        </div>
      </div>
      {theme.sectionOrder.map(renderSection)}
    </div>
  );

  const renderProfessional = () => (
    <div className={`p-12 ${textAlignClass}`}>
      <div className="flex justify-between items-start mb-10">
        <div>
          <h2 className={`text-5xl font-black mb-1`} style={{ color: eyeComfort ? 'white' : 'black' }}>{data.personal_info.full_name}</h2>
          <p className="text-xl font-bold text-slate-500 uppercase tracking-widest" style={{ color: theme.primaryColor }}>{data.personal_info.target_job}</p>
        </div>
        <div className={`text-right text-xs space-y-1 font-medium ${eyeComfort ? 'text-slate-400' : 'text-slate-600'}`}>
          <p>{data.personal_info.email}</p>
          <p>{data.personal_info.phone}</p>
          <p>{data.personal_info.location}</p>
        </div>
      </div>
      <div className="grid grid-cols-1 gap-4">
        {theme.sectionOrder.map(renderSection)}
      </div>
    </div>
  );

  const renderModern = () => (
    <div className={`flex min-h-[1123px] ${directionClass}`}>
      <div className="w-1/3 bg-slate-900 text-white p-8 space-y-8">
        <div className="space-y-4">
          <div className="w-32 h-32 bg-slate-800 rounded-2xl mx-auto flex items-center justify-center border-2 border-slate-700 shadow-xl">
             <i className="fa-solid fa-user text-5xl text-slate-600"></i>
          </div>
          <div className="text-center">
             <h2 className="text-xl font-black mb-1">{data.personal_info.full_name}</h2>
             <p className="text-xs text-slate-400 font-bold uppercase tracking-widest" style={{ color: theme.primaryColor }}>{data.personal_info.target_job}</p>
          </div>
        </div>
        <div className="space-y-6">
          <section>
            <h4 className="text-[10px] font-black uppercase text-slate-500 mb-3 border-b border-slate-700 pb-1">Contact</h4>
            <div className="text-xs space-y-2 opacity-80">
              <p className="flex items-center gap-2"><i className="fa-solid fa-envelope w-4"></i> {data.personal_info.email}</p>
              <p className="flex items-center gap-2"><i className="fa-solid fa-phone w-4"></i> {data.personal_info.phone}</p>
              <p className="flex items-center gap-2"><i className="fa-solid fa-location-dot w-4"></i> {data.personal_info.location}</p>
            </div>
          </section>
          {theme.sectionOrder.filter(s => s === 'skills' || s === 'education').map(s => {
             if (s === 'skills') return (
               <section key="skills_side">
                 <h4 className="text-[10px] font-black uppercase text-slate-500 mb-3 border-b border-slate-700 pb-1">Expertise</h4>
                 <div className="flex flex-wrap gap-1">
                   {data.skills.map((sk, i) => <span key={i} className="bg-slate-800 text-[9px] px-2 py-1 rounded">{sk}</span>)}
                 </div>
               </section>
             );
             if (s === 'education') return (
              <section key="edu_side">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-3 border-b border-slate-700 pb-1">Education</h4>
                <div className="space-y-3">
                  {data.education.map((edu, i) => (
                    <div key={i} className="text-[10px]">
                      <p className="font-black" style={{ color: theme.primaryColor }}>{edu.degree}</p>
                      <p className="opacity-60">{edu.institution}</p>
                    </div>
                  ))}
                </div>
              </section>
             );
          })}
        </div>
      </div>
      <div className={`flex-1 p-12 ${eyeComfort ? 'bg-slate-950' : 'bg-white'} ${textAlignClass}`}>
        {theme.sectionOrder.filter(s => s === 'summary' || s === 'experience').map(renderSection)}
      </div>
    </div>
  );

  const renderNeom = () => (
    <div className={`p-12 ${eyeComfort ? 'bg-slate-950' : 'bg-slate-50'} ${textAlignClass}`}>
      <div className={`${eyeComfort ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'} rounded-[40px] shadow-2xl p-10 border mb-8 relative overflow-hidden`}>
        <div className="absolute top-0 right-0 w-32 h-32 blur-3xl rounded-full opacity-20" style={{ backgroundColor: theme.primaryColor }}></div>
        <div className="flex flex-col md:flex-row justify-between items-center gap-6 relative z-10">
           <div>
             <h2 className={`text-4xl font-black mb-2 ${eyeComfort ? 'text-white' : 'text-slate-900'}`}>{data.personal_info.full_name}</h2>
             <div className="flex gap-4">
                <span className="text-xs font-black px-3 py-1 bg-slate-900 text-white rounded-full">{data.personal_info.target_job}</span>
                <span className="text-xs font-bold text-slate-400">{data.personal_info.location}</span>
             </div>
           </div>
           <div className="flex flex-col items-end gap-1">
             <div className="bg-emerald-50 text-emerald-600 px-4 py-1.5 rounded-2xl text-[10px] font-black border border-emerald-100 dark:bg-emerald-950 dark:border-emerald-900">
               ATS RATING: {data.ats_score}%
             </div>
           </div>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {theme.sectionOrder.map(renderSection)}
      </div>
    </div>
  );

  const getTemplate = () => {
    switch (template) {
      case TemplateType.CLASSIC: return renderClassic();
      case TemplateType.PROFESSIONAL: return renderProfessional();
      case TemplateType.MODERN: return renderModern();
      case TemplateType.NEOM: return renderNeom();
    }
  };

  return (
    <div className={`group relative mx-auto max-w-[800px] no-print`}>
      {/* Eye comfort toggle - floating inside preview */}
      <button 
        onClick={() => setEyeComfort(!eyeComfort)}
        className="absolute -top-12 left-0 bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-bold hover:bg-slate-700 transition-all flex items-center gap-2 z-[60]"
      >
        <i className={`fa-solid ${eyeComfort ? 'fa-eye' : 'fa-eye-slash'}`}></i>
        {eyeComfort ? (isRtl ? 'عرض وضع الطباعة' : 'View Print Mode') : (isRtl ? 'رؤية السيرة في الظلام' : 'Resume in the Dark')}
      </button>

      <div className={`${eyeComfort ? 'bg-slate-950 text-slate-300' : 'bg-white text-slate-900'} shadow-2xl overflow-hidden min-h-[1123px] relative border border-slate-200 dark:border-slate-800 ${directionClass} transition-colors duration-500`}>
        {!activated && (
          <div className="absolute inset-0 pointer-events-none z-50 overflow-hidden flex flex-col justify-center gap-32">
            {Array(8).fill(0).map((_, i) => (
              <div key={i} className="text-slate-200/40 dark:text-slate-700/20 text-6xl font-black -rotate-45 whitespace-nowrap select-none w-full text-center">
                {isRtl ? 'نسخة معاينة - غير مفعلة' : 'PREVIEW ONLY - NOT ACTIVATED'}
              </div>
            ))}
          </div>
        )}
        {getTemplate()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { SocialBrand } from './components/SocialBrand';
import { SalaryNegotiator } from './components/SalaryNegotiator';
import { CredentialVerifier } from './components/CredentialVerifier';
import { CareerSimulator } from './components/CareerSimulator';
import { PortfolioBuilder } from './components/PortfolioBuilder';
import { VirtualCoach } from './components/VirtualCoach';
import { CandidateHub } from './components/CandidateHub';
import { TalentScout } from './components/TalentScout';
import { AIScreening } from './components/AIScreening';
import { Scorecard } from './components/Scorecard';
import { SmartScheduler } from './components/SmartScheduler';
import { CVComparison } from './components/CVComparison';
import { processCVInput, generateInterviewQuestions, generateScorecard, translateCV } from './services/geminiService';
import { UserRole, ApiResponse, VerificationResult, CandidateProfile, InterviewQuestion, InterviewReport, ScorecardData, TemplateType, ThemeConfig, Language, ThemeMode } from './types';
import { APP_CONFIG, TRANSLATIONS } from './constants';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [rawInput, setRawInput] = useState('');
  const [userLocation, setUserLocation] = useState('السعودية');
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  // Theme & Language State
  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [themeMode, setThemeMode] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('sirati_theme');
    if (saved) return saved as ThemeMode;
    // Auto-detect system preference
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? ThemeMode.DARK : ThemeMode.LIGHT;
  });
  const [template, setTemplate] = useState<TemplateType>(TemplateType.PROFESSIONAL);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#059669', // Default Emerald-600
    sectionOrder: ['summary', 'experience', 'education', 'skills']
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(() => setUserLocation(isRtl ? "الرياض (منطقتك الحالية)" : "Riyadh (Your current location)"));
    }
  }, [uiLang]);

  const toggleTheme = () => {
    setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);
  };

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleProcessSeeker = async (data: string, target: string, ghost: boolean) => {
    setLoading(true);
    setRawInput(data);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(data, target, UserRole.SEEKER, userLocation, uiLang);
      apiResult.cv.is_ghost_mode = ghost;
      setResult(apiResult);
    } catch (error) {
      alert(isRtl ? "حدث خطأ أثناء معالجة البيانات." : "Error processing data.");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    if (!result) {
      setUiLang(prev => prev === Language.AR ? Language.EN : Language.AR);
      return;
    }
    setLoading(true);
    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert(isRtl ? "فشل الترجمة الذكية للقوالب." : "Smart translation failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleConfirmAchievement = (idx: number, ach: string) => {
    if (!result) return;
    const newCV = { ...result.cv };
    if (newCV.experience[idx]) {
      if (!newCV.experience[idx].achievements.includes(ach)) {
        newCV.experience[idx].achievements.push(ach);
        setResult({ ...result, cv: newCV });
      }
    }
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert(isRtl ? "كود التفعيل غير صحيح" : "Invalid activation code");
  };

  const handleViewCandidate = (c: CandidateProfile) => {
    setActiveCandidate(c);
    setOtp(generateOtp(UserRole.EMPLOYER));
    setResult({
      cv: c as any,
      career_path: {} as any,
      smart_helper: {} as any,
      market_insights: {} as any,
      social_brand: {} as any,
      salary_negotiation: {} as any,
      timeline: {} as any,
      portfolio: {} as any,
      market_pulse: {} as any
    } as ApiResponse);
  };

  const toggleShortlist = (c: CandidateProfile) => {
    setShortlist(prev => 
      prev.some(s => s.id === c.id) ? prev.filter(s => s.id !== c.id) : [...prev, c]
    );
  };

  const themeColors = [
    { name: 'Emerald', color: '#059669' },
    { name: 'Royal', color: '#1d4ed8' },
    { name: 'Midnight', color: '#1e293b' },
    { name: 'Gold', color: '#d97706' },
    { name: 'Classic', color: '#000000' }
  ];

  if (!role) {
    return (
      <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <h2 className={`text-5xl md:text-7xl font-black text-slate-900 dark:text-white leading-tight ${!isRtl ? 'font-en' : ''}`}>
              {t.hero_title} <span className="text-emerald-600 dark:text-emerald-400">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 dark:text-slate-400 text-xl max-w-2xl mx-auto">{t.hero_desc}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 dark:hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className={`text-3xl font-black text-slate-900 dark:text-white mb-2 underline decoration-emerald-200 dark:decoration-emerald-900 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_seeker}</h3><p className="text-slate-500 dark:text-slate-400 text-lg">{t.role_seeker_desc}</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 dark:bg-black border-2 border-slate-800 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className={`text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_employer}</h3><p className="text-slate-400 text-lg">{t.role_employer_desc}</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
      <div className="container mx-auto px-4 py-12">
        <div className={`flex items-center justify-between mb-12 max-w-6xl mx-auto no-print`}>
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setActiveCandidate(null);}} className="text-slate-500 dark:text-slate-400 font-bold flex items-center gap-2 hover:text-slate-900 dark:hover:text-white transition-colors">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i> {t.back_to_main}
          </button>
          <div className="bg-slate-900 dark:bg-slate-800 text-white px-6 py-2 rounded-full text-xs font-bold flex items-center gap-3">
             <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
             {role === UserRole.SEEKER ? (isRtl ? 'لوحة المتقدم نشطة' : 'Candidate Hub Active') : (isRtl ? 'بوابة صاحب العمل' : 'Employer Portal')}
          </div>
        </div>

        {role === UserRole.SEEKER && !result && (
          <div className="max-w-4xl mx-auto no-print">
            <CandidateHub onProcess={handleProcessSeeker} loading={loading} />
          </div>
        )}

        {role === UserRole.EMPLOYER && !activeCandidate && (
          <div className="max-w-6xl mx-auto no-print">
             <TalentScout onViewCandidate={handleViewCandidate} onShortlist={toggleShortlist} shortlist={shortlist} />
          </div>
        )}

        {role === UserRole.SEEKER && result && !activated && result.enhancement && (
          <div className="max-w-6xl mx-auto mb-12 no-print">
            <CVComparison 
              originalText={rawInput} 
              report={result.enhancement} 
              suggested={result.suggested_achievements || []}
              onConfirmAchievement={handleConfirmAchievement}
            />
          </div>
        )}

        {result && (
          <div className={`max-w-6xl mx-auto flex flex-col lg:flex-row gap-8 ${!isRtl ? 'lg:flex-row' : ''}`}>
            {/* Design Sidebar - Only for Seekers */}
            {role === UserRole.SEEKER && (
              <aside className="lg:w-80 space-y-6 no-print">
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-xl border border-slate-100 dark:border-slate-800 sticky top-12">
                  <h3 className="text-lg font-black mb-4 flex items-center gap-2 dark:text-white">
                    <i className="fa-solid fa-palette text-emerald-500"></i>
                    {t.design_customize}
                  </h3>

                  <div className="space-y-6">
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.choose_template}</p>
                      <div className="grid grid-cols-2 gap-2">
                        {Object.values(TemplateType).map(v => (
                          <button 
                            key={v}
                            onClick={() => setTemplate(v)}
                            className={`p-2 rounded-xl border-2 text-[10px] font-bold transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400' : 'border-slate-100 dark:border-slate-800 dark:text-slate-500 hover:border-slate-200'}`}
                          >
                            {v}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.theme_color}</p>
                      <div className="flex flex-wrap gap-2">
                        {themeColors.map(c => (
                          <button 
                            key={c.color}
                            onClick={() => setTheme({...theme, primaryColor: c.color})}
                            className={`w-8 h-8 rounded-full border-2 transition-transform ${theme.primaryColor === c.color ? 'scale-125 border-emerald-500 shadow-lg' : 'border-transparent'}`}
                            style={{ backgroundColor: c.color }}
                            title={c.name}
                          />
                        ))}
                      </div>
                    </div>

                    <div>
                       <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.section_order}</p>
                       <div className="space-y-1">
                          {theme.sectionOrder.map((s, i) => (
                            <div key={s} className="flex items-center justify-between p-2 bg-slate-50 dark:bg-slate-800 rounded-lg text-[10px] font-bold text-slate-600 dark:text-slate-300">
                               <span>{s.toUpperCase()}</span>
                               <div className="flex gap-2">
                                  <button onClick={() => {
                                    const newOrder = [...theme.sectionOrder];
                                    if (i > 0) [newOrder[i-1], newOrder[i]] = [newOrder[i], newOrder[i-1]];
                                    setTheme({...theme, sectionOrder: newOrder});
                                  }} className="text-slate-400 hover:text-emerald-500 transition-colors"><i className="fa-solid fa-chevron-up"></i></button>
                               </div>
                            </div>
                          ))}
                       </div>
                    </div>

                    <button 
                      onClick={handleTranslateToggle}
                      disabled={loading}
                      className="w-full py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-xs font-black hover:bg-black dark:hover:bg-emerald-500 transition-all flex items-center justify-center gap-2"
                    >
                      {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-language"></i>}
                      {t.translate_btn}
                    </button>
                  </div>
                </div>
              </aside>
            )}

            <div className="flex-1 space-y-12">
               {/* Watermarked Preview Area */}
               <div className="relative">
                  <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />
               </div>

               {otp && !activated && <div className="no-print"><Paywall role={role} otp={otp} onActivate={handleActivate} lang={uiLang} /></div>}

               {activated && (
                  <div className="space-y-12">
