import React, { useState } from 'react';
import { getKeywordSuggestions } from '../services/geminiService';

interface CandidateHubProps {
  onProcess: (data: string, target: string, ghostMode: boolean) => void;
  loading: boolean;
}

export const CandidateHub: React.FC<CandidateHubProps> = ({ onProcess, loading }) => {
  const [targetJob, setTargetJob] = useState('');
  const [name, setName] = useState('');
  const [exp, setExp] = useState('');
  const [skillsInput, setSkillsInput] = useState('');
  const [ghostMode, setGhostMode] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [suggesting, setSuggesting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  const handleSkillBlur = async () => {
    if (!skillsInput || !targetJob) return;
    setSuggesting(true);
    try {
      const data = await getKeywordSuggestions(skillsInput, targetJob);
      setSuggestions(data);
    } catch (e) {} finally { setSuggesting(false); }
  };

  const addSuggestion = (s: string) => {
    setSkillsInput(prev => prev ? `${prev}, ${s}` : s);
    setSuggestions(prev => prev.filter(x => x !== s));
  };

  const handleUploadClick = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.pdf,.doc,.docx,image/*';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      if (file) {
        setIsUploading(true);
        setTimeout(() => {
          setExp(`[تم استخراج البيانات من الملف: ${file.name}]\n\nالخبرات السابقة:\n- كاتب محتوى في شركة التقنية\n- إداري مكتب في مؤسسة المقاولات\n- خدمة عملاء في مركز الاتصال`);
          setIsUploading(false);
        }, 2000);
      }
    };
    input.click();
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-100 dark:border-slate-800 p-8 space-y-8">
      <div className="flex justify-between items-center bg-slate-50 dark:bg-slate-800 p-6 rounded-2xl border border-slate-100 dark:border-slate-700">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-slate-900 dark:bg-black rounded-xl flex items-center justify-center text-white">
            <i className={`fa-solid ${ghostMode ? 'fa-user-secret' : 'fa-user'}`}></i>
          </div>
          <div>
            <h4 className="font-bold text-slate-900 dark:text-white">وضع التوظيف الصامت (Ghost Mode)</h4>
            <p className="text-xs text-slate-500 dark:text-slate-400">إخفاء هويتك الحقيقية عن شركتك الحالية</p>
          </div>
        </div>
        <button 
          onClick={() => setGhostMode(!ghostMode)}
          className={`w-14 h-8 rounded-full transition-all relative p-1 ${ghostMode ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-600'}`}
        >
          <div className={`w-6 h-6 bg-white rounded-full transition-all absolute top-1 ${ghostMode ? 'left-7' : 'left-1'}`}></div>
        </button>
      </div>

      <div className="bg-emerald-50 dark:bg-emerald-950/30 p-6 rounded-3xl border-2 border-dashed border-emerald-200 dark:border-emerald-900 text-center space-y-3">
        <div className="flex flex-col items-center">
          <div className="w-16 h-16 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-lg mb-4 text-emerald-600 dark:text-emerald-400">
             {isUploading ? <i className="fa-solid fa-spinner fa-spin text-2xl"></i> : <i className="fa-solid fa-file-pdf text-2xl"></i>}
          </div>
          <h3 className="font-bold text-slate-900 dark:text-white">هل لديك سيرة قديمة؟</h3>
          <p className="text-sm text-slate-500 dark:text-slate-400">ارفع ملفك الآن لنقوم بـ "التنقيب العميق" وتحويله فوراً لنظام الـ Bullet Points</p>
        </div>
        <button 
          onClick={handleUploadClick}
          disabled={isUploading}
          className="bg-white dark:bg-slate-800 text-emerald-600 dark:text-emerald-400 font-bold px-8 py-2.5 rounded-xl border border-emerald-200 dark:border-emerald-900 shadow-sm hover:bg-emerald-50 dark:hover:bg-slate-700 transition-all flex items-center gap-2 mx-auto"
        >
          <i className="fa-solid fa-upload"></i>
          {isUploading ? 'جاري قراءة الملف...' : 'رفع سيرة سابقة'}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700 dark:text-slate-300">الاسم الكامل</label>
          <input 
            type="text" 
            className="w-full p-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 dark:text-white" 
            value={name} 
            onChange={e => setName(e.target.value)}
          />
        </div>
        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700 dark:text-slate-300">المسمى الوظيفي المستهدف</label>
          <input 
            type="text" 
            className="w-full p-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 dark:text-white" 
            value={targetJob} 
            onChange={e => setTargetJob(e.target.value)}
          />
        </div>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-bold text-slate-700 dark:text-slate-300">الخبرات العملية (اذكر جهة العمل والمهام)</label>
        <textarea 
          className="w-full p-4 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 h-32 dark:text-white" 
          value={exp} 
          onChange={e => setExp(e.target.value)}
          placeholder="يمكنك الكتابة هنا أو الصق النص مباشرة..."
        />
      </div>

      <div className="space-y-2">
        <div className="flex justify-between items-center">
          <label className="text-sm font-bold text-slate-700 dark:text-slate-300">المهارات التقنية (افصل بينها بفاصلة)</label>
          {suggesting && <i className="fa-solid fa-spinner fa-spin text-emerald-500 text-xs"></i>}
        </div>
        <input 
          type="text" 
          className="w-full p-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 dark:text-white" 
          value={skillsInput} 
          onBlur={handleSkillBlur}
          onChange={e => setSkillsInput(e.target.value)}
          placeholder="مثال: SQL, Project Management, Python"
        />
        {suggestions.length > 0 && (
          <div className="flex flex-wrap gap-2 pt-2">
            <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 w-full mb-1">كلمات مفتاحية مقترحة لرفع الـ ATS:</span>
            {suggestions.map((s, i) => (
              <button 
                key={i} 
                onClick={() => addSuggestion(s)}
                className="text-[10px] bg-emerald-50 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-400 border border-emerald-200 dark:border-emerald-900 px-2 py-1 rounded-full hover:bg-emerald-100 dark:hover:bg-emerald-900 transition-colors"
              >
                + {s}
              </button>
            ))}
          </div>
        )}
      </div>

      <button 
        onClick={() => onProcess(`${name}\n${exp}\nSkills: ${skillsInput}`, targetJob, ghostMode)}
        disabled={loading || !name || !targetJob}
        className="w-full bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-lg flex items-center justify-center gap-3 hover:bg-emerald-700 transition-all disabled:opacity-50"
      >
        {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
        بدء التنقيب العميق والتحسين الذكي
      </button>
    </div>
  );
};

