import { GoogleGenAI, Type } from "@google/genai";
import { ApiResponse, CVData, JobMatchResult, VerificationResult, InterviewAnalysis, CandidateProfile, InterviewQuestion, InterviewReport, ScorecardData, Language } from "../types";

export const suggestFieldContent = async (fieldName: string, currentData: CVData, lang: Language): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are a professional resume writer. Suggest a powerful, metric-driven content for the resume field: "${fieldName}". 
    Target Job: ${currentData.personal_info.target_job}. 
    Candidate Name: ${currentData.personal_info.full_name}.
    Current Language: ${lang === Language.AR ? 'Arabic' : 'English'}.
    Keep it concise and high-impact.`,
  });
  return response.text.trim();
};

export const magicExtractCV = async (base64File: string, lang: Language): Promise<CVData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Simulated OCR/Extraction via Gemini multimodal capability
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        inlineData: {
          mimeType: base64File.split(';')[0].split(':')[1],
          data: base64File.split(',')[1]
        }
      },
      { text: "Extract professional information from this document into a structured CV JSON. Modernize titles and fix formatting. Language: " + (lang === Language.AR ? 'Arabic' : 'English') }
    ],
    config: { responseMimeType: "application/json" }
  });
  const data = JSON.parse(response.text);
  return data.cv || data;
};

export const translateCV = async (cv: CVData, targetLang: Language): Promise<CVData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are a professional recruitment expert. Translate the following CV data to ${targetLang === Language.EN ? 'English' : 'Arabic'}. 
    RULES:
    1. CONTEXTUAL TRANSLATION: Do not use literal translation. Use industry-standard professional terms.
    2. Maintain exact JSON structure.
    Data: ${JSON.stringify(cv)}`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export const verifyCertificate = async (base64Data: string, cvData: CVData): Promise<VerificationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const data = base64Data.split(',')[1];
  const mimeType = base64Data.split(';')[0].split(':')[1];
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { 
      parts: [
        { inlineData: { data, mimeType } }, 
        { text: `Verify if this professional certificate belongs to ${cvData.personal_info.full_name} and aligns with their career goals. Return JSON.` }
      ]
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

