import React, { useState } from 'react';
import { magicExtractCV } from '../services/geminiService';
import { Language, CVData } from '../types';

interface CandidateHubProps {
  onStartFresh: () => void;
  onExtracted: (data: CVData) => void;
  lang: Language;
}

export const CandidateHub: React.FC<CandidateHubProps> = ({ onStartFresh, onExtracted, lang }) => {
  const [loading, setLoading] = useState(false);
  const isRtl = lang === Language.AR;

  const handleMagicExtract = async () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.pdf,.doc,.docx,image/*';
    input.onchange = async (e: any) => {
      const file = e.target.files[0];
      if (file) {
        setLoading(true);
        try {
          const reader = new FileReader();
          reader.onloadend = async () => {
            const base64 = reader.result as string;
            const extracted = await magicExtractCV(base64, lang);
            onExtracted(extracted);
          };
          reader.readAsDataURL(file);
        } catch (e) {
          alert("فشل استخراج البيانات الذكي.");
        } finally {
          setLoading(false);
        }
      }
    };
    input.click();
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in zoom-in duration-500">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-black text-slate-900 dark:text-white">
          {isRtl ? 'كيف ترغب في البدء؟' : 'How would you like to start?'}
        </h2>
        <p className="text-slate-500 dark:text-slate-400 text-lg">
          {isRtl ? 'اختر الطريقة التي تفضلها لبناء مستقبلك المهني' : 'Choose your preferred way to build your career path'}
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Magic Extract Card */}
        <button 
          onClick={handleMagicExtract}
          disabled={loading}
          className="group relative p-10 bg-emerald-600 rounded-[40px] shadow-2xl hover:bg-emerald-700 transition-all text-start overflow-hidden border-4 border-transparent hover:border-emerald-400"
        >
          <div className="relative z-10 space-y-6">
            <div className="w-20 h-20 bg-white/20 rounded-3xl flex items-center justify-center text-white text-4xl group-hover:scale-110 transition-transform">
              {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
            </div>
            <div className="text-white">
              <h3 className="text-3xl font-black mb-2">{isRtl ? 'Magic Extract' : 'Magic Extract'}</h3>
              <p className="text-emerald-100 opacity-80 leading-relaxed">
                {isRtl ? 'ارفع سيرتك القديمة وسيقوم الذكاء الاصطناعي بسحب البيانات وتحديثها فوراً.' : 'Upload your old resume and AI will extract and modernize data instantly.'}
              </p>
            </div>
            <div className="flex items-center gap-2 text-white font-bold text-sm">
              <span>{isRtl ? 'أسرع بـ 10 مرات' : '10x Faster'}</span>
              <i className="fa-solid fa-arrow-left"></i>
            </div>
          </div>
          <div className="absolute -bottom-10 -right-10 w-48 h-48 bg-white/5 blur-3xl rounded-full"></div>
        </button>

