import React, { useState } from 'react';
import { CVData, WizardStep, Language } from '../types';
import { suggestFieldContent } from '../services/geminiService';

interface EditorWizardProps {
  data: CVData;
  onChange: (data: CVData) => void;
  step: WizardStep;
  onNext: () => void;
  onPrev: () => void;
  lang: Language;
}

export const EditorWizard: React.FC<EditorWizardProps> = ({ data, onChange, step, onNext, onPrev, lang }) => {
  const isRtl = lang === Language.AR;
  const [loadingField, setLoadingField] = useState<string | null>(null);

  const handleAIWrite = async (field: string) => {
    setLoadingField(field);
    try {
      const suggestion = await suggestFieldContent(field, data, lang);
      if (field === 'summary') {
        onChange({ ...data, summary: suggestion });
      }
      // Expand for other fields as needed
    } catch (e) {
      alert("AI drafting failed.");
    } finally {
      setLoadingField(null);
    }
  };

  const progress = step === WizardStep.PERSONAL ? 25 : step === WizardStep.EXPERIENCE ? 50 : step === WizardStep.SKILLS ? 75 : 100;

  const renderPersonal = () => (
    <div className="space-y-6 animate-in slide-in-from-left duration-300">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{isRtl ? 'الاسم الكامل' : 'Full Name'}</label>
          <input 
            className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl focus:border-emerald-500 outline-none transition-all dark:text-white"
            value={data.personal_info.full_name}
            onChange={e => onChange({ ...data, personal_info: { ...data.personal_info, full_name: e.target.value } })}
          />
        </div>
        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{isRtl ? 'المسمى الوظيفي المستهدف' : 'Target Job Title'}</label>
          <input 
            className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl focus:border-emerald-500 outline-none transition-all dark:text-white"
            value={data.personal_info.target_job}
            onChange={e => onChange({ ...data, personal_info: { ...data.personal_info, target_job: e.target.value } })}
          />
        </div>
      </div>
      <div className="space-y-2">
        <div className="flex justify-between items-center">
          <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{isRtl ? 'الملخص المهني' : 'Professional Summary'}</label>
          <button 
            onClick={() => handleAIWrite('summary')}
            className="text-xs font-black text-emerald-600 flex items-center gap-1 hover:text-emerald-700 transition-colors"
          >
            {loadingField === 'summary' ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
            {isRtl ? 'اكتب لي بالذكاء' : 'AI Write for me'}
          </button>
        </div>
        <textarea 
          className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl focus:border-emerald-500 outline-none h-32 transition-all dark:text-white"
          value={data.summary}
          onChange={e => onChange({ ...data, summary: e.target.value })}
        />
      </div>
    </div>
  );

  const renderExperience = () => (
    <div className="space-y-6 animate-in slide-in-from-left duration-300">
      {data.experience.map((exp, idx) => (
        <div key={idx} className="p-6 bg-slate-50 dark:bg-slate-800 rounded-3xl border-2 border-slate-100 dark:border-slate-700 space-y-4 relative group">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              placeholder={isRtl ? 'الشركة' : 'Company'}
              className="p-3 bg-white dark:bg-slate-900 border rounded-xl outline-none focus:ring-1 focus:ring-emerald-500 dark:text-white"
              value={exp.company}
              onChange={e => {
                const newExp = [...data.experience];
                newExp[idx].company = e.target.value;
                onChange({ ...data, experience: newExp });
              }}
            />
            <input 
              placeholder={isRtl ? 'المسمى الوظيفي' : 'Job Title'}
              className="p-3 bg-white dark:bg-slate-900 border rounded-xl outline-none focus:ring-1 focus:ring-emerald-500 dark:text-white"
              value={exp.position}
              onChange={e => {
                const newExp = [...data.experience];
                newExp[idx].position = e.target.value;
                onChange({ ...data, experience: newExp });
              }}
            />
          </div>
          <textarea 
            placeholder={isRtl ? 'الإنجازات (واحد في كل سطر)' : 'Achievements (one per line)'}
            className="w-full p-3 bg-white dark:bg-slate-900 border rounded-xl outline-none focus:ring-1 focus:ring-emerald-500 h-24 dark:text-white"
            value={exp.achievements.join('\n')}
            onChange={e => {
              const newExp = [...data.experience];
              newExp[idx].achievements = e.target.value.split('\n');
              onChange({ ...data, experience: newExp });
            }}
          />
          <button 
            onClick={() => {
              const newExp = data.experience.filter((_, i) => i !== idx);
              onChange({ ...data, experience: newExp });
            }}
            className="absolute -top-2 -right-2 w-8 h-8 bg-red-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
          >
            <i className="fa-solid fa-times"></i>
          </button>
        </div>
      ))}
      <button 
        onClick={() => onChange({ ...data, experience: [...data.experience, { company: '', position: '', duration: '', achievements: [] }] })}
        className="w-full py-4 border-2 border-dashed border-emerald-300 dark:border-emerald-800 rounded-3xl text-emerald-600 font-black hover:bg-emerald-50 dark:hover:bg-emerald-950 transition-all flex items-center justify-center gap-2"
      >
        <i className="fa-solid fa-plus"></i>
        {isRtl ? 'إضافة خبرة جديدة' : 'Add New Experience'}
      </button>
    </div>
  );

  const renderSkills = () => (
    <div className="space-y-6 animate-in slide-in-from-left duration-300">
      <div className="space-y-2">
        <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{isRtl ? 'المهارات (افصل بينها بفاصلة)' : 'Skills (separate by comma)'}</label>
        <input 
          className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl focus:border-emerald-500 outline-none transition-all dark:text-white"
          value={data.skills.join(', ')}
          onChange={e => onChange({ ...data, skills: e.target.value.split(',').map(s => s.trim()) })}
        />
      </div>
    </div>
  );

  return (
    <div className="bg-white dark:bg-slate-900 rounded-[40px] shadow-2xl overflow-hidden border border-slate-100 dark:border-slate-800">
      {/* Progress Bar */}
      <div className="h-2 bg-slate-100 dark:bg-slate-800 w-full">
        <div 
          className="h-full bg-emerald-500 transition-all duration-500"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="p-10 space-y-10">
        <div className="flex justify-between items-center">
          <div>
            <h3 className="text-2xl font-black dark:text-white">
              {step === WizardStep.PERSONAL ? (isRtl ? 'البيانات الشخصية' : 'Personal Info') :
               step === WizardStep.EXPERIENCE ? (isRtl ? 'الخبرات العملية' : 'Work Experience') :
               (isRtl ? 'المهارات التقنية' : 'Technical Skills')}
            </h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm">{isRtl ? 'أدخل بياناتك بدقة لتحسين نتيجة الـ ATS' : 'Enter your data accurately to improve ATS score'}</p>
          </div>
          <div className="bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 px-4 py-2 rounded-full font-black text-xs">
            {isRtl ? 'قوة السيرة:' : 'CV Score:'} {data.ats_score}%
          </div>
        </div>

        <div className="min-h-[300px]">
          {step === WizardStep.PERSONAL && renderPersonal()}
          {step === WizardStep.EXPERIENCE && renderExperience()}
          {step === WizardStep.SKILLS && renderSkills()}
        </div>

        <div className="flex justify-between items-center pt-8 border-t border-slate-100 dark:border-slate-800">
          <button 
            onClick={onPrev}
            className="px-8 py-3 text-slate-500 dark:text-slate-400 font-bold hover:text-slate-900 transition-colors flex items-center gap-2"
          >
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i>
            {isRtl ? 'السابق' : 'Previous'}
          </button>
          <button 
            onClick={onNext}
            className="bg-emerald-600 text-white font-black px-12 py-4 rounded-2xl shadow-xl hover:bg-emerald-700 transition-all flex items-center gap-2"
          >
            {isRtl ? 'التالي' : 'Next'}
            <i className={`fa-solid ${isRtl ? 'fa-arrow-left' : 'fa-arrow-right'}`}></i>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { SocialBrand } from './components/SocialBrand';
import { SalaryNegotiator } from './components/SalaryNegotiator';
import { CredentialVerifier } from './components/CredentialVerifier';
import { CareerSimulator } from './components/CareerSimulator';
import { PortfolioBuilder } from './components/PortfolioBuilder';
import { VirtualCoach } from './components/VirtualCoach';
import { CandidateHub } from './components/CandidateHub';
import { EditorWizard } from './components/EditorWizard';
import { TalentScout } from './components/TalentScout';
import { AIScreening } from './components/AIScreening';
import { Scorecard } from './components/Scorecard';
import { SmartScheduler } from './components/SmartScheduler';
import { CVComparison } from './components/CVComparison';
import { processCVInput, generateInterviewQuestions, generateScorecard, translateCV } from './services/geminiService';
import { UserRole, ApiResponse, CVData, CandidateProfile, InterviewQuestion, InterviewReport, ScorecardData, TemplateType, ThemeConfig, Language, ThemeMode, WizardStep } from './types';
import { TRANSLATIONS } from './constants';

const initialCV: CVData = {
  personal_info: { full_name: '', email: '', phone: '', location: '', target_job: '' },
  summary: '',
  experience: [],
  education: [],
  skills: [],
  ats_score: 15
};

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [cvData, setCVData] = useState<CVData>(initialCV);
  const [wizardStep, setWizardStep] = useState<WizardStep>(WizardStep.HUB);
  const [userLocation, setUserLocation] = useState('السعودية');
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  // Theme & Language State
  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [themeMode, setThemeMode] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('sirati_theme');
    if (saved) return saved as ThemeMode;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? ThemeMode.DARK : ThemeMode.LIGHT;
  });
  const [template, setTemplate] = useState<TemplateType>(TemplateType.PROFESSIONAL);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#059669',
    sectionOrder: ['summary', 'experience', 'education', 'skills']
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  const toggleTheme = () => {
    setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);
  };

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const handleStartFresh = () => setWizardStep(WizardStep.PERSONAL);

  const handleExtracted = (data: CVData) => {
    setCVData({ ...data, ats_score: 75 });
    setWizardStep(WizardStep.PERSONAL);
  };

  const handleProcessFinal = async () => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(JSON.stringify(cvData), cvData.personal_info.target_job, UserRole.SEEKER, userLocation, uiLang);
      setResult(apiResult);
      setWizardStep(WizardStep.PREVIEW);
    } catch (error) {
      alert(isRtl ? "حدث خطأ أثناء معالجة البيانات." : "Error processing data.");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    if (!result) {
      setUiLang(prev => prev === Language.AR ? Language.EN : Language.AR);
      return;
    }
    setLoading(true);
    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert("Smart translation failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert(isRtl ? "كود التفعيل غير صحيح" : "Invalid activation code");
  };

  const themeColors = [
    { name: 'Emerald', color: '#059669' },
    { name: 'Royal', color: '#1d4ed8' },
    { name: 'Midnight', color: '#1e293b' },
    { name: 'Gold', color: '#d97706' },
    { name: 'Classic', color: '#000000' }
  ];

  if (!role) {
    return (
      <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <h2 className={`text-5xl md:text-7xl font-black text-slate-900 dark:text-white leading-tight ${!isRtl ? 'font-en' : ''}`}>
              {t.hero_title} <span className="text-emerald-600 dark:text-emerald-400">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 dark:text-slate-400 text-xl max-w-2xl mx-auto">{t.hero_desc}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 dark:hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className={`text-3xl font-black text-slate-900 dark:text-white mb-2 underline decoration-emerald-200 dark:decoration-emerald-900 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_seeker}</h3><p className="text-slate-500 dark:text-slate-400 text-lg">{t.role_seeker_desc}</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 dark:bg-black border-2 border-slate-800 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className={`text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_employer}</h3><p className="text-slate-400 text-lg">{t.role_employer_desc}</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
      <div className="container mx-auto px-4 py-12">
        <div className={`flex items-center justify-between mb-12 max-w-6xl mx-auto no-print`}>
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setWizardStep(WizardStep.HUB);}} className="text-slate-500 dark:text-slate-400 font-bold flex items-center gap-2 hover:text-slate-900 dark:hover:text-white transition-colors">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i> {t.back_to_main}
          </button>
          {role === UserRole.SEEKER && (
            <div className="flex items-center gap-4 bg-slate-100 dark:bg-slate-800 p-2 rounded-2xl">
              <span className={`w-3 h-3 rounded-full ${cvData.ats_score > 70 ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`}></span>
              <span className="text-xs font-black dark:text-white">ATS: {cvData.ats_score}%</span>
            </div>
          )}
        </div>

        {role === UserRole.SEEKER && wizardStep === WizardStep.HUB && (
          <CandidateHub onStartFresh={handleStartFresh} onExtracted={handleExtracted} lang={uiLang} />
        )}

        {role === UserRole.SEEKER && wizardStep !== WizardStep.HUB && wizardStep !== WizardStep.PREVIEW && (
          <div className="max-w-4xl mx-auto grid grid-cols-1 gap-12">
            <EditorWizard 
              data={cvData} 
              onChange={setCVData} 
              step={wizardStep} 
              lang={uiLang}
              onNext={() => {
                if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.EXPERIENCE);
                else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.SKILLS);
                else handleProcessFinal();
              }}
              onPrev={() => {
                if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.HUB);
                else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.PERSONAL);
                else setWizardStep(WizardStep.EXPERIENCE);
              }}
            />
          </div>
        )}

        {role === UserRole.EMPLOYER && !activeCandidate && (
          <TalentScout onViewCandidate={c => setActiveCandidate(c)} onShortlist={c => setShortlist([...shortlist, c])} shortlist={shortlist} />
        )}

        {result && (
          <div className="max-w-6xl mx-auto flex flex-col lg:flex-row gap-8">
            <aside className="lg:w-80 space-y-6 no-print">
              <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-xl border border-slate-100 dark:border-slate-800 sticky top-12">
                <h3 className="text-lg font-black mb-4 flex items-center gap-2 dark:text-white">
                  <i className="fa-solid fa-palette text-emerald-500"></i>
                  {t.design_customize}
                </h3>
                <div className="space-y-6">
                  <div>
                    <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.choose_template}</p>
                    <div className="grid grid-cols-2 gap-2">
                      {Object.values(TemplateType).map(v => (
                        <button key={v} onClick={() => setTemplate(v)} className={`p-2 rounded-xl border-2 text-[10px] font-bold transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700' : 'border-slate-100 dark:border-slate-800'}`}>{v}</button>
                      ))}
                    </div>
                  </div>
                  <div>
                    <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.theme_color}</p>
                    <div className="flex flex-wrap gap-2">
                      {themeColors.map(c => (
                        <button key={c.color} onClick={() => setTheme({...theme, primaryColor: c.color})} className={`w-8 h-8 rounded-full border-2 transition-transform ${theme.primaryColor === c.color ? 'scale-125 border-emerald-500 shadow-lg' : 'border-transparent'}`} style={{ backgroundColor: c.color }} />
                      ))}
                    </div>
                  </div>
                  <button onClick={handleTranslateToggle} disabled={loading} className="w-full py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-xs font-black flex items-center justify-center gap-2">
                    {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-language"></i>}
                    {t.translate_btn}
                  </button>
                </div>
              </div>
            </aside>

            <div className="flex-1 space-y-12">
              <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />
              {otp && !activated && <Paywall role={role} otp={otp} onActivate={handleActivate} lang={uiLang} />}
              {activated && (
                <div className="space-y-12">
                  <div className="bg-emerald-600 dark:bg-black text-white p-8 rounded-[40px] shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6 no-print">
                    <div className="flex items-center gap-4">
                      <i className="fa-solid fa-crown text-4xl text-yellow-300"></i>
                      <div><h4 className="text-xl font-black">{t.verified_badge}</h4><p className="opacity-80 text-sm">{t.verified_desc}</p></div>
                    </div>
                    <button onClick={() => window.print()} className="bg-white text-emerald-600 px-8 py-4 rounded-2xl font-black shadow-lg flex items-center gap-2">
                      <i className="fa-solid fa-download"></i> {t.export_pdf}
                    </button>
                  </div>
                  <div className="grid grid-cols-1 gap-12 no-print">
                    <CareerPath data={result.career_path} />
                    <CareerRadar data={result.market_insights} />
                    <SmartHelper data={result.smart_helper} />
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {loading && wizardStep !== WizardStep.HUB && (
        <div className="fixed bottom-10 left-10 z-[100] animate-bounce">
           <div className="bg-emerald-600 text-white px-6 py-3 rounded-full shadow-2xl font-black text-sm flex items-center gap-3">
              <i className="fa-solid fa-spinner fa-spin"></i>
              {isRtl ? 'جاري التحسين الذكي...' : 'AI Optimizing...'}
           </div>
        </div>
      )}
    </Layout>
  );
};

