    contents: { 
      parts: [
        { inlineData: { data: base64Data.split(',')[1], mimeType: base64Data.split(';')[0].split(':')[1] } }, 
        { text: `Verify this certificate for ${cvData.personal_info.full_name}. Return JSON.` }
