                        ))}
                      </div>
                    </div>
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.theme_color}</p>
                      <div className="flex flex-wrap gap-2">
                        {themeColors.map(c => (
                          <button key={c.color} onClick={() => setTheme({...theme, primaryColor: c.color})} className={`w-8 h-8 rounded-full border-2 transition-all ${theme.primaryColor === c.color ? 'scale-125 border-emerald-500 ring-2 ring-emerald-500/20' : 'border-transparent'}`} style={{ backgroundColor: c.color }} />
                        ))}
                      </div>
                    </div>
                    <div className="pt-4 space-y-2">
                       <button onClick={handleTranslateToggle} disabled={loading} className="w-full py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-xs font-black flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/10 transition-all hover:scale-[1.02] active:scale-[0.98]">
                        {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-language"></i>}
                        {t.translate_btn}
                      </button>
                      <button 
                        onClick={() => setWizardStep(WizardStep.PERSONAL)}
                        className="w-full py-3 bg-white dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 text-slate-600 dark:text-slate-300 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 hover:bg-slate-50 transition-all"
                      >
                        <i className="fa-solid fa-pen-to-square"></i>
                        {isRtl ? 'تعديل البيانات' : 'Edit Data'}
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </aside>

            <div className="flex-1 space-y-12 pb-24">
              <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />

              {otp && !activated && (
                <div className="no-print space-y-8">
                  <Paywall role={role} otp={otp} onActivate={handleActivate} lang={uiLang} />
                  <div className="flex justify-center">
                    <button 
                      onClick={handleOpenWhatsapp}
                      className="bg-[#25D366] text-white px-10 py-5 rounded-[24px] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3"
                    >
                      <i className="fa-brands fa-whatsapp text-2xl"></i>
                      {isRtl ? 'تفعيل الآن عبر واتساب' : 'Activate via WhatsApp'}
                    </button>
                  </div>
                </div>
              )}

              {activated && (
                <div className="space-y-12 animate-in fade-in zoom-in duration-500">
                  <div className="bg-emerald-600 dark:bg-black text-white p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row items-center justify-between gap-8 no-print border border-white/10">
                    <div className="flex items-center gap-6">
                      <div className="w-20 h-20 bg-yellow-400 text-black rounded-3xl flex items-center justify-center text-4xl shadow-xl shadow-yellow-400/20">
                        <i className="fa-solid fa-crown"></i>
                      </div>
                      <div>
                        <h4 className="text-2xl font-black">{t.verified_badge}</h4>
                        <p className="opacity-80 text-sm">{t.verified_desc}</p>
                      </div>
                    </div>
                    <button onClick={() => window.print()} className="bg-white text-emerald-600 dark:text-black dark:bg-emerald-400 px-12 py-5 rounded-[24px] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
                      <i className="fa-solid fa-file-pdf text-xl"></i>
                      {t.export_pdf}
                    </button>
                  </div>
                  <div className="grid grid-cols-1 gap-12 no-print">
                    <CareerPath data={result.career_path} />
                    <CareerRadar data={result.market_insights} />
                    <SmartHelper data={result.smart_helper} />
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {loading && wizardStep !== WizardStep.HUB && (
        <div className="fixed bottom-10 left-10 z-[100] animate-bounce no-print">
           <div className="bg-emerald-600 text-white px-8 py-4 rounded-full shadow-2xl font-black text-xs flex items-center gap-3 border-2 border-white/20">
              <i className="fa-solid fa-spinner fa-spin"></i>
              {isRtl ? 'جاري التحليل والمطابقة الذكية...' : 'AI Analysis in Progress...'}
           </div>
        </div>
      )}
    </Layout>
  );
};

