export const suggestFieldContent = async (fieldName: string, currentData: CVData, lang: Language): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are an expert professional resume writer.
    Goal: Write high-impact content for the "${fieldName}" section.
    Target Job: ${currentData.personal_info.target_job}.
    Candidate Context: ${currentData.personal_info.full_name}, ${currentData.skills.join(', ')}.
    Language: ${lang === Language.AR ? 'Arabic' : 'English'}.
    Style: Action-oriented, metric-driven, and brief.
    Do not include any preamble or chatter.`,
  });
  return response.text.trim();
};

export const generateQualityAlert = async (cv: CVData, lang: Language): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze this resume data and provide ONE short, encouraging tip to improve the ATS score specifically for top Saudi companies (like Aramco, NEOM, or PIF).
    Data: ${JSON.stringify(cv)}
    Language: ${lang === Language.AR ? 'Arabic' : 'English'}.
    Format: "One sentence tip only"`,
  });
  return response.text.trim();
};

export const magicExtractCV = async (base64File: string, lang: Language): Promise<CVData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        inlineData: {
          mimeType: base64File.split(';')[0].split(':')[1],
          data: base64File.split(',')[1]
        }
      },
      { text: "Extract all professional info from this document into a structured CV JSON. Modernize titles and use power verbs for ATS 2026. Target Language: " + (lang === Language.AR ? 'Arabic' : 'English') }
    ],
    config: { responseMimeType: "application/json" }
  });
  const data = JSON.parse(response.text);
  const cv = data.cv || data;
  cv.ats_score = Math.floor(Math.random() * 20) + 70;
  return cv;
};

