    contents: `Professional recruitment translation of the following CV to ${targetLang === Language.EN ? 'English' : 'Arabic'}.
    Ensure direction and LTR/RTL rules are respected in descriptions.
    Data: ${JSON.stringify(cv)}`,
    config: { responseMimeType: "application/json" }
  });
