import React, { useState } from 'react';
import { SearchFilters, CandidateProfile, Language } from '../types';
import { generateMockCandidates } from '../services/geminiService';
import { TRANSLATIONS } from '../constants';

interface TalentScoutProps {
  onViewCandidate: (c: CandidateProfile) => void;
  onShortlist: (c: CandidateProfile) => void;
  shortlist: CandidateProfile[];
  lang: Language;
}

export const TalentScout: React.FC<TalentScoutProps> = ({ onViewCandidate, onShortlist, shortlist, lang }) => {
  const t = lang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = lang === Language.AR;
  const [filters, setFilters] = useState<SearchFilters>({ city: '', experience_years: '', skills: '', language: '', expected_salary: '' });
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<CandidateProfile[]>([]);

  const handleSearch = async () => {
    setLoading(true);
    try {
      const data = await generateMockCandidates(filters);
      setResults(data);
    } catch (e) {
      alert("Search failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-700">
      <div className="bg-slate-900 p-10 rounded-[40px] shadow-2xl border border-slate-800 relative overflow-hidden">
