        <h3 className="text-2xl font-black text-white mb-8 flex items-center gap-3 relative z-10">
          <i className="fa-solid fa-radar text-emerald-400"></i>
          {t.employer_search_title}
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-5 gap-4 relative z-10">
          <div className="space-y-1">
             <label className="text-[10px] font-black text-slate-500 uppercase px-2">{t.employer_filters_city}</label>
             <input className="w-full bg-slate-800 border border-slate-700 p-3 rounded-2xl text-white outline-none focus:ring-1 focus:ring-emerald-500 text-sm" placeholder="..." value={filters.city} onChange={e => setFilters({...filters, city: e.target.value})} />
          </div>
          <div className="space-y-1">
             <label className="text-[10px] font-black text-slate-500 uppercase px-2">{t.employer_filters_salary}</label>
             <input className="w-full bg-slate-800 border border-slate-700 p-3 rounded-2xl text-white outline-none focus:ring-1 focus:ring-emerald-500 text-sm" placeholder="..." value={filters.expected_salary} onChange={e => setFilters({...filters, expected_salary: e.target.value})} />
          </div>
          <div className="md:col-span-2 space-y-1">
             <label className="text-[10px] font-black text-slate-500 uppercase px-2">{t.employer_filters_skills}</label>
             <input className="w-full bg-slate-800 border border-slate-700 p-3 rounded-2xl text-white outline-none focus:ring-1 focus:ring-emerald-500 text-sm" placeholder="..." value={filters.skills} onChange={e => setFilters({...filters, skills: e.target.value})} />
          </div>
          <div className="pt-5">
             <button onClick={handleSearch} disabled={loading} className="w-full h-12 bg-emerald-600 text-white font-black rounded-2xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-2 shadow-xl shadow-emerald-600/20">
               {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-bolt"></i>}
               {isRtl ? 'فرز عصبي' : 'Neural Filter'}
             </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {results.map(candidate => (
          <div key={candidate.id} className="bg-white dark:bg-slate-900 rounded-[40px] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden group hover:border-emerald-500 transition-all relative">
            <div className="bg-slate-50 dark:bg-slate-800/50 p-8 border-b border-slate-100 dark:border-slate-800">
               <div className="flex justify-between items-start mb-4">
                  <div>
                    <h4 className="font-black text-slate-900 dark:text-white text-xl">
                      {candidate.is_ghost_mode ? (isRtl ? 'مرشح مجهول (Ghost)' : 'Ghost Candidate') : candidate.personal_info.full_name}
                    </h4>
                    <p className="text-emerald-600 font-bold text-sm">{candidate.personal_info.target_job}</p>
                  </div>
                  <div className="bg-emerald-50 dark:bg-emerald-950 text-emerald-700 dark:text-emerald-400 px-4 py-1 rounded-full text-[10px] font-black border border-emerald-100 dark:border-emerald-900">
                    {candidate.ai_fit_score}% {t.candidate_card_fit}
                  </div>
               </div>
            </div>

            <div className="p-8 space-y-6">
              <div className="space-y-3">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t.candidate_card_achievements}</p>
                 <ul className="space-y-2">
                   {candidate.top_achievements.map((ach, i) => (
                     <li key={i} className="text-xs text-slate-700 dark:text-slate-300 flex items-start gap-3 bg-slate-50 dark:bg-slate-800 p-3 rounded-2xl border border-slate-100 dark:border-slate-700">
                        <i className="fa-solid fa-check-circle text-emerald-500 mt-0.5"></i>
                        {ach}
                     </li>
                   ))}
                 </ul>
              </div>

              <div className="p-4 bg-indigo-50 dark:bg-indigo-950/30 rounded-3xl border border-indigo-100 dark:border-indigo-900">
                 <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">{t.candidate_card_personality}</p>
                 <p className="text-xs text-indigo-700 dark:text-indigo-300 italic">"{candidate.personality_eval}"</p>
              </div>

              <div className="flex justify-between items-center text-xs font-bold pt-2">
                 <span className="text-slate-400 uppercase tracking-tighter">{isRtl ? 'الراتب المتوقع:' : 'Expected Salary:'}</span>
                 <span className="text-slate-900 dark:text-white font-black">{candidate.expected_salary}</span>
              </div>

              <div className="grid grid-cols-2 gap-3 pt-4">
                <button onClick={() => onViewCandidate(candidate)} className="bg-slate-900 dark:bg-slate-800 text-white py-3 rounded-2xl text-xs font-black hover:scale-[1.02] transition-all shadow-xl">{isRtl ? 'عرض الذكاء' : 'View Intelligence'}</button>
                <button onClick={() => onShortlist(candidate)} className={`py-3 rounded-2xl text-xs font-black transition-all border ${shortlist.some(s => s.id === candidate.id) ? 'bg-amber-50 dark:bg-amber-950 border-amber-500 text-amber-600' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400'}`}>
                  {shortlist.some(s => s.id === candidate.id) ? (isRtl ? 'في المفضلة' : 'Shortlisted') : (isRtl ? 'حفظ' : 'Save')}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {results.length === 0 && !loading && (
        <div className="py-20 text-center space-y-4">
           <div className="w-20 h-20 bg-slate-100 dark:bg-slate-900 rounded-full flex items-center justify-center mx-auto text-slate-300">
              <i className="fa-solid fa-inbox text-3xl"></i>
           </div>
           <p className="text-slate-500 dark:text-slate-400 font-bold">{isRtl ? 'ابدأ البحث لاكتشاف أفضل الكفاءات المتوافقة مع وظيفتك' : 'Start search to discover the best talents matching your job'}</p>
        </div>
      )}
    </div>
  );
};

