    primaryColor: '#059669',
    sectionOrder: ['summary', 'experience', 'education', 'skills'],
    fontSize: 'base'
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  const toggleTheme = () => {
    setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);
  };

  const generateOtp = (role: UserRole) => {
    const prefix = role === UserRole.SEEKER ? 'S-' : 'B-';
    const num = Math.floor(1000 + Math.random() * 9000);
    return `${prefix}${num}`;
  };

  const calculateScore = (data: CVData) => {
    let score = 15;
    if (data.personal_info.full_name) score += 5;
    if (data.personal_info.target_job) score += 10;
    if (data.summary.length > 50) score += 15;
    if (data.experience.length > 0) score += 25;
    if (data.skills.length > 3) score += 20;
    if (data.education.length > 0) score += 10;
    return Math.min(score, 100);
  };

  const updateCVData = async (newData: CVData) => {
    const score = calculateScore(newData);
    const updated = { ...newData, ats_score: score };

    if (Math.abs(score - cvData.ats_score) > 10) {
      const alert = await generateQualityAlert(updated, uiLang);
      updated.quality_alert = alert;
    }

    setCVData(updated);
  };

  const handleStartFresh = () => setWizardStep(WizardStep.PERSONAL);

  const handleExtracted = (data: CVData) => {
    setCVData(data);
    setWizardStep(WizardStep.PERSONAL);
  };

  const handleProcessFinal = async () => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(JSON.stringify(cvData), cvData.personal_info.target_job, UserRole.SEEKER, userLocation, uiLang);
      setResult(apiResult);
      setWizardStep(WizardStep.PREVIEW);
    } catch (error) {
      alert(isRtl ? "حدث خطأ أثناء معالجة البيانات." : "Error processing data.");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    if (!result) {
      setUiLang(targetLang);
      return;
    }
    setLoading(true);
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert("Smart translation failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert(isRtl ? "كود التفعيل غير صحيح" : "Invalid activation code");
  };

  const handleOpenWhatsapp = () => {
    const text = isRtl 
      ? `مرحباً أستاذ فيصل السني، أرغب في تفعيل سيرتي الاحترافية. رمز المعالجة هو: ${otp}`
      : `Hello Faisal Al-Sunni, I want to activate my resume. Processing code: ${otp}`;
    window.open(`https://wa.me/${PAYMENT_INFO.whatsapp}?text=${encodeURIComponent(text)}`);
  };

  const handleViewCandidate = (candidate: CandidateProfile) => {
    setActiveCandidate(candidate);
    setOtp(generateOtp(UserRole.EMPLOYER));
    // For employers, we wrap the candidate data in the ApiResponse structure to use the preview
    setResult({
      cv: candidate as any,
      career_path: {} as any,
      smart_helper: {} as any,
      market_insights: {} as any,
      social_brand: {} as any,
      salary_negotiation: {} as any,
      timeline: {} as any,
      portfolio: {} as any,
      market_pulse: {} as any
    });
  };

  const themeColors = [
    { name: 'Emerald', color: '#059669' },
    { name: 'Royal', color: '#1d4ed8' },
    { name: 'Midnight', color: '#1e293b' },
    { name: 'Gold', color: '#d97706' },
    { name: 'Classic', color: '#000000' }
  ];

  if (!role) {
    return (
      <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <h2 className={`text-5xl md:text-7xl font-black text-slate-900 dark:text-white leading-tight ${!isRtl ? 'font-en' : ''}`}>
              {t.hero_title} <span className="text-emerald-600 dark:text-emerald-400">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 dark:text-slate-400 text-xl max-w-2xl mx-auto">{t.hero_desc}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 dark:hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className={`text-3xl font-black text-slate-900 dark:text-white mb-2 underline decoration-emerald-200 dark:decoration-emerald-900 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_seeker}</h3><p className="text-slate-500 dark:text-slate-400 text-lg">{t.role_seeker_desc}</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 dark:bg-black border-2 border-slate-800 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className={`text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4 ${!isRtl ? 'font-en' : ''}`}>{t.role_employer}</h3><p className="text-slate-400 text-lg">{t.role_employer_desc}</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
      <div className="container mx-auto px-4 py-12">
        <div className={`flex items-center justify-between mb-12 max-w-6xl mx-auto no-print`}>
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setWizardStep(WizardStep.HUB); setActiveCandidate(null);}} className="text-slate-500 dark:text-slate-400 font-bold flex items-center gap-2 hover:text-slate-900 dark:hover:text-white transition-colors">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i> {t.back_to_main}
          </button>

          {role === UserRole.SEEKER && wizardStep !== WizardStep.HUB && (
            <div className="flex items-center gap-6">
              {cvData.quality_alert && (
                <div className="hidden lg:flex items-center gap-2 bg-amber-50 dark:bg-amber-950/30 text-amber-600 dark:text-amber-400 px-4 py-2 rounded-2xl border border-amber-100 dark:border-amber-900 text-[10px] font-black animate-pulse">
                   <i className="fa-solid fa-lightbulb"></i>
                   {cvData.quality_alert}
                </div>
              )}
              <div className="flex items-center gap-4 bg-slate-900 dark:bg-slate-800 p-2 pl-4 rounded-full border border-white/10 shadow-xl">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-xs ${cvData.ats_score > 75 ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'}`}>
                  {cvData.ats_score}%
                </div>
                <div className="flex flex-col">
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none">ATS Score</span>
                  <div className="h-1 w-20 bg-white/10 rounded-full mt-1 overflow-hidden">
                    <div className="h-full bg-emerald-500" style={{ width: `${cvData.ats_score}%` }}></div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {role === UserRole.SEEKER && wizardStep === WizardStep.HUB && (
          <CandidateHub onStartFresh={handleStartFresh} onExtracted={handleExtracted} lang={uiLang} />
        )}

        {role === UserRole.SEEKER && wizardStep !== WizardStep.HUB && wizardStep !== WizardStep.PREVIEW && (
          <div className="max-w-4xl mx-auto grid grid-cols-1 gap-12">
            <EditorWizard 
              data={cvData} 
              onChange={updateCVData} 
              step={wizardStep} 
              lang={uiLang}
              onNext={() => {
                if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.EXPERIENCE);
                else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.EDUCATION);
                else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.SKILLS);
                else handleProcessFinal();
              }}
              onPrev={() => {
                if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.HUB);
                else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.PERSONAL);
                else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.EXPERIENCE);
                else setWizardStep(WizardStep.EDUCATION);
              }}
            />
          </div>
        )}

        {role === UserRole.EMPLOYER && !result && (
          <TalentScout onViewCandidate={handleViewCandidate} onShortlist={c => setShortlist([...shortlist, c])} shortlist={shortlist} lang={uiLang} />
        )}

        {result && (
          <div className="max-w-6xl mx-auto flex flex-col lg:flex-row gap-8 animate-in fade-in duration-500">
            <aside className="lg:w-80 space-y-6 no-print">
              <div className="bg-white dark:bg-slate-900 p-8 rounded-[40px] shadow-2xl border border-slate-100 dark:border-slate-800 sticky top-12 space-y-8">
                <div>
                  <h3 className="text-lg font-black mb-4 flex items-center gap-2 dark:text-white">
                    <i className="fa-solid fa-swatchbook text-emerald-500"></i>
                    {t.design_customize}
                  </h3>
                  <div className="space-y-6">
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.choose_template}</p>
                      <div className="grid grid-cols-2 gap-2">
                        {Object.values(TemplateType).map(v => (
                          <button key={v} onClick={() => setTemplate(v)} className={`p-2 rounded-xl border-2 text-[9px] font-bold transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-950 text-emerald-700' : 'border-slate-50 dark:border-slate-800 text-slate-400'}`}>{v}</button>
                        ))}
                      </div>
                    </div>
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 mb-3">{t.theme_color}</p>
                      <div className="flex flex-wrap gap-2">
                        {themeColors.map(c => (
                          <button key={c.color} onClick={() => setTheme({...theme, primaryColor: c.color})} className={`w-8 h-8 rounded-full border-2 transition-all ${theme.primaryColor === c.color ? 'scale-125 border-emerald-500 ring-2 ring-emerald-500/20' : 'border-transparent'}`} style={{ backgroundColor: c.color }} />
                        ))}
                      </div>
                    </div>
                    <div className="pt-4 space-y-2">
                       <button onClick={handleTranslateToggle} disabled={loading} className="w-full py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-xs font-black flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/10 transition-all hover:scale-[1.02] active:scale-[0.98]">
                        {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-language"></i>}
                        {t.translate_btn}
                      </button>
                      {role === UserRole.SEEKER && (
                        <button 
                          onClick={() => setWizardStep(WizardStep.PERSONAL)}
                          className="w-full py-3 bg-white dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 text-slate-600 dark:text-slate-300 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 hover:bg-slate-50 transition-all"
                        >
                          <i className="fa-solid fa-pen-to-square"></i>
                          {isRtl ? 'تعديل البيانات' : 'Edit Data'}
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </aside>

            <div className="flex-1 space-y-12 pb-24">
              <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />

              {otp && !activated && (
                <div className="no-print space-y-8">
                  <Paywall role={role} otp={otp} onActivate={handleActivate} lang={uiLang} />
                  <div className="flex justify-center">
                    <button 
                      onClick={handleOpenWhatsapp}
                      className="bg-[#25D366] text-white px-10 py-5 rounded-[24px] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3"
                    >
                      <i className="fa-brands fa-whatsapp text-2xl"></i>
                      {isRtl ? 'تفعيل الآن عبر واتساب' : 'Activate via WhatsApp'}
                    </button>
                  </div>
                </div>
              )}

              {activated && (
                <div className="space-y-12 animate-in fade-in zoom-in duration-500">
                  <div className="bg-emerald-600 dark:bg-black text-white p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row items-center justify-between gap-8 no-print border border-white/10">
                    <div className="flex items-center gap-6">
                      <div className="w-20 h-20 bg-yellow-400 text-black rounded-3xl flex items-center justify-center text-4xl shadow-xl shadow-yellow-400/20">
                        <i className="fa-solid fa-crown"></i>
                      </div>
                      <div>
                        <h4 className="text-2xl font-black">{t.verified_badge}</h4>
                        <p className="opacity-80 text-sm">{t.verified_desc}</p>
                      </div>
                    </div>
                    <button onClick={() => window.print()} className="bg-white text-emerald-600 dark:text-black dark:bg-emerald-400 px-12 py-5 rounded-[24px] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
                      <i className="fa-solid fa-file-pdf text-xl"></i>
                      {t.export_pdf}
                    </button>
                  </div>
                  {role === UserRole.SEEKER && (
                    <div className="grid grid-cols-1 gap-12 no-print">
                      <CareerPath data={result.career_path} />
                      <CareerRadar data={result.market_insights} />
                      <SmartHelper data={result.smart_helper} />
                    </div>
                  )}
                  {role === UserRole.EMPLOYER && activeCandidate && (
                    <div className="space-y-12 no-print">
                       <Scorecard data={{
                         ats_score: activeCandidate.ats_score,
                         interview_score: 85,
                         reliability_score: 95,
                         recommendation: 'HIRE',
                         summary_text: activeCandidate.personality_eval || ''
                       }} />
                       <SmartScheduler candidateName={activeCandidate.personal_info.full_name} onSchedule={(d) => alert(`Scheduled for ${d}`)} />
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {loading && wizardStep !== WizardStep.HUB && (
        <div className="fixed bottom-10 left-10 z-[100] animate-bounce no-print">
           <div className="bg-emerald-600 text-white px-8 py-4 rounded-full shadow-2xl font-black text-xs flex items-center gap-3 border-2 border-white/20">
              <i className="fa-solid fa-spinner fa-spin"></i>
              {isRtl ? 'جاري التحليل والمطابقة الذكية...' : 'AI Analysis in Progress...'}
           </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

