import React, { useState } from 'react';
import { magicExtractCV } from '../services/geminiService';
import { Language, CVData } from '../types';

interface CandidateHubProps {
  onStartFresh: () => void;
  onStartChat: () => void;
  onExtracted: (data: CVData) => void;
  lang: Language;
}

export const CandidateHub: React.FC<CandidateHubProps> = ({ onStartFresh, onStartChat, onExtracted, lang }) => {
  const [loading, setLoading] = useState(false);
  const isRtl = lang === Language.AR;

  const handleMagicExtract = async () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.pdf,.doc,.docx,image/*';
    input.onchange = async (e: any) => {
      const file = e.target.files[0];
      if (file) {
        setLoading(true);
        try {
          const reader = new FileReader();
          reader.onloadend = async () => {
            const base64 = reader.result as string;
            const extracted = await magicExtractCV(base64, lang);
            onExtracted(extracted);
          };
          reader.readAsDataURL(file);
        } catch (e) {
          alert("Magic Extraction failed.");
        } finally {
          setLoading(false);
        }
      }
    };
    input.click();
  };

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-in fade-in zoom-in duration-500">
      <div className="text-center space-y-4">
        <h2 className="text-5xl font-black text-slate-900 dark:text-white">
          {isRtl ? 'كيف ترغب في بناء مستقبلك؟' : 'How do you want to build your future?'}
        </h2>
        <p className="text-slate-500 dark:text-slate-400 text-xl">
          {isRtl ? 'اختر الطريقة الأكثر ملاءمة لك للوصول للعالمية' : 'Choose the most convenient way to reach global standards'}
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {/* Magic Extract */}
        <button 
          onClick={handleMagicExtract}
          disabled={loading}
          className="group relative p-10 bg-emerald-600 rounded-[40px] shadow-2xl hover:bg-emerald-700 transition-all text-start overflow-hidden border-4 border-transparent hover:border-emerald-400"
        >
          <div className="relative z-10 space-y-6">
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center text-white text-3xl group-hover:scale-110 transition-transform">
              {loading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
            </div>
            <div className="text-white">
              <h3 className="text-2xl font-black mb-2">{isRtl ? 'Smart Reconstruct' : 'Smart Reconstruct'}</h3>
              <p className="text-emerald-100 text-sm leading-relaxed">
                {isRtl ? 'رفع ملف PDF قديم وإعادة هيكلته فوراً بمعايير ATS 2026.' : 'Upload old PDF and restructure it instantly for ATS 2026 standards.'}
              </p>
            </div>
          </div>
        </button>

        {/* Build with Chat */}
        <button 
          onClick={onStartChat}
          className="group relative p-10 bg-indigo-600 rounded-[40px] shadow-2xl hover:bg-indigo-700 transition-all text-start overflow-hidden border-4 border-transparent hover:border-indigo-400"
        >
          <div className="relative z-10 space-y-6">
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center text-white text-3xl group-hover:scale-110 transition-transform">
              <i className="fa-solid fa-comments"></i>
            </div>
            <div className="text-white">
              <h3 className="text-2xl font-black mb-2">{isRtl ? 'البناء بالدردشة' : 'Build with Chat'}</h3>
              <p className="text-indigo-100 text-sm leading-relaxed">
                {isRtl ? 'أجب على أسئلة ذكية وسنقوم بصياغة إنجازاتك بشكل احترافي.' : 'Answer smart questions and we will draft your achievements professionally.'}
              </p>
            </div>
          </div>
        </button>

        {/* Build Fresh */}
        <button 
