import React, { useState, useMemo } from 'react';
import { CVData, TemplateType, ThemeConfig, Language } from '../types';

interface CVPreviewProps {
  data: CVData;
  template: TemplateType;
  theme: ThemeConfig;
  lang: Language;
  activated: boolean;
}

export const CVPreview: React.FC<CVPreviewProps> = ({ data, template, theme, lang, activated }) => {
  const [eyeComfort, setEyeComfort] = useState(false);
  const isRtl = lang === Language.AR;
  const directionClass = isRtl ? 'rtl' : 'ltr';
  const textAlignClass = isRtl ? 'text-right' : 'text-left';

  // Auto-Fit Logic
  const autoFontSize = useMemo(() => {
    const totalItems = data.experience.reduce((acc, exp) => acc + exp.achievements.length, 0) + data.education.length + (data.summary.length / 100);
    if (totalItems > 15) return 'text-[9px]';
    if (totalItems > 10) return 'text-[10px]';
    return theme.fontSize === 'sm' ? 'text-[11px]' : theme.fontSize === 'lg' ? 'text-sm' : 'text-xs';
  }, [data, theme.fontSize]);

  const renderSection = (type: string, overrideHeader?: string) => {
    const textColor = eyeComfort ? 'text-slate-300' : 'text-slate-700';
    const headingColor = theme.primaryColor;

    switch (type) {
      case 'summary':
        return (
          <section key="summary" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'الملخص المهني' : 'Professional Summary')}
            </h3>
            <p className={`${autoFontSize} leading-relaxed ${textColor} text-justify`}>{data.summary}</p>
          </section>
        );
      case 'experience':
        return (
          <section key="experience" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-3 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'الخبرات العملية' : 'Work Experience')}
            </h3>
            <div className="space-y-3">
              {data.experience.map((exp, idx) => (
                <div key={idx} className="relative">
                  <div className="flex justify-between items-baseline mb-1">
                    <h4 className={`font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} text-xs`}>{exp.position}</h4>
                    <span className="text-[9px] text-slate-500 font-bold">{exp.duration}</span>
                  </div>
                  <p className="text-[10px] italic mb-1" style={{ color: headingColor }}>{exp.company}</p>
                  <ul className={`list-disc list-inside space-y-1 ${textColor} ${autoFontSize}`}>
                    {exp.achievements.map((item, i) => item.trim() && <li key={i}>{item}</li>)}
                  </ul>
                </div>
              ))}
            </div>
          </section>
        );
      case 'education':
        return (
          <section key="education" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'التعليم' : 'Education')}
            </h3>
            <div className="space-y-2">
              {data.education.map((edu, idx) => (
                <div key={idx}>
                  <h4 className={`font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} text-[11px]`}>{edu.degree}</h4>
                  <p className={`text-[9px] ${eyeComfort ? 'text-slate-400' : 'text-slate-600'}`}>{edu.institution} | {edu.year}</p>
                </div>
              ))}
            </div>
          </section>
        );
      case 'skills':
        return (
          <section key="skills" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'المهارات' : 'Skills')}
            </h3>
            <div className="flex flex-wrap gap-1.5">
              {data.skills.map((skill, idx) => skill.trim() && (
                <span key={idx} className={`px-2 py-0.5 ${eyeComfort ? 'bg-slate-800 text-slate-300' : 'bg-slate-100 text-slate-700'} rounded text-[9px] font-bold border border-slate-200 dark:border-slate-700`}>
                  {skill}
                </span>
              ))}
            </div>
          </section>
        );
      default: return null;
    }
  };

  const templates = {
    [TemplateType.CLASSIC]: () => (
      <div className={`p-10 ${textAlignClass}`}>
        <div className={`border-b-4 ${eyeComfort ? 'border-slate-700' : 'border-slate-900'} pb-4 mb-6 text-center`}>
          <h2 className={`text-3xl font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} mb-1 uppercase tracking-tighter`}>{data.personal_info.full_name}</h2>
          <div className={`flex justify-center gap-4 text-[9px] ${eyeComfort ? 'text-slate-400' : 'text-slate-600'} font-bold`}>
            <span>{data.personal_info.email}</span>
            <span>•</span>
            <span>{data.personal_info.phone}</span>
            <span>•</span>
            <span>{data.personal_info.location}</span>
          </div>
        </div>
        {theme.sectionOrder.map(s => renderSection(s))}
      </div>
    ),
    [TemplateType.MODERN]: () => (
      <div className={`flex min-h-[1123px] ${directionClass}`}>
        <div className="w-1/3 bg-slate-900 text-white p-6 space-y-6">
          <div className="text-center">
             <div className="w-20 h-20 bg-slate-800 rounded-full mx-auto mb-4 border-2 border-slate-700 flex items-center justify-center">
                <i className="fa-solid fa-user text-3xl"></i>
             </div>
             <h2 className="text-xl font-black">{data.personal_info.full_name}</h2>
             <p className="text-[9px] font-bold tracking-widest text-emerald-400">{data.personal_info.target_job}</p>
          </div>
          <div className="space-y-6">
             {theme.sectionOrder.filter(s => s === 'skills' || s === 'education').map(s => renderSection(s))}
          </div>
        </div>
        <div className={`flex-1 p-10 ${eyeComfort ? 'bg-slate-950' : 'bg-white'} ${textAlignClass}`}>
          {theme.sectionOrder.filter(s => s === 'summary' || s === 'experience').map(s => renderSection(s))}
        </div>
      </div>
    ),
    [TemplateType.TECH]: () => (
      <div className={`p-10 ${textAlignClass} bg-slate-950 text-emerald-400 font-mono`}>
        <div className="border-l-4 border-emerald-500 pl-6 mb-10">
          <h2 className="text-4xl font-black text-white">{data.personal_info.full_name}</h2>
          <p className="text-emerald-500 uppercase tracking-widest">{data.personal_info.target_job}</p>
          <div className="text-[9px] text-slate-500 mt-2">
            {data.personal_info.email} // {data.personal_info.phone} // {data.personal_info.location}
          </div>
        </div>
        <div className="grid grid-cols-1 gap-8">
          {theme.sectionOrder.map(s => renderSection(s))}
        </div>
      </div>
    ),
    [TemplateType.EXECUTIVE]: () => (
      <div className={`p-12 ${textAlignClass} font-serif bg-white`}>
        <div className="text-center mb-12 border-b border-slate-300 pb-8">
          <h2 className="text-4xl font-black text-slate-900 mb-2 uppercase tracking-widest">{data.personal_info.full_name}</h2>
          <p className="text-sm font-bold text-slate-500 uppercase tracking-[0.3em] mb-4">{data.personal_info.target_job}</p>
          <div className="flex justify-center gap-6 text-[10px] text-slate-400 font-bold italic">
            <span>{data.personal_info.email}</span>
            <span>•</span>
            <span>{data.personal_info.phone}</span>
            <span>•</span>
            <span>{data.personal_info.location}</span>
          </div>
        </div>
        {theme.sectionOrder.map(s => renderSection(s))}
      </div>
    ),
    [TemplateType.NEOM]: () => (
      <div className={`p-10 ${eyeComfort ? 'bg-slate-950' : 'bg-slate-50'} ${textAlignClass}`}>
        <div className={`${eyeComfort ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'} rounded-[32px] shadow-xl p-8 border mb-6 relative overflow-hidden`}>
          <div className="absolute top-0 right-0 w-32 h-32 blur-3xl rounded-full opacity-20" style={{ backgroundColor: theme.primaryColor }}></div>
          <div className="flex justify-between items-center relative z-10">
             <div>
               <h2 className={`text-3xl font-black mb-1 ${eyeComfort ? 'text-white' : 'text-slate-900'}`}>{data.personal_info.full_name}</h2>
               <span className="text-[9px] font-black px-3 py-1 bg-slate-900 text-white rounded-full">{data.personal_info.target_job}</span>
             </div>
             <div className="bg-emerald-50 text-emerald-600 px-3 py-1.5 rounded-2xl text-[9px] font-black">ATS: {data.ats_score}%</div>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-6">{theme.sectionOrder.map(s => renderSection(s))}</div>
      </div>
    )
  };

  return (
    <div className={`group relative mx-auto max-w-[800px] no-print w-full`}>
      <div className="flex justify-between items-center mb-4">
        <button 
          onClick={() => setEyeComfort(!eyeComfort)}
          className="bg-slate-800 dark:bg-slate-700 text-white px-4 py-2 rounded-xl text-[10px] font-black hover:bg-slate-700 transition-all flex items-center gap-2 z-[60] shadow-lg"
        >
          <i className={`fa-solid ${eyeComfort ? 'fa-eye' : 'fa-eye-slash'}`}></i>
          {eyeComfort ? (isRtl ? 'وضع الطباعة' : 'Print Mode') : (isRtl ? 'رؤية في الظلام' : 'View in Dark')}
        </button>
        <div className="bg-slate-900 dark:bg-black text-white px-3 py-1 rounded-full text-[9px] font-black border border-white/10 uppercase">
           A4 Optimized // 210 x 297 mm
        </div>
      </div>

      <div className={`${eyeComfort ? 'bg-slate-950 text-slate-300' : 'bg-white text-slate-900'} shadow-2xl overflow-hidden min-h-[1123px] relative border border-slate-200 dark:border-slate-800 ${directionClass} transition-all duration-500`}>
        {!activated && (
          <div className="absolute inset-0 pointer-events-none z-50 overflow-hidden flex flex-col justify-center gap-32 backdrop-blur-[2px]">
            {Array(8).fill(0).map((_, i) => (
              <div key={i} className="text-slate-200/40 dark:text-slate-700/20 text-5xl font-black -rotate-45 whitespace-nowrap select-none w-full text-center">
                {isRtl ? 'نسخة معاينة - غير مفعلة' : 'PREVIEW ONLY - NOT ACTIVATED'}
              </div>
            ))}
          </div>
        )}
        <div className={!activated ? 'blur-[1.5px] opacity-90' : ''}>
          {templates[template]()}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { SocialBrand } from './components/SocialBrand';
import { SalaryNegotiator } from './components/SalaryNegotiator';
import { CredentialVerifier } from './components/CredentialVerifier';
import { CareerSimulator } from './components/CareerSimulator';
import { PortfolioBuilder } from './components/PortfolioBuilder';
import { VirtualCoach } from './components/VirtualCoach';
import { CandidateHub } from './components/CandidateHub';
import { EditorWizard } from './components/EditorWizard';
import { TalentScout } from './components/TalentScout';
import { AIScreening } from './components/AIScreening';
import { Scorecard } from './components/Scorecard';
import { SmartScheduler } from './components/SmartScheduler';
import { processCVInput, translateCV, generateQualityAlert, generateCoverLetter } from './services/geminiService';
import { UserRole, ApiResponse, CVData, CandidateProfile, TemplateType, ThemeConfig, Language, ThemeMode, WizardStep } from './types';
import { TRANSLATIONS, PAYMENT_INFO } from './constants';

const initialCV: CVData = {
  personal_info: { full_name: '', email: '', phone: '', location: '', target_job: '' },
  summary: '',
  experience: [],
  education: [],
  skills: [],
  ats_score: 15
};

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [cvData, setCVData] = useState<CVData>(initialCV);
  const [wizardStep, setWizardStep] = useState<WizardStep>(WizardStep.HUB);
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  // Theme & Language State
  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [themeMode, setThemeMode] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('sirati_theme');
    if (saved) return saved as ThemeMode;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? ThemeMode.DARK : ThemeMode.LIGHT;
  });
  const [template, setTemplate] = useState<TemplateType>(TemplateType.PROFESSIONAL);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#059669',
    sectionOrder: ['summary', 'experience', 'education', 'skills'],
    fontSize: 'base'
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  const toggleTheme = () => {
    setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);
  };

  const generateOtp = (r: UserRole) => {
    const prefix = r === UserRole.SEEKER ? 'S-' : 'B-';
    return `${prefix}${Math.floor(1000 + Math.random() * 9000)}`;
  };

  const updateCVData = async (newData: CVData) => {
    setCVData(newData);
  };

  const handleStartFresh = () => setWizardStep(WizardStep.PERSONAL);
  const handleStartChat = () => setWizardStep(WizardStep.CHAT);

  const handleExtracted = (data: CVData) => {
    setCVData(data);
    setWizardStep(WizardStep.PERSONAL);
  };

  const handleProcessFinal = async () => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(JSON.stringify(cvData), cvData.personal_info.target_job, uiLang);
      const coverLetter = await generateCoverLetter(cvData, uiLang);
      apiResult.cv.cover_letter = coverLetter;
      setResult(apiResult);
      setWizardStep(WizardStep.PREVIEW);
    } catch (error) {
      alert("Processing error.");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    if (!result) {
      setUiLang(targetLang);
      return;
    }
    setLoading(true);
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert("Translation failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string) => {
    if (code.length >= 4) setActivated(true);
    else alert(isRtl ? "كود التفعيل غير صحيح" : "Invalid code");
  };

  if (!role) {
    return (
      <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center">
          <div className="text-center mb-16 space-y-6">
            <h2 className="text-6xl md:text-8xl font-black text-slate-900 dark:text-white leading-tight">
              {t.hero_title} <span className="text-emerald-600 dark:text-emerald-400">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 dark:text-slate-400 text-2xl max-w-2xl mx-auto">{t.hero_desc}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group p-12 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-tie"></i></div>
              <div><h3 className="text-3xl font-black text-slate-900 dark:text-white mb-2 underline decoration-emerald-200 decoration-8 underline-offset-4">{t.role_seeker}</h3><p className="text-slate-500 dark:text-slate-400 text-lg">{t.role_seeker_desc}</p></div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group p-12 bg-slate-900 dark:bg-black border-2 border-slate-800 rounded-[40px] shadow-2xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-6">
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-3xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform"><i className="fa-solid fa-bolt"></i></div>
              <div className="text-white"><h3 className="text-3xl font-black mb-2 underline decoration-slate-700 decoration-8 underline-offset-4">{t.role_employer}</h3><p className="text-slate-400 text-lg">{t.role_employer_desc}</p></div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
      <div className="container mx-auto px-4 py-12">
        <div className="flex items-center justify-between mb-12 max-w-6xl mx-auto no-print">
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setWizardStep(WizardStep.HUB);}} className="text-slate-500 dark:text-slate-400 font-bold flex items-center gap-2 hover:text-slate-900 dark:hover:text-white transition-colors">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i> {t.back_to_main}
          </button>
        </div>

        {role === UserRole.SEEKER && wizardStep === WizardStep.HUB && (
          <CandidateHub onStartFresh={handleStartFresh} onStartChat={handleStartChat} onExtracted={handleExtracted} lang={uiLang} />
        )}

        {role === UserRole.SEEKER && wizardStep === WizardStep.CHAT && (
          <div className="max-w-2xl mx-auto bg-white dark:bg-slate-900 rounded-[40px] shadow-2xl p-10 space-y-8 animate-in slide-in-from-bottom duration-500">
            <h3 className="text-3xl font-black dark:text-white">{isRtl ? 'البناء بالدردشة' : 'Build with Chat'}</h3>
            <div className="h-96 overflow-y-auto space-y-4 p-4 bg-slate-50 dark:bg-slate-800 rounded-3xl border border-slate-100 dark:border-slate-700">
               <div className="bg-emerald-100 dark:bg-emerald-900 p-4 rounded-2xl text-sm">{isRtl ? 'مرحباً! أنا مساعدك المهني. ما هو اسمك الكامل؟' : 'Hi! I am your career assistant. What is your full name?'}</div>
            </div>
            <div className="flex gap-4">
               <input className="flex-1 p-4 bg-slate-50 dark:bg-slate-800 border rounded-2xl outline-none dark:text-white" placeholder={isRtl ? 'اكتب إجابتك هنا...' : 'Type your answer...'} />
               <button onClick={() => setWizardStep(WizardStep.PERSONAL)} className="bg-emerald-600 text-white px-8 rounded-2xl font-black">إرسال</button>
            </div>
          </div>
        )}

        {role === UserRole.SEEKER && wizardStep !== WizardStep.HUB && wizardStep !== WizardStep.CHAT && wizardStep !== WizardStep.PREVIEW && (
          <EditorWizard 
            data={cvData} 
            onChange={updateCVData} 
            step={wizardStep} 
            lang={uiLang}
            onNext={() => {
              if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.EXPERIENCE);
              else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.EDUCATION);
              else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.SKILLS);
              else handleProcessFinal();
            }}
            onPrev={() => {
              if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.HUB);
              else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.PERSONAL);
              else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.EXPERIENCE);
              else setWizardStep(WizardStep.EDUCATION);
            }}
          />
        )}

        {role === UserRole.EMPLOYER && !result && (
          <TalentScout onViewCandidate={c => { setActiveCandidate(c); handleActivate("BYPASS"); setResult({cv: c, career_path: {}, smart_helper: {}, market_insights: {}} as any); }} onShortlist={c => setShortlist([...shortlist, c])} shortlist={shortlist} lang={uiLang} />
        )}

        {result && (
          <div className="max-w-6xl mx-auto flex flex-col lg:flex-row gap-12">
            <aside className="lg:w-80 space-y-6 no-print">
              <div className="bg-white dark:bg-slate-900 p-8 rounded-[40px] shadow-2xl border border-slate-100 dark:border-slate-800 sticky top-12 space-y-8">
                <h3 className="text-lg font-black dark:text-white flex items-center gap-2"><i className="fa-solid fa-palette text-emerald-500"></i> {t.design_customize}</h3>
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-2">
                    {Object.values(TemplateType).map(v => (
                      <button key={v} onClick={() => setTemplate(v)} className={`p-2 rounded-xl border-2 text-[9px] font-bold ${template === v ? 'border-emerald-500 bg-emerald-50' : 'border-slate-50'}`}>{v}</button>
                    ))}
                  </div>
                  <button onClick={handleTranslateToggle} className="w-full py-4 bg-slate-900 dark:bg-emerald-600 text-white rounded-2xl text-xs font-black shadow-lg">{t.translate_btn}</button>
                </div>
              </div>
            </aside>

            <div className="flex-1 space-y-12">
              <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />

              {otp && !activated && (
                <div className="no-print space-y-8">
                  <Paywall role={role} otp={otp} onActivate={handleActivate} lang={uiLang} />
                </div>
              )}

              {activated && (
                <div className="space-y-12 animate-in fade-in zoom-in duration-500">
                  <div className="bg-emerald-600 dark:bg-black text-white p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row items-center justify-between gap-8 no-print border border-white/10">
                    <div className="flex items-center gap-6">
                      <div className="w-16 h-16 bg-yellow-400 text-black rounded-3xl flex items-center justify-center text-3xl shadow-xl shadow-yellow-400/20"><i className="fa-solid fa-crown"></i></div>
                      <div><h4 className="text-2xl font-black">{t.verified_badge}</h4><p className="opacity-80 text-sm">{t.verified_desc}</p></div>
                    </div>
                    <button onClick={() => window.print()} className="bg-white text-emerald-600 px-12 py-5 rounded-[24px] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
                      <i className="fa-solid fa-file-pdf"></i> {t.export_pdf}
                    </button>
                  </div>
                  {result.cv.cover_letter && (
                    <div className="bg-white dark:bg-slate-900 p-10 rounded-[40px] shadow-2xl border border-slate-100 dark:border-slate-800 no-print">
                      <h3 className="text-2xl font-black mb-6 text-emerald-600">{isRtl ? 'خطاب التغطية (Cover Letter)' : 'Cover Letter'}</h3>
                      <div className="whitespace-pre-wrap text-slate-700 dark:text-slate-300 italic bg-slate-50 dark:bg-slate-800 p-8 rounded-3xl border">{result.cv.cover_letter}</div>
                    </div>
                  )}
                  {role === UserRole.SEEKER && (
                    <div className="grid grid-cols-1 gap-12 no-print">
                      <CareerPath data={result.career_path} />
                      <CareerRadar data={result.market_insights} />
                      <SmartHelper data={result.smart_helper} />
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

