                  {role === UserRole.SEEKER && (
                    <div className="grid grid-cols-1 gap-12 no-print pb-24">
                      <CareerPath data={result.career_path} />
                      <CareerRadar data={result.market_insights} />
                      <SmartHelper data={result.smart_helper} />

                      <div className="text-center py-10 border-t border-slate-200 dark:border-slate-800 opacity-50">
                        <p className="text-xs font-bold text-slate-400">
                          {t.founder_by} 
                          <a href={PAYMENT_INFO.linkedin} target="_blank" rel="noopener noreferrer" className="text-emerald-500 hover:underline mx-1">
                            {t.founder_name}
                          </a>
                        </p>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

