import { GoogleGenAI, Type } from "@google/genai";
import { 
  ApiResponse, 
  CVData, 
  Language, 
  CandidateProfile, 
  VerificationResult, 
  InterviewAnalysis, 
  JobMatchResult,
  InterviewQuestion,
  InterviewReport
} from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const CV_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    personal_info: {
      type: Type.OBJECT,
      properties: {
        full_name: { type: Type.STRING },
        email: { type: Type.STRING },
        phone: { type: Type.STRING },
        location: { type: Type.STRING },
        target_job: { type: Type.STRING },
      },
      required: ["full_name", "email", "phone", "location", "target_job"]
    },
    summary: { type: Type.STRING },
    experience: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          company: { type: Type.STRING },
          position: { type: Type.STRING },
          duration: { type: Type.STRING },
          achievements: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["company", "position", "duration", "achievements"]
      }
    },
    education: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          institution: { type: Type.STRING },
          degree: { type: Type.STRING },
          year: { type: Type.STRING }
        },
        required: ["institution", "degree", "year"]
      }
    },
    skills: { type: Type.ARRAY, items: { type: Type.STRING } },
    ats_score: { type: Type.NUMBER }
  },
  required: ["personal_info", "summary", "experience", "education", "skills", "ats_score"]
};

export const suggestFieldContent = async (fieldName: string, currentData: CVData, lang: Language): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Professional resume writer for Sirati Pro Platform. Field: ${fieldName}. Target: ${currentData?.personal_info?.target_job || 'General'}. Lang: ${lang}. Impactful, metrics-driven sentences.`,
  });
  return response.text.trim();
};

export const conversationalChatBuilder = async (messages: {role: string, content: string}[], lang: Language): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are the Sirati AI Career Coach. Help the user build their resume by asking short questions one by one. Lang: ${lang}. Current Conversation: ${JSON.stringify(messages)}`,
  });
  return response.text.trim();
};

export const generateCoverLetter = async (cv: CVData, lang: Language): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a high-impact cover letter for ${cv?.personal_info?.full_name || 'Candidate'} targeting ${cv?.personal_info?.target_job || 'this role'}. Lang: ${lang}. Data: ${JSON.stringify(cv)}`,
  });
  return response.text.trim();
};

export const magicExtractCV = async (base64File: string, lang: Language): Promise<CVData> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      { inlineData: { mimeType: base64File.split(';')[0].split(':')[1], data: base64File.split(',')[1] } },
      { text: `Extract resume data into JSON following the schema. 
      CRITICAL: You MUST provide 'personal_info' with all required fields (full_name, email, phone, location, target_job). 
      If a value is missing, use an empty string "" but NEVER leave the field or parent object undefined.
      Modernize for 2026 standards. Use power verbs. Lang: ${lang}` }
    ],
    config: { 
      responseMimeType: "application/json",
      responseSchema: CV_SCHEMA
    }
  });
  const raw = JSON.parse(response.text);

  // Extra safety check for App component's 'personal_info' dependency
  if (!raw.personal_info) {
    raw.personal_info = { full_name: '', email: '', phone: '', location: '', target_job: '' };
  }

  return raw;
};

export const translateCV = async (cv: CVData, targetLang: Language): Promise<CVData> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Professional recruitment translation to ${targetLang}. Mirror all fields exactly. Preserve all metric-driven achievements. Data: ${JSON.stringify(cv)}`,
    config: { 
      responseMimeType: "application/json",
      responseSchema: CV_SCHEMA
    }
  });
  return JSON.parse(response.text);
};

export const generateMockCandidates = async (filters: any): Promise<CandidateProfile[]> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate 3 diverse professional candidate profiles matching: ${JSON.stringify(filters)}. Include fit scores and personality eval. Each profile must strictly follow the candidate schema including personal_info.`,
    config: { responseMimeType: "application/json" }
  });
  const data = JSON.parse(response.text);
  return data.candidates || data;
};

export const processCVInput = async (input: string, targetJob: string, lang: Language): Promise<ApiResponse> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
