                <p className="text-slate-400 text-lg leading-relaxed">{t.role_employer_desc}</p>
              </div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
      <div className="container mx-auto px-4 py-12">
        <div className="flex items-center justify-between mb-12 max-w-6xl mx-auto no-print">
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setWizardStep(WizardStep.HUB);}} className="bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black px-6 py-3 rounded-2xl flex items-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-md group">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'} group-hover:scale-110 transition-transform`}></i> 
            {t.back_to_main}
          </button>

          <div className="text-center font-black text-slate-400 text-xs tracking-widest uppercase">
            {isRtl ? 'بإشراف: ' : 'By: '}
            <a href={PAYMENT_INFO.linkedin} target="_blank" rel="noopener noreferrer" className="text-emerald-500 hover:underline mx-1">
              {isRtl ? PAYMENT_INFO.owner.ar : PAYMENT_INFO.owner.en}
            </a>
          </div>
        </div>

        {role === UserRole.SEEKER && wizardStep === WizardStep.HUB && (
