                        <button key={v} onClick={() => setTemplate(v)} className={`p-3 rounded-2xl border-2 text-[10px] font-black transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-400' : 'border-slate-50 dark:border-slate-800 text-slate-400 hover:border-slate-200'}`}>{v}</button>
