export const verifyCertificate = async (base64Data: string, cvData: CVData): Promise<VerificationResult> => {
  // Use correct multi-part content structure with actual image data for multimodal tasks
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: base64Data.split(';')[0].split(':')[1],
            data: base64Data.split(',')[1],
          },
        },
        { text: `Verify this certificate for ${cvData?.personal_info?.full_name || 'Candidate'}. Identify if it matches the skills in the CV.` }
      ]
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text);
};

export const getKeywordSuggestions = async (skill: string, targetJob: string): Promise<string[]> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Provide 5 high-impact ATS keywords for ${skill} within a ${targetJob} role. Return as JSON array of strings.`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text);
};

export const analyzeInterviewAnswers = async (questions: InterviewQuestion[], answers: string[]): Promise<InterviewReport> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Evaluate these interview responses. Questions: ${JSON.stringify(questions)}, Answers: ${JSON.stringify(answers)}. Analyze honesty, depth, and professionalism.`,
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text);
};

