import React, { useState, useMemo } from 'react';
import { CVData, TemplateType, ThemeConfig, Language } from '../types';
import { PAYMENT_INFO } from '../constants';

interface CVPreviewProps {
  data: CVData;
  template: TemplateType;
  theme: ThemeConfig;
  lang: Language;
  activated: boolean;
}

export const CVPreview: React.FC<CVPreviewProps> = ({ data, template, theme, lang, activated }) => {
  const [eyeComfort, setEyeComfort] = useState(false);
  const isRtl = lang === Language.AR;
  const directionClass = isRtl ? 'rtl' : 'ltr';
  const textAlignClass = isRtl ? 'text-right' : 'text-left';

  // Auto-Fit Logic
  const autoFontSize = useMemo(() => {
    const totalItems = (data.experience?.reduce((acc, exp) => acc + (exp.achievements?.length || 0), 0) || 0) + (data.education?.length || 0) + (data.summary?.length / 100 || 0);
    if (totalItems > 15) return 'text-[9px]';
    if (totalItems > 10) return 'text-[10px]';
    return theme.fontSize === 'sm' ? 'text-[11px]' : theme.fontSize === 'lg' ? 'text-sm' : 'text-xs';
  }, [data, theme.fontSize]);

  const renderSection = (type: string, overrideHeader?: string) => {
    const textColor = eyeComfort ? 'text-slate-300' : 'text-slate-700';
    const headingColor = theme.primaryColor;

    switch (type) {
      case 'summary':
        return (
          <section key="summary" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'الملخص المهني' : 'Professional Summary')}
            </h3>
            <p className={`${autoFontSize} leading-relaxed ${textColor} text-justify`}>{data.summary}</p>
          </section>
        );
      case 'experience':
        return (
          <section key="experience" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-3 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'الخبرات العملية' : 'Work Experience')}
            </h3>
            <div className="space-y-3">
              {data.experience?.map((exp, idx) => (
                <div key={idx} className="relative">
                  <div className="flex justify-between items-baseline mb-1">
                    <h4 className={`font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} text-xs`}>{exp.position}</h4>
                    <span className="text-[9px] text-slate-500 font-bold">{exp.duration}</span>
                  </div>
                  <p className="text-[10px] italic mb-1" style={{ color: headingColor }}>{exp.company}</p>
                  <ul className={`list-disc list-inside space-y-1 ${textColor} ${autoFontSize}`}>
                    {exp.achievements?.map((item, i) => item.trim() && <li key={i}>{item}</li>)}
                  </ul>
                </div>
              ))}
            </div>
          </section>
        );
      case 'education':
        return (
          <section key="education" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'التعليم' : 'Education')}
            </h3>
            <div className="space-y-2">
              {data.education?.map((edu, idx) => (
                <div key={idx}>
                  <h4 className={`font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} text-[11px]`}>{edu.degree}</h4>
                  <p className={`text-[9px] ${eyeComfort ? 'text-slate-400' : 'text-slate-600'}`}>{edu.institution} | {edu.year}</p>
                </div>
              ))}
            </div>
          </section>
        );
      case 'skills':
        return (
          <section key="skills" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'المهارات' : 'Skills')}
            </h3>
            <div className="flex flex-wrap gap-1.5">
              {data.skills?.map((skill, idx) => skill.trim() && (
                <span key={idx} className={`px-2 py-0.5 ${eyeComfort ? 'bg-slate-800 text-slate-300' : 'bg-slate-100 text-slate-700'} rounded text-[9px] font-bold border border-slate-200 dark:border-slate-700`}>
                  {skill}
                </span>
              ))}
            </div>
          </section>
        );
      default: return null;
    }
  };

  /**
   * IMPORTANT: The 'BrandingFooter' is strictly for web visualization.
   * It MUST NOT appear in the professional PDF export as per Faisal Alsanea's 'White Label' requirement.
   * We use 'print:hidden' to ensure a clean, professional PDF.
   */
  const BrandingFooter = () => (
    <div className="mt-auto pt-8 border-t border-slate-100 text-[10px] text-slate-400 flex justify-between items-center no-print-section print:hidden">
      <span>{isRtl ? 'تم الإنشاء عبر Sira-AI' : 'Generated via Sira-AI'}</span>
      <a 
        href={PAYMENT_INFO.linkedin} 
        target="_blank" 
        rel="noopener noreferrer" 
        className="font-bold text-emerald-600 hover:underline"
      >
        {isRtl ? 'بإشراف: فيصل السني' : 'By: Faisal Alsanea'}
      </a>
    </div>
  );

  const templates = {
    [TemplateType.CLASSICAL]: () => (
      <div className={`p-10 min-h-[1123px] flex flex-col ${textAlignClass} bg-white print:p-0`}>
        <div className={`border-b-4 ${eyeComfort ? 'border-slate-700' : 'border-slate-900'} pb-4 mb-6 text-center print:border-slate-900`}>
          <h2 className={`text-3xl font-black ${eyeComfort ? 'text-white' : 'text-slate-900'} mb-1 uppercase tracking-tighter print:text-slate-900`}>{data.personal_info?.full_name || '...'}</h2>
          <div className={`flex justify-center gap-4 text-[9px] ${eyeComfort ? 'text-slate-400' : 'text-slate-600'} font-bold print:text-slate-600`}>
            <span>{data.personal_info?.email}</span>
            <span>•</span>
            <span>{data.personal_info?.phone}</span>
            <span>•</span>
            <span>{data.personal_info?.location}</span>
          </div>
        </div>
        <div className="flex-grow">
          {theme.sectionOrder.map(s => renderSection(s))}
        </div>
        <BrandingFooter />
      </div>
    ),
    [TemplateType.MODERN]: () => (
      <div className={`flex min-h-[1123px] ${directionClass} bg-white`}>
        <div className="w-1/3 bg-slate-900 text-white p-6 flex flex-col space-y-6 print:bg-slate-900">
          <div className="text-center">
             <div className="w-20 h-20 bg-slate-800 rounded-full mx-auto mb-4 border-2 border-slate-700 flex items-center justify-center print:border-slate-700">
                <i className="fa-solid fa-user text-3xl"></i>
             </div>
             <h2 className="text-xl font-black">{data.personal_info?.full_name || '...'}</h2>
             <p className="text-[9px] font-bold tracking-widest text-emerald-400">{data.personal_info?.target_job}</p>
          </div>
          <div className="flex-grow space-y-6">
             {theme.sectionOrder.filter(s => s === 'skills' || s === 'education').map(s => renderSection(s))}
          </div>
          {/* White Label check: ensure this is hidden in print */}
          <div className="pt-4 border-t border-slate-800 text-[8px] opacity-40 print:hidden">
            Sira-AI Sovereign Hub
          </div>
        </div>
        <div className={`flex-1 p-10 flex flex-col ${eyeComfort ? 'bg-slate-950' : 'bg-white'} ${textAlignClass} print:bg-white`}>
          <div className="flex-grow">
            {theme.sectionOrder.filter(s => s === 'summary' || s === 'experience').map(s => renderSection(s))}
          </div>
          <BrandingFooter />
        </div>
      </div>
    ),
    [TemplateType.TECH]: () => (
      <div className={`p-10 min-h-[1123px] flex flex-col ${textAlignClass} bg-slate-950 text-emerald-400 font-mono relative overflow-hidden print:bg-white print:text-slate-900`}>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/5 blur-[100px] pointer-events-none print:hidden"></div>
        <div className="border-l-4 border-emerald-500 pl-6 mb-10 print:border-emerald-600">
          <h2 className="text-4xl font-black text-white print:text-slate-900">{data.personal_info?.full_name || '...'}</h2>
          <p className="text-emerald-500 uppercase tracking-widest print:text-emerald-700">{data.personal_info?.target_job}</p>
          <div className="text-[9px] text-slate-500 mt-2 print:text-slate-500">
            {data.personal_info?.email} // {data.personal_info?.phone} // {data.personal_info?.location}
          </div>
        </div>
        <div className="flex-grow grid grid-cols-1 gap-8">
          {theme.sectionOrder.map(s => renderSection(s))}
        </div>
        <BrandingFooter />
      </div>
    ),
    [TemplateType.EXECUTIVE]: () => (
      <div className={`p-12 min-h-[1123px] flex flex-col ${textAlignClass} font-serif bg-white border-[12px] border-slate-50 print:border-none print:p-8`}>
        <div className="text-center mb-12 border-b border-slate-300 pb-8">
          <h2 className="text-4xl font-black text-slate-900 mb-2 uppercase tracking-widest">{data.personal_info?.full_name || '...'}</h2>
          <p className="text-sm font-bold text-slate-500 uppercase tracking-[0.3em] mb-4">{data.personal_info?.target_job}</p>
          <div className="flex justify-center gap-6 text-[10px] text-slate-400 font-bold italic">
            <span>{data.personal_info?.email}</span>
            <span>•</span>
            <span>{data.personal_info?.phone}</span>
            <span>•</span>
            <span>{data.personal_info?.location}</span>
          </div>
        </div>
        <div className="flex-grow">
          {theme.sectionOrder.map(s => renderSection(s))}
        </div>
        <BrandingFooter />
      </div>
    ),
    [TemplateType.NEOM]: () => (
      <div className={`p-10 min-h-[1123px] flex flex-col ${eyeComfort ? 'bg-slate-950' : 'bg-slate-50'} ${textAlignClass} print:bg-white print:p-0`}>
        <div className={`${eyeComfort ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'} rounded-[40px] shadow-2xl p-10 border mb-8 relative overflow-hidden print:shadow-none print:border-slate-200 print:rounded-none`}>
          <div className="absolute top-0 right-0 w-48 h-48 blur-[80px] rounded-full opacity-10 print:hidden" style={{ backgroundColor: theme.primaryColor }}></div>
          <div className="flex justify-between items-center relative z-10">
             <div>
               <h2 className={`text-4xl font-black mb-2 ${eyeComfort ? 'text-white' : 'text-slate-900'} print:text-slate-900`}>{data.personal_info?.full_name || '...'}</h2>
               <div className="flex gap-2">
                <span className="text-[10px] font-black px-4 py-1.5 bg-slate-900 text-white rounded-full uppercase tracking-wider print:bg-slate-800">{data.personal_info?.target_job}</span>
                <span className="text-[10px] font-bold text-slate-400 self-center">{data.personal_info?.location}</span>
               </div>
             </div>
             <div className="bg-emerald-50 text-emerald-600 px-4 py-2 rounded-2xl text-[10px] font-black shadow-inner print:border print:border-emerald-200">ATS COMPLIANT: {data.ats_score}%</div>
          </div>
        </div>
        <div className="flex-grow grid grid-cols-2 gap-8 print:grid-cols-1">
          {theme.sectionOrder.map(s => renderSection(s))}
        </div>
        <BrandingFooter />
