    )
  };

  return (
    <div className={`group relative mx-auto max-w-[800px] no-print-container w-full`}>
      <div className="flex justify-between items-center mb-4 px-2 no-print">
        <div className="flex gap-2">
          <button 
            onClick={() => setEyeComfort(!eyeComfort)}
            className="bg-slate-800 dark:bg-slate-700 text-white px-4 py-2 rounded-xl text-[10px] font-black hover:bg-slate-600 transition-all flex items-center gap-2 z-[60] shadow-xl border border-white/5"
          >
            <i className={`fa-solid ${eyeComfort ? 'fa-eye' : 'fa-eye-slash'}`}></i>
            {eyeComfort ? (isRtl ? 'وضع الطباعة' : 'Print Mode') : (isRtl ? 'رؤية في الظلام' : 'View in Dark')}
          </button>
        </div>
        <div className="bg-slate-900 dark:bg-black text-white px-4 py-1.5 rounded-full text-[9px] font-black border border-white/10 uppercase tracking-widest shadow-lg">
           Sira-AI Engine 2026 // A4 Optimized
        </div>
      </div>

      <div className={`${eyeComfort ? 'bg-slate-950 text-slate-300' : 'bg-white text-slate-900'} shadow-2xl overflow-hidden min-h-[1123px] relative border border-slate-200 dark:border-slate-800 ${directionClass} transition-all duration-500 print:shadow-none print:border-none print:m-0 print:p-0`}>
        {!activated && (
          <div className="absolute inset-0 pointer-events-none z-50 overflow-hidden flex flex-col justify-center gap-32 backdrop-blur-[1px] print:hidden">
            {Array(10).fill(0).map((_, i) => (
              <div key={i} className="text-slate-200/40 dark:text-slate-700/10 text-6xl font-black -rotate-45 whitespace-nowrap select-none w-full text-center uppercase tracking-[0.5em]">
                {isRtl ? 'نسخة معاينة - غير مفعلة' : 'DRAFT - NOT ACTIVATED'}
              </div>
            ))}
          </div>
        )}
        <div className={!activated ? 'blur-[0.5px] opacity-95 select-none print:opacity-100 print:blur-none' : ''}>
          {templates[template]()}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { Invoice } from './components/Invoice';
import { CandidateHub } from './components/CandidateHub';
import { EditorWizard } from './components/EditorWizard';
import { TalentScout } from './components/TalentScout';
import { processCVInput, translateCV, generateQualityAlert, generateCoverLetter } from './services/geminiService';
import { UserRole, ApiResponse, CVData, CandidateProfile, TemplateType, ThemeConfig, Language, ThemeMode, WizardStep, InvoiceData } from './types';
import { TRANSLATIONS, PAYMENT_INFO } from './constants';

const initialCV: CVData = {
  personal_info: { full_name: '', email: '', phone: '', location: '', target_job: '' },
  summary: '',
  experience: [],
  education: [],
  skills: [],
  ats_score: 15
};

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [invoice, setInvoice] = useState<InvoiceData | null>(null);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [cvData, setCVData] = useState<CVData>(initialCV);
  const [wizardStep, setWizardStep] = useState<WizardStep>(WizardStep.HUB);
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);

  // Theme & Language State
  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [themeMode, setThemeMode] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('sirati_theme');
    if (saved) return saved as ThemeMode;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? ThemeMode.DARK : ThemeMode.LIGHT;
  });
  const [template, setTemplate] = useState<TemplateType>(TemplateType.NEOM);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#10b981', // Emerald 500
    sectionOrder: ['summary', 'experience', 'education', 'skills'],
    fontSize: 'base'
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  const toggleTheme = () => {
    setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);
  };

  const generateOtp = (r: UserRole) => {
    const prefix = r === UserRole.SEEKER ? 'TX-' : 'EX-';
    return `${prefix}${Math.floor(10000 + Math.random() * 89999)}`;
  };

  const updateCVData = (newData: Partial<CVData>) => {
    setCVData(prev => ({
      ...prev,
      ...newData,
      personal_info: newData.personal_info ? { ...prev.personal_info, ...newData.personal_info } : prev.personal_info
    }));
  };

  const handleStartFresh = () => setWizardStep(WizardStep.PERSONAL);
  const handleStartChat = () => setWizardStep(WizardStep.CHAT);

  const handleExtracted = (data: CVData) => {
    if (!data || !data.personal_info) {
      alert(isRtl ? "خطأ في استخراج البيانات" : "Extraction error");
      return;
    }
    setCVData(data);
    setWizardStep(WizardStep.PERSONAL);
  };

  const handleProcessFinal = async () => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(JSON.stringify(cvData), cvData.personal_info.target_job, uiLang);
      const coverLetter = await generateCoverLetter(cvData, uiLang);
      apiResult.cv.cover_letter = coverLetter;
      setResult(apiResult);
      setWizardStep(WizardStep.PREVIEW);
    } catch (error) {
      alert(isRtl ? "فشل المحرك السيادي في المعالجة" : "Sovereign Engine failed processing");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    if (result && !activated) {
      alert(isRtl ? "ميزة الترجمة متاحة فقط في النسخة الاحترافية (كود التفعيل مطلوب)" : "Translation is only available in the Pro version (Activation Code required)");
      return;
    }

    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    if (!result) {
      setUiLang(targetLang);
      return;
    }

    setLoading(true);
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert("Translation error");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string, invoiceData?: InvoiceData) => {
    if (code === "INSTANT_SUCCESS" || code.length >= 4) {
      setActivated(true);
      if (invoiceData) setInvoice(invoiceData);
      if (code === "INSTANT_SUCCESS") {
         alert(isRtl ? "نجحت عملية الدفع! تم تفعيل سيرتك الاحترافية وتوليد الفاتورة الذكية فوراً." : "Payment Successful! Your professional CV activated and smart invoice generated instantly.");
      }
    } else {
      alert(isRtl ? "كود تفعيل غير صحيح" : "Invalid activation code");
    }
  };

  const handlePrint = () => {
    if (!result) return;

    const originalTitle = document.title;
    const name = result.cv.personal_info.full_name || 'Candidate';
    const job = result.cv.personal_info.target_job || 'CV';

    // Slugging: Replace spaces and special characters with underscores
    const slug = (str: string) => str.trim().replace(/[^\w\s\u0600-\u06FF]/g, '').replace(/\s+/g, '_');

    const fileName = isRtl 
      ? `${slug(name)}_${slug(job)}_سيرة_ذاتية`
      : `${slug(name)}_${slug(job)}_CV`;

    document.title = fileName;
    window.print();

    // Restore original title after a short delay
    setTimeout(() => {
      document.title = originalTitle;
    }, 500);
  };

  if (!role) {
    return (
      <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
        <div className="container mx-auto px-4 py-24 flex flex-col items-center animate-in fade-in duration-1000">
          <div className="text-center mb-16 space-y-6">
            <h2 className="text-7xl md:text-9xl font-black text-slate-900 dark:text-white leading-tight tracking-tighter">
              {t.hero_title}<span className="text-emerald-500">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 dark:text-slate-400 text-2xl max-w-3xl mx-auto font-medium leading-relaxed">{t.hero_desc}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full max-w-5xl">
            <button onClick={() => setRole(UserRole.SEEKER)} className="group relative p-12 bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[60px] shadow-3xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-10 overflow-hidden active:scale-95">
              <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-[80px]"></div>
              <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-600 rounded-[30px] flex items-center justify-center text-4xl group-hover:scale-110 group-hover:rotate-6 transition-transform shadow-2xl shadow-emerald-500/10"><i className="fa-solid fa-user-graduate"></i></div>
              <div>
                <h3 className="text-3xl font-black text-slate-900 dark:text-white mb-3 underline decoration-emerald-200 decoration-8 underline-offset-8">{t.role_seeker}</h3>
                <p className="text-slate-500 dark:text-slate-400 text-lg leading-relaxed">{t.role_seeker_desc}</p>
              </div>
            </button>
            <button onClick={() => setRole(UserRole.EMPLOYER)} className="group relative p-12 bg-slate-900 dark:bg-black border-2 border-slate-800 rounded-[60px] shadow-3xl hover:border-emerald-500 transition-all text-start flex flex-col items-start gap-10 overflow-hidden active:scale-95">
              <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/10 blur-[80px]"></div>
              <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-[30px] flex items-center justify-center text-4xl group-hover:scale-110 group-hover:-rotate-6 transition-transform shadow-2xl shadow-emerald-500/20"><i className="fa-solid fa-bolt-lightning"></i></div>
              <div className="text-white">
                <h3 className="text-3xl font-black mb-3 underline decoration-slate-700 decoration-8 underline-offset-8">{t.role_employer}</h3>
                <p className="text-slate-400 text-lg leading-relaxed">{t.role_employer_desc}</p>
              </div>
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout lang={uiLang} onLangToggle={handleTranslateToggle} themeMode={themeMode} onThemeToggle={toggleTheme}>
      <div className="container mx-auto px-4 py-12">
        <div className="flex items-center justify-between mb-12 max-w-7xl mx-auto no-print">
          <button onClick={() => {setRole(null); setActivated(false); setResult(null); setInvoice(null); setWizardStep(WizardStep.HUB);}} className="bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black px-8 py-3.5 rounded-3xl flex items-center gap-3 hover:bg-slate-900 hover:text-white transition-all shadow-xl group">
            <i className={`fa-solid ${isRtl ? 'fa-arrow-right' : 'fa-arrow-left'} group-hover:scale-110 transition-transform`}></i> 
            {t.back_to_main}
          </button>

          <div className="text-center font-black text-slate-400 text-[10px] tracking-[0.3em] uppercase">
            {isRtl ? 'بإشراف: ' : 'By: '}
            <a href={PAYMENT_INFO.linkedin} target="_blank" rel="noopener noreferrer" className="text-emerald-500 hover:underline mx-1">
              {isRtl ? PAYMENT_INFO.owner.ar : PAYMENT_INFO.owner.en}
            </a>
          </div>
        </div>

        {role === UserRole.SEEKER && wizardStep === WizardStep.HUB && (
          <CandidateHub onStartFresh={handleStartFresh} onStartChat={handleStartChat} onExtracted={handleExtracted} lang={uiLang} />
        )}

        {role === UserRole.SEEKER && wizardStep === WizardStep.CHAT && (
          <div className="max-w-2xl mx-auto bg-white dark:bg-slate-900 rounded-[60px] shadow-3xl p-12 space-y-10 animate-in slide-in-from-bottom duration-500 border-2 border-slate-50 dark:border-slate-800">
            <h3 className="text-3xl font-black dark:text-white flex items-center gap-4">
              <i className="fa-solid fa-comments text-indigo-500"></i>
              {isRtl ? 'البناء بالدردشة الذكية' : 'Conversational AI Build'}
            </h3>
            <div className="h-96 overflow-y-auto space-y-5 p-8 bg-slate-50 dark:bg-slate-800/50 rounded-[40px] border-2 border-slate-100 dark:border-slate-700 shadow-inner">
               <div className="bg-emerald-100 dark:bg-emerald-900/50 p-6 rounded-[30px] text-sm dark:text-emerald-200 border border-emerald-200 dark:border-emerald-800 shadow-sm">
                 {isRtl ? 'مرحباً! أنا رفيقك المهني في Sira-AI. لنتعاون معاً لبناء سيرتك بمعايير 2026. ما هو اسمك الكامل؟' : 'Welcome! I am your Sira-AI career partner. Let\'s build your 2026-ready CV. What is your full name?'}
               </div>
               <p className="text-[10px] text-center text-slate-400 mt-8 uppercase font-black tracking-[0.4em]">Sovereign AI Protocol Active</p>
            </div>
            <div className="flex gap-4">
               <input className="flex-1 p-6 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-[30px] outline-none focus:border-emerald-500 dark:text-white transition-all shadow-inner font-bold" placeholder={isRtl ? 'اكتب هنا...' : 'Type here...'} />
               <button onClick={() => setWizardStep(WizardStep.PERSONAL)} className="bg-slate-900 dark:bg-emerald-600 hover:bg-black dark:hover:bg-emerald-500 text-white px-12 rounded-[30px] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all">إرسال</button>
            </div>
          </div>
        )}

        {role === UserRole.SEEKER && wizardStep !== WizardStep.HUB && wizardStep !== WizardStep.CHAT && wizardStep !== WizardStep.PREVIEW && (
          <EditorWizard 
            data={cvData} 
            onChange={updateCVData} 
            step={wizardStep} 
            lang={uiLang}
            onNext={() => {
              if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.EXPERIENCE);
              else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.EDUCATION);
              else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.SKILLS);
              else handleProcessFinal();
            }}
            onPrev={() => {
              if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.HUB);
              else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.PERSONAL);
              else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.EXPERIENCE);
              else setWizardStep(WizardStep.EDUCATION);
            }}
          />
        )}

        {role === UserRole.EMPLOYER && !result && (
          <TalentScout onViewCandidate={c => { setActiveCandidate(c); handleActivate("AUTO"); setResult({cv: c, career_path: {} as any, smart_helper: {} as any, market_insights: {} as any}); }} onShortlist={c => setShortlist([...shortlist, c])} shortlist={shortlist} lang={uiLang} />
        )}

        {result && (
          <div className="max-w-7xl mx-auto flex flex-col lg:flex-row gap-12 animate-in fade-in duration-1000">
            <aside className="lg:w-[400px] space-y-8 no-print">
              <div className="bg-white dark:bg-slate-900 p-10 rounded-[60px] shadow-3xl border border-slate-100 dark:border-slate-800 sticky top-12 space-y-10">
                <h3 className="text-2xl font-black dark:text-white flex items-center gap-4">
                  <i className="fa-solid fa-wand-sparkles text-emerald-500"></i> 
                  {t.design_customize}
                </h3>
                <div className="space-y-8">
                  <div className="space-y-4">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em]">{t.choose_template}</label>
                    <div className="grid grid-cols-2 gap-4">
                      {Object.values(TemplateType).map(v => (
                        <button key={v} onClick={() => setTemplate(v)} className={`p-4 rounded-[24px] border-2 text-[10px] font-black transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-400 shadow-lg' : 'border-slate-50 dark:border-slate-800 text-slate-400 hover:border-slate-200'}`}>{v}</button>
                      ))}
                    </div>
                  </div>

                  <button onClick={handleTranslateToggle} className="w-full py-6 bg-slate-900 dark:bg-emerald-600 hover:bg-black dark:hover:bg-emerald-500 text-white rounded-[32px] text-sm font-black shadow-3xl hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                    <i className="fa-solid fa-language text-xl"></i>
                    {t.translate_btn}
                  </button>
                </div>
              </div>
            </aside>

            <div className="flex-1 space-y-12 pb-24">
              <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />

              {otp && !activated && (
                <div className="no-print space-y-12">
                  <Paywall role={role} otp={otp} userName={cvData.personal_info.full_name} onActivate={handleActivate} lang={uiLang} />
                </div>
              )}

              {activated && (
                <div className="space-y-12 animate-in fade-in zoom-in duration-500">
                  <div className="bg-emerald-600 dark:bg-black text-white p-12 rounded-[70px] shadow-4xl flex flex-col md:flex-row items-center justify-between gap-10 no-print border-4 border-white/10 relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-full h-full bg-white/5 pointer-events-none group-hover:bg-white/10 transition-all"></div>
                    <div className="flex items-center gap-10 relative z-10">
                      <div className="w-24 h-24 bg-yellow-400 text-black rounded-[35px] flex items-center justify-center text-5xl shadow-3xl shadow-yellow-400/30 rotate-3 group-hover:rotate-6 transition-transform"><i className="fa-solid fa-crown"></i></div>
                      <div>
                        <h4 className="text-4xl font-black mb-3 tracking-tighter">{t.verified_badge}</h4>
                        <p className="opacity-80 text-xl font-medium">{t.verified_desc}</p>
                      </div>
                    </div>
                    <button onClick={handlePrint} className="bg-white text-emerald-600 hover:bg-emerald-50 px-20 py-7 rounded-[35px] font-black shadow-4xl hover:scale-105 active:scale-95 transition-all flex items-center gap-4 relative z-10 text-xl">
                      <i className="fa-solid fa-file-pdf"></i> {t.export_pdf}
                    </button>
                  </div>

                  {invoice && <div className="no-print"><Invoice data={invoice} lang={uiLang} /></div>}

                  <div className="grid grid-cols-1 gap-12 no-print">
                    <JobMatcher cv={result.cv} />
                    {role === UserRole.SEEKER && (
                      <>
                        <CareerPath data={result.career_path} />
                        <CareerRadar data={result.market_insights} />
                        <SmartHelper data={result.smart_helper} />
                      </>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {loading && (
        <div className="fixed inset-0 bg-slate-950/70 backdrop-blur-2xl z-[300] flex items-center justify-center p-8 no-print">
           <div className="bg-white dark:bg-slate-900 p-16 rounded-[70px] shadow-4xl text-center space-y-10 max-w-xl border-4 border-emerald-500 animate-in zoom-in duration-500">
              <div className="relative w-32 h-32 mx-auto">
                 <div className="absolute inset-0 border-[12px] border-emerald-500/20 rounded-full"></div>
                 <div className="absolute inset-0 border-[12px] border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                 <div className="absolute inset-4 bg-emerald-500 rounded-full flex items-center justify-center text-white text-3xl shadow-2xl shadow-emerald-500/40">
                    <i className="fa-solid fa-microchip"></i>
                 </div>
              </div>
              <div className="space-y-4">
                <h4 className="text-4xl font-black dark:text-white uppercase tracking-tighter">
                  {isRtl ? 'جاري التنقيب والتحليل السيادي...' : 'Neural Mining & Analysis...'}
                </h4>
                <p className="text-slate-500 dark:text-slate-400 text-lg font-bold leading-relaxed">
                  {isRtl ? 'نقوم الآن بتطبيق معايير ATS 2026 وهندسة إنجازاتك رقمياً لضمان أعلى نسبة قبول.' : 'Applying ATS 2026 standards and digitally engineering your achievements for maximum impact.'}
                </p>
              </div>
           </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { CVData, TemplateType, ThemeConfig, Language } from '../types';
import { PAYMENT_INFO } from '../constants';

interface CVPreviewProps {
  data: CVData;
  template: TemplateType;
  theme: ThemeConfig;
  lang: Language;
  activated: boolean;
}

export const CVPreview: React.FC<CVPreviewProps> = ({ data, template, theme, lang, activated }) => {
  const [eyeComfort, setEyeComfort] = useState(false);
  const isRtl = lang === Language.AR;
  const directionClass = isRtl ? 'rtl' : 'ltr';
  const textAlignClass = isRtl ? 'text-right' : 'text-left';

  // Auto-Fit Logic
  const autoFontSize = useMemo(() => {
    const totalItems = (data.experience?.reduce((acc, exp) => acc + (exp.achievements?.length || 0), 0) || 0) + (data.education?.length || 0) + (data.summary?.length / 100 || 0);
    if (totalItems > 15) return 'text-[9px]';
    if (totalItems > 10) return 'text-[10px]';
    return theme.fontSize === 'sm' ? 'text-[11px]' : theme.fontSize === 'lg' ? 'text-sm' : 'text-xs';
  }, [data, theme.fontSize]);

  const renderSection = (type: string, overrideHeader?: string) => {
    const textColor = eyeComfort ? 'text-slate-300' : 'text-slate-700';
    const headingColor = theme.primaryColor;

    switch (type) {
      case 'summary':
        return (
          <section key="summary" className="mb-4">
            <h3 style={{ color: headingColor }} className="text-sm font-black border-b border-current pb-1 mb-2 uppercase tracking-wider">
              {overrideHeader || (isRtl ? 'الملخص المهني' : 'Professional Summary')}
            </h3>
