import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Paywall } from './components/Paywall';
import { CVPreview } from './components/CVPreview';
import { CareerPath } from './components/CareerPath';
import { SmartHelper } from './components/SmartHelper';
import { JobMatcher } from './components/JobMatcher';
import { CareerRadar } from './components/CareerRadar';
import { Invoice } from './components/Invoice';
import { CandidateHub } from './components/CandidateHub';
import { EditorWizard } from './components/EditorWizard';
import { TalentScout } from './components/TalentScout';
import { processCVInput, translateCV, generateQualityAlert, generateCoverLetter } from './services/geminiService';
import { UserRole, ApiResponse, CVData, CandidateProfile, TemplateType, ThemeConfig, Language, ThemeMode, WizardStep, InvoiceData } from './types';
import { TRANSLATIONS, PAYMENT_INFO } from './constants';

const initialCV: CVData = {
  personal_info: { full_name: '', email: '', phone: '', location: '', target_job: '' },
  summary: '',
  experience: [],
  education: [],
  skills: [],
  ats_score: 15
};

type InfoPage = 'home' | 'about' | 'payment' | 'support' | 'terms';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [invoice, setInvoice] = useState<InvoiceData | null>(null);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [cvData, setCVData] = useState<CVData>(initialCV);
  const [wizardStep, setWizardStep] = useState<WizardStep>(WizardStep.HUB);
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeCandidate, setActiveCandidate] = useState<CandidateProfile | null>(null);
  const [activeInfoPage, setActiveInfoPage] = useState<InfoPage>('home');

  // Theme & Language State
  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [themeMode, setThemeMode] = useState<ThemeMode>(() => {
    const saved = localStorage.getItem('sirati_theme');
    if (saved) return saved as ThemeMode;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? ThemeMode.DARK : ThemeMode.LIGHT;
  });
  const [template, setTemplate] = useState<TemplateType>(TemplateType.NEOM);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#10b981', // Emerald 500
    sectionOrder: ['summary', 'experience', 'education', 'skills'],
    fontSize: 'base'
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  const toggleTheme = () => {
    setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);
  };

  const generateOtp = (r: UserRole) => {
    const prefix = r === UserRole.SEEKER ? 'TX-' : 'EX-';
    return `${prefix}${Math.floor(10000 + Math.random() * 89999)}`;
  };

  const updateCVData = (newData: Partial<CVData>) => {
    setCVData(prev => ({
      ...prev,
      ...newData,
      personal_info: newData.personal_info ? { ...prev.personal_info, ...newData.personal_info } : prev.personal_info
    }));
  };

  const handleStartFresh = () => setWizardStep(WizardStep.PERSONAL);
  const handleStartChat = () => setWizardStep(WizardStep.CHAT);

  const handleExtracted = (data: CVData) => {
    if (!data || !data.personal_info) {
      alert(isRtl ? "خطأ في استخراج البيانات" : "Extraction error");
      return;
    }
    setCVData(data);
    setWizardStep(WizardStep.PERSONAL);
  };

  const handleProcessFinal = async () => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(JSON.stringify(cvData), cvData.personal_info.target_job, uiLang);
      const coverLetter = await generateCoverLetter(cvData, uiLang);
      apiResult.cv.cover_letter = coverLetter;
      setResult(apiResult);
      setWizardStep(WizardStep.PREVIEW);
    } catch (error) {
      alert(isRtl ? "فشل المحرك السيادي في المعالجة" : "Sovereign Engine failed processing");
    } finally {
      setLoading(false);
    }
  };

  const handleTranslateToggle = async () => {
    if (result && !activated) {
      alert(isRtl ? "ميزة الترجمة متاحة فقط في النسخة الاحترافية (كود التفعيل مطلوب)" : "Translation is only available in the Pro version (Activation Code required)");
      return;
    }

    const targetLang = uiLang === Language.AR ? Language.EN : Language.AR;
    if (!result) {
      setUiLang(targetLang);
      return;
    }

    setLoading(true);
    try {
      const translatedData = await translateCV(result.cv, targetLang);
      setResult({ ...result, cv: translatedData });
      setUiLang(targetLang);
    } catch (e) {
      alert("Translation error");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string, invoiceData?: InvoiceData) => {
    if (code === "INSTANT_SUCCESS" || code.length >= 4) {
      setActivated(true);
      if (invoiceData) setInvoice(invoiceData);
      if (code === "INSTANT_SUCCESS") {
         alert(isRtl ? "نجحت عملية الدفع! تم تفعيل سيرتك الاحترافية وتوليد الفاتورة الذكية فوراً." : "Payment Successful! Your professional CV activated and smart invoice generated instantly.");
      }
