import React, { useState } from 'react';
import { PAYMENT_INFO, TRANSLATIONS } from '../constants';
import { UserRole, Language, InvoiceData } from '../types';

interface PaywallProps {
  role: UserRole;
  otp: string;
  userName: string;
  onActivate: (code: string, invoice?: InvoiceData) => void;
  lang: Language;
}

export const Paywall: React.FC<PaywallProps> = ({ role, otp, userName, onActivate, lang }) => {
  const [activeTab, setActiveTab] = useState<'digital' | 'bank'>('digital');
  const [code, setCode] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isAgreed, setIsAgreed] = useState(false);

  const t = lang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = lang === Language.AR;

  const price = role === UserRole.SEEKER 
    ? (isRtl ? PAYMENT_INFO.seekerPrice.ar : PAYMENT_INFO.seekerPrice.en)
    : (isRtl ? PAYMENT_INFO.employerPrice.ar : PAYMENT_INFO.employerPrice.en);

  const handleDigitalPay = () => {
    if (!isAgreed) return;
    setIsProcessing(true);
    // Simulate Apple Pay / Mada Gateway Processing
    setTimeout(() => {
      const invoice: InvoiceData = {
        id: `INV-${Math.floor(100000 + Math.random() * 900000)}`,
        date: new Date().toLocaleDateString(isRtl ? 'ar-SA' : 'en-US'),
        amount: price,
        userName: userName || (isRtl ? 'عميل مقدر' : 'Valued Customer'),
        service: role === UserRole.SEEKER ? (isRtl ? 'تفعيل السيرة الذاتية - نسخة 2026' : 'CV Activation - 2026 Edition') : (isRtl ? 'باقة أصحاب الأعمال' : 'Employer Hub Access'),
        status: 'PAID'
      };
      setIsProcessing(false);
      onActivate("INSTANT_SUCCESS", invoice);
    }, 2000);
  };

  const handleReceiptUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsProcessing(true);
      setTimeout(() => {
        setIsProcessing(false);
        alert(isRtl ? "تم استلام الإيصال، سيتم التدقيق آلياً وتفعيل حسابك خلال دقائق." : "Receipt received. AI auditing in progress. Activation shortly.");
      }, 1500);
    }
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-[50px] shadow-3xl overflow-hidden border border-slate-200 dark:border-slate-800 max-w-2xl mx-auto animate-in slide-in-from-bottom duration-700">
      <div className="bg-slate-900 dark:bg-black p-10 text-white text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-full bg-emerald-500/5 blur-[120px] pointer-events-none"></div>
        <div className="w-20 h-20 bg-emerald-500 text-slate-900 rounded-[28px] flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-emerald-500/20">
          <i className="fa-solid fa-credit-card text-3xl"></i>
        </div>
        <h2 className="text-3xl font-black mb-2 tracking-tighter">{t.paywall_title}</h2>
        <p className="text-slate-400 text-sm">{t.paywall_subtitle}</p>
        <div className="mt-4 inline-block bg-slate-800 px-4 py-1.5 rounded-full border border-slate-700">
           <span className="text-[10px] font-black uppercase text-emerald-400 tracking-widest">{t.paywall_otp} {otp}</span>
        </div>
      </div>

      <div className="p-8">
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1.5 rounded-3xl mb-8">
          <button 
            onClick={() => setActiveTab('digital')}
            className={`flex-1 py-3 rounded-[22px] text-xs font-black transition-all ${activeTab === 'digital' ? 'bg-white dark:bg-slate-700 shadow-xl text-emerald-600 dark:text-emerald-400' : 'text-slate-500'}`}
          >
            <i className="fa-solid fa-bolt-lightning mr-2 ml-2"></i>
            {t.paywall_fast_pay}
          </button>
          <button 
