import { UserRole, ApiResponse, CVData, CandidateProfile, TemplateType, ThemeConfig, Language, ThemeMode, WizardStep, InvoiceData, ArchiveItem } from './types';
import { TRANSLATIONS, PAYMENT_INFO } from './constants';

const initialCV: CVData = {
  personal_info: { full_name: '', email: '', phone: '', location: '', target_job: '' },
  summary: '',
  experience: [],
  education: [],
  skills: [],
  ats_score: 15
};

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState<string | null>(null);
  const [activated, setActivated] = useState(false);
  const [invoice, setInvoice] = useState<InvoiceData | null>(null);
  const [result, setResult] = useState<ApiResponse | null>(null);
  const [cvData, setCVData] = useState<CVData>(initialCV);
  const [wizardStep, setWizardStep] = useState<WizardStep>(WizardStep.HUB);
  const [shortlist, setShortlist] = useState<CandidateProfile[]>([]);
  const [activeInfoPage, setActiveInfoPage] = useState<string>('home');
  const [autoDownloadFired, setAutoDownloadFired] = useState(false);
  const [archive, setArchive] = useState<ArchiveItem[]>(() => {
    const saved = localStorage.getItem('sira_archive');
    return saved ? JSON.parse(saved) : [];
  });

  const [uiLang, setUiLang] = useState<Language>(Language.AR);
  const [themeMode, setThemeMode] = useState<ThemeMode>(ThemeMode.LIGHT);
  const [template, setTemplate] = useState<TemplateType>(TemplateType.NEOM);
  const [theme, setTheme] = useState<ThemeConfig>({
    primaryColor: '#10b981',
    sectionOrder: ['summary', 'experience', 'education', 'skills'],
    fontSize: 'base',
    showQR: false
  });

  const t = uiLang === Language.AR ? TRANSLATIONS.ar : TRANSLATIONS.en;
  const isRtl = uiLang === Language.AR;

  // Optimized Theme Sync
  useEffect(() => {
    const saved = localStorage.getItem('sirati_theme') as ThemeMode;
    if (saved) setThemeMode(saved);
  }, []);

  useEffect(() => {
    localStorage.setItem('sirati_theme', themeMode);
  }, [themeMode]);

  useEffect(() => {
    localStorage.setItem('sira_archive', JSON.stringify(archive));
  }, [archive]);

  const handlePrint = useCallback(() => {
    if (!result) return;

    const name = result.cv.personal_info.full_name || 'Candidate';
    const job = result.cv.personal_info.target_job || 'CV';

    // Smart Sanitization for Windows/Mac file systems
    const sanitize = (str: string) => str.trim()
      .replace(/[^\w\s\u0600-\u06FF]/g, '')
      .replace(/\s+/g, '_');

    const fileName = isRtl 
      ? `${sanitize(name)}_${sanitize(job)}_سيرة_ذاتية`
      : `${sanitize(name)}_${sanitize(job)}_CV`;

    const originalTitle = document.title;
    document.title = fileName;

    // Client-side instant export trigger
    window.print();

    setTimeout(() => { document.title = originalTitle; }, 1000);
  }, [result, isRtl]);

  // Forced Download Protocol: Instant Trigger after activation
  useEffect(() => {
    if (activated && result && !autoDownloadFired) {
      setAutoDownloadFired(true);
      // Small delay to ensure DOM is ready for clean PDF export
      const timer = setTimeout(() => {
        handlePrint();
      }, 800);
      return () => clearTimeout(timer);
    }
  }, [activated, result, autoDownloadFired, handlePrint]);

  const toggleTheme = () => setThemeMode(prev => prev === ThemeMode.LIGHT ? ThemeMode.DARK : ThemeMode.LIGHT);

  const generateOtp = (r: UserRole) => {
    const prefix = r === UserRole.SEEKER ? 'TX-' : 'EX-';
    return `${prefix}${Math.floor(10000 + Math.random() * 89999)}`;
  };

  const handleProcessFinal = async () => {
    setLoading(true);
    try {
      setOtp(generateOtp(UserRole.SEEKER));
      const apiResult = await processCVInput(JSON.stringify(cvData), cvData.personal_info.target_job, uiLang);
      const coverLetter = await generateCoverLetter(cvData, uiLang);
      apiResult.cv.cover_letter = coverLetter;
      setResult(apiResult);
      setWizardStep(WizardStep.PREVIEW);
    } catch (error) {
      alert(isRtl ? "فشل المحرك السيادي في المعالجة" : "Engine processing failed");
    } finally {
      setLoading(false);
    }
  };

  const handleActivate = (code: string, invoiceData?: InvoiceData) => {
    if (code === "INSTANT_SUCCESS" || code.length >= 4) {
      setActivated(true);
      if (invoiceData) setInvoice(invoiceData);

      if (result) {
        const newItem: ArchiveItem = {
          id: invoiceData?.id || `ARC-${Date.now()}`,
          date: new Date().toLocaleDateString(),
          cv: result.cv,
          otp: otp || 'PRO',
          job: result.cv.personal_info.target_job
        };
        setArchive(prev => [newItem, ...prev].slice(0, 10));
      }

      if (code === "INSTANT_SUCCESS") {
         alert(isRtl ? "تم التفعيل اللحظي! جاري تصدير النسخة البيضاء..." : "Instant activation! Exporting white-label copy...");
      }
    } else {
      alert(isRtl ? "كود التفعيل غير صالح" : "Invalid activation code");
    }
  };

  const handleNavClick = (page: string) => {
    setActiveInfoPage(page);
    if (page === 'home') {
      setRole(null);
      setResult(null);
      setWizardStep(WizardStep.HUB);
      setAutoDownloadFired(false);
    }
  };

  return (
    <Layout lang={uiLang} onLangToggle={() => setUiLang(prev => prev === Language.AR ? Language.EN : Language.AR)} themeMode={themeMode} onThemeToggle={toggleTheme} onNavClick={handleNavClick}>
      <div className="container mx-auto px-4 py-8">
        {!role && activeInfoPage === 'home' && (
          <div className="flex flex-col items-center py-20 animate-in fade-in zoom-in duration-300">
            <h2 className="text-7xl md:text-9xl font-black text-slate-900 dark:text-white mb-6 tracking-tighter">
              {t.hero_title}<span className="text-emerald-500">{t.hero_title_accent}</span>
            </h2>
            <p className="text-slate-500 text-2xl mb-16 text-center max-w-2xl">{t.hero_desc}</p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-4xl">
              <button onClick={() => setRole(UserRole.SEEKER)} className="p-12 bg-white dark:bg-slate-900 border-2 rounded-[50px] shadow-3xl hover:border-emerald-500 transition-all text-start group">
                <i className="fa-solid fa-user-graduate text-4xl text-emerald-500 mb-6 group-hover:scale-110 transition-transform"></i>
                <h3 className="text-3xl font-black mb-2">{t.role_seeker}</h3>
                <p className="text-slate-500 text-sm">{t.role_seeker_desc}</p>
              </button>
              <button onClick={() => setRole(UserRole.EMPLOYER)} className="p-12 bg-slate-900 text-white rounded-[50px] shadow-3xl hover:border-emerald-500 transition-all text-start group">
                <i className="fa-solid fa-bolt text-4xl text-emerald-400 mb-6 group-hover:scale-110 transition-transform"></i>
                <h3 className="text-3xl font-black mb-2">{t.role_employer}</h3>
                <p className="text-slate-400 text-sm">{t.role_employer_desc}</p>
              </button>
            </div>
          </div>
        )}

        {role === UserRole.SEEKER && wizardStep === WizardStep.HUB && activeInfoPage === 'home' && (
          <CandidateHub onStartFresh={() => setWizardStep(WizardStep.PERSONAL)} onStartChat={() => setWizardStep(WizardStep.CHAT)} onExtracted={(d) => { setCVData(d); setWizardStep(WizardStep.PERSONAL); }} lang={uiLang} />
        )}

        {role === UserRole.SEEKER && wizardStep !== WizardStep.HUB && wizardStep !== WizardStep.PREVIEW && activeInfoPage === 'home' && (
          <EditorWizard data={cvData} onChange={(d) => setCVData(prev => ({...prev, ...d}))} step={wizardStep} lang={uiLang} onNext={() => {
            if (wizardStep === WizardStep.PERSONAL) setWizardStep(WizardStep.EXPERIENCE);
            else if (wizardStep === WizardStep.EXPERIENCE) setWizardStep(WizardStep.EDUCATION);
            else if (wizardStep === WizardStep.EDUCATION) setWizardStep(WizardStep.SKILLS);
            else handleProcessFinal();
          }} onPrev={() => setWizardStep(prev => prev === WizardStep.PERSONAL ? WizardStep.HUB : WizardStep.PERSONAL)} />
        )}

        {result && activeInfoPage === 'home' && (
          <div className="max-w-7xl mx-auto flex flex-col lg:flex-row gap-12">
            <aside className="lg:w-[380px] space-y-8 no-print">
              <div className="bg-white dark:bg-slate-900 p-8 rounded-[40px] shadow-3xl border border-slate-100 dark:border-slate-800 sticky top-8">
                <h3 className="text-xl font-black mb-6 flex items-center gap-2"><i className="fa-solid fa-sliders text-emerald-500"></i> {t.design_customize}</h3>
                <div className="space-y-6">
                  <div className="grid grid-cols-2 gap-3">
                    {Object.values(TemplateType).map(v => (
                      <button key={v} onClick={() => setTemplate(v)} className={`p-3 rounded-2xl border-2 text-[10px] font-black transition-all ${template === v ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-50 text-slate-400'}`}>{v}</button>
                    ))}
                  </div>
                  <button onClick={() => setUiLang(prev => prev === Language.AR ? Language.EN : Language.AR)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm shadow-xl flex items-center justify-center gap-2">
                    <i className="fa-solid fa-language"></i> {t.translate_btn}
                  </button>
                  <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl">
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">{t.qr_link_toggle}</span>
                    <button onClick={() => setTheme({...theme, showQR: !theme.showQR})} className={`w-10 h-5 rounded-full relative transition-all ${theme.showQR ? 'bg-emerald-500' : 'bg-slate-300'}`}>
                      <div className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all ${theme.showQR ? (isRtl ? 'left-0.5' : 'right-0.5') : (isRtl ? 'right-0.5' : 'left-0.5')}`}></div>
                    </button>
                  </div>
                </div>
              </div>
            </aside>

            <div className="flex-1 space-y-12 pb-20">
              <CVPreview data={result.cv} template={template} theme={theme} lang={uiLang} activated={activated} />

              {!activated && otp && (
                <Paywall role={role} otp={otp} userName={cvData.personal_info.full_name} onActivate={handleActivate} lang={uiLang} />
              )}

              {activated && (
                <div className="space-y-12 animate-in fade-in slide-in-from-bottom duration-500">
                  <div className="bg-emerald-600 text-white p-10 rounded-[50px] shadow-4xl flex flex-col md:flex-row items-center justify-between gap-8 no-print">
                    <div className="flex items-center gap-6">
                      <div className="w-20 h-20 bg-yellow-400 text-black rounded-3xl flex items-center justify-center text-4xl shadow-2xl rotate-3"><i className="fa-solid fa-crown"></i></div>
                      <div>
                        <h4 className="text-3xl font-black mb-1">{t.verified_badge}</h4>
                        <p className="opacity-80 font-bold">{t.verified_desc}</p>
                      </div>
                    </div>
                    <button onClick={handlePrint} className="bg-white text-emerald-600 px-12 py-5 rounded-3xl font-black shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3">
                      <i className="fa-solid fa-file-pdf"></i> {isRtl ? 'تحميل النسخة النهائية الآن' : 'Download Final Version'}
                    </button>
                  </div>
                  {invoice && <Invoice data={invoice} lang={uiLang} />}
                  <JobMatcher cv={result.cv} />
                  <CareerPath data={result.career_path} />
                  <SmartHelper data={result.smart_helper} />
                </div>
              )}
            </div>
          </div>
        )}

        {activeInfoPage === 'archive' && (
          <div className="max-w-4xl mx-auto py-20 animate-in fade-in duration-300">
             <h2 className="text-5xl font-black mb-6 tracking-tighter">{t.archive_title}</h2>
             <p className="text-slate-500 mb-10">{t.archive_desc}</p>
             <div className="grid gap-4">
                {archive.length > 0 ? archive.map(item => (
                  <div key={item.id} className="bg-white p-6 rounded-3xl border flex justify-between items-center group hover:border-emerald-500 transition-all">
                    <div>
                      <h4 className="font-black text-xl">{item.cv.personal_info.full_name}</h4>
                      <p className="text-xs text-slate-400 font-bold">{item.job} | {item.date}</p>
                    </div>
                    <button onClick={() => { setRole(UserRole.SEEKER); setActivated(true); setResult({cv: item.cv, career_path: {} as any, smart_helper: {} as any, market_insights: {} as any}); setActiveInfoPage('home'); }} className="bg-slate-900 text-white px-6 py-2 rounded-xl text-xs font-black">تحميل</button>
                  </div>
                )) : <div className="text-center py-20 bg-slate-50 rounded-3xl border-2 border-dashed font-bold text-slate-400">{t.archive_empty}</div>}
             </div>
          </div>
        )}
      </div>

      {loading && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-3xl z-[500] flex items-center justify-center p-8 no-print">
          <div className="text-center space-y-8 max-w-lg animate-pulse">
            <div className="w-32 h-32 border-[12px] border-emerald-500 border-t-transparent rounded-full animate-spin mx-auto shadow-4xl shadow-emerald-500/20"></div>
            <h4 className="text-4xl font-black text-white tracking-tighter uppercase">Turbo Neural Sync...</h4>
            <p className="text-slate-400 font-bold text-lg">{isRtl ? 'جاري معالجة المحرك السيادي بسرعة الضوء...' : 'Sovereign Engine processing at light speed...'}</p>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
