                 <p className="text-slate-600 dark:text-slate-400 leading-relaxed font-medium">{t.legal_terms_body}</p>
               </section>
               <section>
                 <h4 className="text-2xl font-black text-emerald-600 mb-4">{t.legal_privacy_title}</h4>
                 <p className="text-slate-600 dark:text-slate-400 leading-relaxed font-medium">{t.legal_privacy_body}</p>
               </section>
               <section>
                 <h4 className="text-2xl font-black text-emerald-600 mb-4">{t.legal_liability_title}</h4>
                 <p className="text-slate-600 dark:text-slate-400 leading-relaxed font-medium">{t.legal_liability_body}</p>
               </section>
               <button onClick={() => setActiveInfoPage('home')} className="bg-slate-900 text-white px-8 py-3 rounded-2xl font-black">{isRtl ? 'عودة' : 'Back'}</button>
