                  <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">{t.qr_link_toggle}</span>
                    <button onClick={() => setTheme({...theme, showQR: !theme.showQR})} className={`w-10 h-5 rounded-full relative transition-all ${theme.showQR ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
