              {!activated && otp && (
                <Paywall role={role} otp={otp} userName={cvData.personal_info.full_name} onActivate={handleActivate} lang={uiLang} />
              )}

              {activated && (
                <div className="space-y-12 animate-in fade-in slide-in-from-bottom duration-500">
                  <div className="bg-emerald-600 text-white p-10 rounded-[50px] shadow-4xl flex flex-col md:flex-row items-center justify-between gap-8 no-print relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-full bg-white/5 pointer-events-none"></div>
                    <div className="flex items-center gap-6 relative z-10">
                      <div className="w-20 h-20 bg-yellow-400 text-black rounded-3xl flex items-center justify-center text-4xl shadow-2xl rotate-3"><i className="fa-solid fa-crown"></i></div>
                      <div>
                        <h4 className="text-3xl font-black mb-1">{t.verified_badge}</h4>
                        <p className="opacity-80 font-bold">{t.verified_desc}</p>
                      </div>
                    </div>
                    <div className="flex flex-col gap-4 w-full md:w-auto relative z-10">
                      <button onClick={handlePrint} className="bg-white text-emerald-600 px-12 py-5 rounded-3xl font-black shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-3 w-full">
                        <i className="fa-solid fa-file-pdf"></i> {isRtl ? 'تحميل النسخة النهائية الآن' : 'Download Final Version'}
                      </button>
                      {showManualDownload && (
                        <button onClick={handlePrint} className="bg-amber-400 text-slate-900 px-12 py-5 rounded-3xl font-black shadow-2xl animate-bounce hover:scale-105 transition-all flex items-center justify-center gap-3 border-4 border-white">
                           <i className="fa-solid fa-cloud-arrow-down text-2xl"></i>
                           {isRtl ? 'تحميل سيرتك النهائية الآن (رابط طوارئ)' : 'Download Final CV Now (Emergency Link)'}
                        </button>
                      )}
                    </div>
                  </div>
                  {invoice && <Invoice data={invoice} lang={uiLang} />}
